window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["n"]={"Nikodem": "<b>Nikodem</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, także rzadkie nazwisko. Wywodzi się od słowa oznaczającego „ten, który zwycięża dla ludu” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Νικόδημος: νίκη „zwycięstwo” + δημος „lud”). To samo znaczenie ma imię <a href=\"https://pl.wikipedia.org/wiki/Miko%C5%82aj\" target=\"_blank\" rel=\"noopener noreferrer\">Mikołaj</a>. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Nikodema\" target=\"_blank\" rel=\"noopener noreferrer\">Nikodema</a>.", "Norbert": "<b>Norbert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">starogermańskiego</a>. Wywodzi się od słów <i>nord</i> – tj. północ i <i>beraht</i> – czyli błyszczeć, jaśnieć. Całość znaczy więc „ten, który dokonuje wielkich czynów na północy”, „sławny mąż z północy”.", "Natan": "<b>Natan</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> נָתָן, <i>dar, podarunek</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> hebrajskie. Imieniu Natan etymologicznie bliskie są imiona <a href=\"https://pl.wikipedia.org/wiki/Natanael\" target=\"_blank\" rel=\"noopener noreferrer\">Natanael</a> (<a href=\"https://pl.wikipedia.org/wiki/Natanael\" target=\"_blank\" rel=\"noopener noreferrer\">Nataniel</a>). <b>Natan</b> <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/12_lipca\" target=\"_blank\" rel=\"noopener noreferrer\">12 lipca</a> oraz <a href=\"https://pl.wikipedia.org/wiki/25_grudnia\" target=\"_blank\" rel=\"noopener noreferrer\">25 grudnia</a>.", "Nazar": "<b>Nazar</b>, zwany też <b>okiem <a href=\"https://pl.wikipedia.org/wiki/Fatima_(c%C3%B3rka_Mahometa)\" target=\"_blank\" rel=\"noopener noreferrer\">Fatimy</a></b> lub <b>okiem proroka</b> – <a href=\"https://pl.wikipedia.org/wiki/Amulet\" target=\"_blank\" rel=\"noopener noreferrer\">amulet</a> mający chronić przed „<a href=\"https://pl.wikipedia.org/wiki/Z%C5%82e_oko\" target=\"_blank\" rel=\"noopener noreferrer\">złym okiem</a>”. Nazwa nazar jest pochodzenia arabskiego i znaczy tyle co spojrzenie.", "Nikita": "<p>Nikita: Nikita to męskie imię w krajach postsowieckich i niektórych krajach wschodniej Europy. Nikita Wodopol (dzień Nikita) - dzień kalendarza narodowego wschodnich Słowań.</p>", "Nataniel": "<b>Natanael</b> (hebr. Bóg dał) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> hebrajskie, znaczeniowo przypomina takie imiona, jak greckie z pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a> czy polskie <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCydar_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bożydar</a>.", "Nazarii": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nazariusz</b>.</p><b>Nazariusz</b>, <b>Nazary</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające \"pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Nazaret\" target=\"_blank\" rel=\"noopener noreferrer\">Nazaretu</a>\". Wśród patronów tego imienia, <a href=\"https://pl.wikipedia.org/wiki/Nazariusz_i_Celsus\" target=\"_blank\" rel=\"noopener noreferrer\">św. Nazariusz</a>, męczennik z I lub III wieku.", "Nathan": "<p>Nathan Allan de Souza (ur. 13 marca 1996), znany jako Nathan, jest brazylijskim piłkarzem, który gra za Atlético Mineiro, wypożyczonym z English Premier League Chelsea. grając w strzelaninie, może grać także jako lewicowy lub w stronę.</p>", "Noah": "<p>Noah (ang. Noah) - amerykański epiczny biblijny film dramatyczny z 2014 roku, reżysera Darrena Aronofskiego, napisany przez Aronofskiego i Eriego Hendela, w oparciu o biblijny scenariusz o Noego i potopie w starozownych księgach, takich jak Księga Początku i Księga Enoch, a także włączając apokryfy.</p>", "Nika": "<b>Nika</b> – imię żeńskie o dyskusyjnym pochodzeniu. Może pochodzić od greckiego słowa <i>nike</i> oznaczającego zwycięstwo lub być zdrobnieniem od takich imion jak: <a href=\"https://pl.wikipedia.org/wiki/Monika\" target=\"_blank\" rel=\"noopener noreferrer\">Monika</a>, <a href=\"https://pl.wikipedia.org/wiki/Dominika_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Dominika</a>, <a href=\"https://pl.wikipedia.org/wiki/Berenika_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Berenika</a> czy <a href=\"https://pl.wikipedia.org/wiki/Weronika\" target=\"_blank\" rel=\"noopener noreferrer\">Weronika</a>. ewentualnie od imion <a href=\"https://pl.wikipedia.org/wiki/Nikola\" target=\"_blank\" rel=\"noopener noreferrer\">Nikola</a>, <a href=\"https://pl.wikipedia.org/wiki/Nikoleta\" target=\"_blank\" rel=\"noopener noreferrer\">Nikoleta</a>, <a href=\"https://pl.wikipedia.org/wiki/Nikolina\" target=\"_blank\" rel=\"noopener noreferrer\">Nikolina</a>, <a href=\"https://pl.wikipedia.org/wiki/Nikodema\" target=\"_blank\" rel=\"noopener noreferrer\">Nikodema</a> itd.", "Noel": "<p>Święto Bożego Narodzenia, czyli Boże Narodzenie, to święto upamiętniające narodziny Jezusa, które odbywa się głównie 25 grudnia każdego roku, jest świętem religijnym i kulturalnym dla miliardów ludzi na całym świecie. Jest celebratem centralnym pięciu lat chrześcijańskich, kończącym sezon świąteczny i rozpoczynającym sezon świąteczny, historycznie trwający w Zachodzie dwanaście dni do Dwunastej Nocy (noce przed Świątą Objawienia).</p>", "Nestor": "<b>Nestor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Istnieją liczni święci o tym imieniu.", "Nikoloz": "<b>Nikoloz</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_gruzi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">gruz.</a> ნიკოლოზი) – <a href=\"https://pl.wikipedia.org/wiki/Gruzja\" target=\"_blank\" rel=\"noopener noreferrer\">gruzińskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Miko%C5%82aj\" target=\"_blank\" rel=\"noopener noreferrer\">Mikołaj</a>.", "Nico": "<p>Nico (Nico, prawdziwe imię Christa Päffgen, niemiecki Christa Päck; 16 października 1938, Köln, Trzeci Reich - 18 lipca 1988, Ivis, Hiszpania) - niemiecka piosenkarka, kompozytorka, autorka piosenek, poetka, fotomodelka i aktorka.</p>", "Niko": "<p>Maurizio De Jorio (włoski: Maurizio De Giorio)  Maurizio De Jorio; rod.</p>", "Noe": "<p>Friedrich Wilhelm Noë (niem. Friedrich Wilhelm Noé; 1798 - 1858) - niemiecki botanik, który później pracował w Konstantynopol.</p>", "Norman": "<b>Norman</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa <i>northman</i> oznaczającego „człowieka z północy” i odnoszącego się do <a href=\"https://pl.wikipedia.org/wiki/Wikingowie\" target=\"_blank\" rel=\"noopener noreferrer\">wikingów</a>.", "Noam": "<p>Noam (Hebrajskie: נעם/נועם) to hebrajskie imię, które oznacza \"miękkość\", \"miękczynię\" lub \"pokój\". Zaczęło się jako męska wersja Naomi (ang. \"Naomi\" lub \"Noémie\"), ale dziś jest bardzo powszechną hebrajską nazwą dla ludzi każdej płci.</p>", "Nikola": "<b>Nikola</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, współcześnie sprowadzony do języka polskiego żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Miko%C5%82aj\" target=\"_blank\" rel=\"noopener noreferrer\">Mikołaj</a>. Pochodzi od greckich słów <i>Nikos</i> – <i>zwycięstwo</i> i <i>laos</i> oznaczającego <i>ludzie</i>. Wśród imion nadawanych nowo narodzonym dzieciom, Nikola w 2017 r. zajmowała 26. miejsce w grupie imion żeńskich, co oznacza spadek o 16 miejsc od 2009 r., kiedy to zajmowała 10. miejsce w analogicznej grupie. W całej populacji Polek Nikola zajmowała w 2017 r. 73. miejsce (66 007 nadań). Imię zyskało jeszcze na popularności. W styczniu 2025 r. w rejestrze <a href=\"https://pl.wikipedia.org/wiki/PESEL\" target=\"_blank\" rel=\"noopener noreferrer\">PESEL</a>, wśród publicznie dostępnych danych dotyczących osób żyjących, wykazano 78429 kobiet o imieniu Nikola nadanym jako imię pierwsze.", "Natanael": "<b>Natanael</b> (hebr. Bóg dał) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> hebrajskie, znaczeniowo przypomina takie imiona, jak greckie z pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a> czy polskie <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCydar_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bożydar</a>.", "Nelson": "<p>Edward William Nelson (ang. Edward William Nelson; 1855 - 1934) - amerykański badacz i etnolog.</p>", "Nurlan": "<p>Nurlan (kazachski: Нұрлан) to turkijska męska nazwa, która jest powszechna w Azerbejdżanie, Kazachstanie i Uzbekistanie. Nazwa jest w istocie połączeniem arabskiego słowa Noor (także śpiewany jako \"Nur\") oznaczającego światło, promienie lub blask oraz tureckiego słowa \"Lan/Ulan\", który oznacza lwa w większości języków tureckich.</p>", "Nicola": "<p>Nicola to portugalska marka kawy, należąca do Massimo Zanetti Beverage Group. Jedna z najstarszych marek kawy w Portugalii.</p>", "Napoleon": "<b>Napoleon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Neapol\" target=\"_blank\" rel=\"noopener noreferrer\">Neapolu</a>”.", "Nodar": "<p>Nodar (georgijski: ნოდარ) to męskie gruzińskie imię. Znanymi osobami z nazwiska są: Nodar Akhalkatsi (1937-1998), gruziński menedżer piłki nożnej Nodar Dumbadze (1928-1984), gruziński pisarz i jeden z najbardziej popularnych autorów pod koniec XX wieku Georgia Nodar Dzhordzhikiya (1921-2008), radziecki koszykarz Nodar Gvakhariya (1932-1996), gruziński polowca wodny Nodar Kancheli (1938-2015), rosyjski architekt, który zaprojektował...</p>", "Nichita": "<p>Nichita to rumuńska męska nazwa i nazwisko. Do wybitnych osób z tym nazwiskiem należą: Nichita Danilov (ur. 1952), rumuński poeta Nichita Iurașco (ur. 1999), moldawska piłkarka Nichita Moțpan (ur. 2001), moldawska piłkarz Nichita Smochină (1894-1980), rosyjsko-rumuńska aktywistka, uczona i polityczna figura Nichita Stănescu (1933-1983), rumuńska poetka i esejistka</p>", "Nikos": "<p>Nikos (grek. Νίκος, Níkos) jest greckim nazwiskiem. Pochodzi od greckiego Nikolaos, co oznacza \"wygrę narodu\".</p>", "Niklas": "<p>Niklas (dat. Niklas Holmgreen Fridh; rodzaj.</p>", "Nam": "<p>W wietnamskim, Nam lub mascul jest słowem do wskazania: Mężczyzna: płci męskiej ludzi, w przeciwieństwie do \"żwomen\" jest płcią (żwomen) najniższej rangi szlachty feitów: Namcowiec kierunek: Słowo-Jużny zakres południowej dzielnicy kolonii miasteczkowej, prowincji Ho Nam, China: Słowe dzielnicy okręgów (khu) o nazwie Nam, patrz Naim (distrikty). W słowach \"wstrzymanie\" wskazują kierunek: męskie leki...</p>", "Nazariy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nazariusz</b>.</p><b>Nazariusz</b>, <b>Nazary</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające \"pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Nazaret\" target=\"_blank\" rel=\"noopener noreferrer\">Nazaretu</a>\". Wśród patronów tego imienia, <a href=\"https://pl.wikipedia.org/wiki/Nazariusz_i_Celsus\" target=\"_blank\" rel=\"noopener noreferrer\">św. Nazariusz</a>, męczennik z I lub III wieku.", "Nikolozi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikoloz</b>.</p><b>Nikoloz</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_gruzi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">gruz.</a> ნიკოლოზი) – <a href=\"https://pl.wikipedia.org/wiki/Gruzja\" target=\"_blank\" rel=\"noopener noreferrer\">gruzińskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Miko%C5%82aj\" target=\"_blank\" rel=\"noopener noreferrer\">Mikołaj</a>.", "Nick": "<p>Nick może odnosić się do: Nick Jonas Nick Heidfeld Nick Cannon Nick Ut</p>", "Nolan": "<p>Nolan (Nolan) - irlandzkie nazwisko i toponim.</p>", "Nodari": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nodar</b>.</p><p>Nodar (georgijski: ნოდარ) to męskie gruzińskie imię. Znanymi osobami z nazwiska są: Nodar Akhalkatsi (1937-1998), gruziński menedżer piłki nożnej Nodar Dumbadze (1928-1984), gruziński pisarz i jeden z najbardziej popularnych autorów pod koniec XX wieku Georgia Nodar Dzhordzhikiya (1921-2008), radziecki koszykarz Nodar Gvakhariya (1932-1996), gruziński polowca wodny Nodar Kancheli (1938-2015), rosyjski architekt, który zaprojektował...</p>", "Narek": "<p>Narek jest miastem w prowincji Ararat w Armenii. W 2011 roku liczba ludności wynosiła 1275 osób.</p>", "Nadir": "<p>W astronomii niebo (Han: 天底, niebo, do = dna), w sposób nominalny, jest punktem (niewidocznym bezpośrednio okowi) nieba leżącym prosto pod stóp obserwatora. Dokładniej mówiąc, następujące definicje są równoważne: jest to punkt o wysokości -90 stopni.</p>", "Nigel": "<p>Nigel (ang. Nigel - ⁇ angel ⁇) - angielskie imię męskie.</p>", "Nodirbek": "<p>Nodirbek to uzbekska męska nazwa. Znanymi osobami z nazwiskiem są: Nodirbek Abdusattorov (ur. 2004), Uzbek szahista Nodirbek Primqulov (ur . 1998), Uzbekiecki piosenkarz i aktor Nodirbek Yakubboev (ur. 2002), Uzbekiecka szahista</p>", "Natig": "<p>Natig, Natik lub Natiq (arabski: ناطق), to nazwisko i nazwisko pochodzenia arabskiego, które oznacza mówienie. Do wybitnych osób z tym nazwiskiem należą:</p>", "Nikhil": "<p>Nikhil (sanskrit: निखिल) to męskie imię pochodzenia sanskrytu. Znajduje się głównie w Indiach, Nepalu i diasporze tych krajów.</p>", "Nursultan": "<p>Astana (kazachskie: Астана [astaˈna]) lub poprzednie nazwisko Nursultan lub Nur-Sultan (kazachski: Нұр-Сұлтан) używane od marca 2019 do września 2022 roku, jest stolicą Kazachstanu. Miasto leży na brzegu rzeki Ishim w północnej części Kazachstanu, w regionie Akmola, choć administrativnie jest zarządzane oddzielnie ze szczególnym statusem.</p>", "Nimrod": "<p>Nimrod (także NIMROD) - komputer do gry w nim. Miała też reżimy do gry zarówno w komputer, jak i w siebie.</p>", "Nabin": "<p>Nabin to męskie imię powszechne na subkontynencie indyjskim. Znani ludzie z nazwiska to: Nabin Chandra Bag, indyjski polityk Nabin Chendra Bardoloi (1875-1936), indyjski pisarz i polityk Nabine K Bhattarai (ur. 1974), nepalejski muzyk Nabin Nanda, indycki polityk Nabina Rabha (ur. 1996), indyjski profesjonalny piłkarz Nabin Subba (ur. 1967), nepalewski reżyser filmowy</p>", "Nicodem": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikodem</b>.</p><b>Nikodem</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, także rzadkie nazwisko. Wywodzi się od słowa oznaczającego „ten, który zwycięża dla ludu” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Νικόδημος: νίκη „zwycięstwo” + δημος „lud”). To samo znaczenie ma imię <a href=\"https://pl.wikipedia.org/wiki/Miko%C5%82aj\" target=\"_blank\" rel=\"noopener noreferrer\">Mikołaj</a>. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Nikodema\" target=\"_blank\" rel=\"noopener noreferrer\">Nikodema</a>.", "Nuriddin": "<p>Nur al-Din (arabski: نور الدين, romanized: nūr ad-dīn) to męskie arabskie imię, tłumaczące na \"światło wiary\", nūr oznacza \"świetło\" i dīn oznacza \"religię\". Ostatnio nazwa ta była używana również jako nazwisko.</p>", "Nenad": "<b>Nenad</b> – słowiańskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie używane w <a href=\"https://pl.wikipedia.org/wiki/Chorwacja\" target=\"_blank\" rel=\"noopener noreferrer\">Chorwacji</a> i <a href=\"https://pl.wikipedia.org/wiki/Serbia\" target=\"_blank\" rel=\"noopener noreferrer\">Serbii</a>.", "Nariman": "<p>Nariman (zwany również Narriman, Nareeman, Neriman, Nəriman) jest nazwą pochodzenia perskiego (perskiego: نریمان Narīmān). Jego korzenie pochodzą z perskiego epiku Shahnameh, napisanego przez Ferdowsi.</p>", "Nykyta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikita</b>.</p><p>Nikita: Nikita to męskie imię w krajach postsowieckich i niektórych krajach wschodniej Europy. Nikita Wodopol (dzień Nikita) - dzień kalendarza narodowego wschodnich Słowań.</p>", "Namik": "<p>Namig, Namik lub Namık to męskie imię. Do wybitnych osób z tym nazwiskiem należą:</p>", "Ngọc": "<p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nizami": "<b>Nizami</b>, <b>Nezami Gandżawi</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">pers.</a>&#160;&#8207;نظامی گنجوی&#8206;, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_azerbejd%C5%BCa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">azer.</a>&#160;<em>Nizami Gəncəvi</em>, właśc. Nizām ad-Dīn Abū Muhammad Ilyās ibn-Yusūf ibn-Zakī ibn-Muˤayyid Nizāmī Ganjavī; ur. ok. <a href=\"https://pl.wikipedia.org/wiki/1141\" target=\"_blank\" rel=\"noopener noreferrer\">1141</a>, zm. ok. <a href=\"https://pl.wikipedia.org/wiki/1209\" target=\"_blank\" rel=\"noopener noreferrer\">1209</a>) – perski poeta pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Gand%C5%BCa\" target=\"_blank\" rel=\"noopener noreferrer\">Gandży</a> (dzisiejszy <a href=\"https://pl.wikipedia.org/wiki/Azerbejd%C5%BCan\" target=\"_blank\" rel=\"noopener noreferrer\">Azerbejdżan</a>), mieszkający przez całe życie w tym mieście i uważany za twórcę literatury perskiej.", "Neo": "<p>Neo (neo) - projekt sztucznego (planowego) języka międzynarodowego, stworzony przez belgijskiego dyplomata i lingwisty Arturo Alfandari. Neo jest językiem autonomii i połącza w sobie cechy esperanto, ido, novial, okcydentał, wolapjuk.</p>", "Nader": "<p>Nader jest męskim imieniem i nazwiskiem pochodzenia arabskiego (nادر Nādir, oznacza \"rzadkość\", \"jedyną\"). Nadir to wariant nazwiska.</p>", "Nil": "<b>Nilus</b>, <b>Nil</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego, od gr. <i>neilos</i> – \"rzeka\". Istnieli liczni święci o tym imieniu.", "Nitin": "<p>Nitin lub Nithin (Devanagari: नितिन, नीतीन, lub नीतिन) to męskie imię w Indiach i Nepalu.</p>", "Naum": "<p>Naum - komercyjny program szachowy opracowany w 2003 roku przez Aleksandra Naumowa z Kanady. Była kiedyś drugim najpotężniejszym programem szachowym na świecie po Rybce, ale obecnie jest ona zajęta nowoczesniejszymi programami.</p>", "Nirmal": "<p>Nirmal to miasto i dzielnica w hrabstwie Adilabad w stanie Telangana w Indiach.</p>", "Noa": "<p>Ahinóam Nińi (br. אחינועם ניני) (znana również pod pseudonimem Noego (br.</p>", "Naim": "<p>naim to kompaktowy program do natychmiastowej wymiany wiadomości, obsługujący protokół AIM, ICQ, IRC. W przeciwieństwie do większości takich programów, nie jest graficzny.</p>", "Nath": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nat</b>.</p><b>Nat</b> (skr. od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a> <i>natural unit</i> „jednostka naturalna”; czasami także <b>nit</b> lub <b>nepit</b>, skr. od <i>Neper unit</i> – „jednostka <a href=\"https://pl.wikipedia.org/wiki/John_Napier\" target=\"_blank\" rel=\"noopener noreferrer\">Nepera</a>”) – <a href=\"https://pl.wikipedia.org/wiki/Logarytm\" target=\"_blank\" rel=\"noopener noreferrer\">logarytmiczna</a> <a href=\"https://pl.wikipedia.org/wiki/Jednostka_miary\" target=\"_blank\" rel=\"noopener noreferrer\">jednostka miary</a> <a href=\"https://pl.wikipedia.org/wiki/Ilo%C5%9B%C4%87_informacji\" target=\"_blank\" rel=\"noopener noreferrer\">ilości informacji</a>. 1 nat jest ilością <a href=\"https://pl.wikipedia.org/wiki/Informacja\" target=\"_blank\" rel=\"noopener noreferrer\">informacji</a> zawartą w <a href=\"https://pl.wikipedia.org/wiki/Komunikat\" target=\"_blank\" rel=\"noopener noreferrer\">wiadomości</a> o zajściu zdarzenia, którego <a href=\"https://pl.wikipedia.org/wiki/Prawdopodobie%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">prawdopodobieństwo</a> równe jest 1/<a href=\"https://pl.wikipedia.org/wiki/Podstawa_logarytmu_naturalnego\" target=\"_blank\" rel=\"noopener noreferrer\">e</a>. Ilość informacji wyraża się w postaci <a href=\"https://pl.wikipedia.org/wiki/Logarytm_naturalny\" target=\"_blank\" rel=\"noopener noreferrer\">logarytmu naturalnego</a> liczby możliwych wariantów zdarzenia.", "Nithin": "<p>Nitin Kumar Reddy (ang. Nithin Kumar Reddy, teлугу niitin kumar reddy, bardziej znany pod mononimem Nitin; rod.</p>", "Naveed": "<p>Naveed to debiutancki album kanadyjskiego zespołu rockowego Our Lady Peace, produkowany przez Arnolda Lenny'ego, wydany 22 marca 1994 roku przez Sony Music Canada. Naveed odniosł sukces komercyjny w Kanadzie, rozbił się w liczbie ponad 100,000 egzemplarzy do końca roku i stał się platynem.</p>", "Nasim": "<p>Nassim (arabski: نسيم) również przetransliterowany jako Nacim, Naseem, Nasseem, Nasim, Nesim lub Nessim, jest unisex nazwisko oznaczające \"miękkie wiatr, świeży powietrze\". Jest używany głównie w kulturach i grupach językowych Bliskiego Wschodu i Azji Południowej.</p>", "Nurzhan": "<p>Nurzhan to unisex (choć częściej męskie) nazwisko pochodzące z Kazachstanu, co oznacza \"świeca dusza\". Znani ludzie z nazwiskiem to: Nurzhan Karimzhanov (ur. 1980), kazachstaniec boxer Nurzhan Kermenbayev (ur. 1989), kazachski piosenkarz Nurzhan Smanov (ur . 1972), kaszkiański emerytur boxer</p>", "Natik": "<p>Natig, Natik lub Natiq (arabski: ناطق), to nazwisko i nazwisko pochodzenia arabskiego, które oznacza mówienie. Do wybitnych osób z tym nazwiskiem należą:</p>", "Nicolo": "<p>Nicolò (w włoskim: [nikoˈlɔ]) to włoskie imię męskie. Kolejna wariantka to Niccolò, najczęstsza w Toskanii.</p>", "Nebojša": "<p>Nebojša to serbskie imię, co oznacza \"bez obaw\". Do osób z tym nazwiskiem należą:</p>", "Nurul": "<p>Noor to powszechne arabskie unisex nazwisko, które oznacza \"światło\", z arabskiego al-Nur (النور). Wśród kobiecych wariantów są Noora, Nora, Norah, Noura i Nura.</p>", "Nguyen": "Nazwisko pochodzi z <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">Chin</a>, gdzie jest pisane 阮 i wymawiane <i>Ruǎn</i> <a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#91;</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_z_retrofleksj%C4%85_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">ʐ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_p%C3%B3%C5%82otwarta_wargowo-mi%C4%99kkopodniebienna\" target=\"_blank\" rel=\"noopener noreferrer\">w</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">à</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#93;</a>.", "Nikon": "<b>Nikon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, wywodzące się od greckiego <i>νικη (nike)</i>, co oznacza \"zwycięstwo\". Imię to stosunkowo największą popularnością cieszyło się u prawosławnych Słowian wschodnich. Nikon <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/23_marca\" target=\"_blank\" rel=\"noopener noreferrer\">23 marca</a> i <a href=\"https://pl.wikipedia.org/wiki/26_listopada\" target=\"_blank\" rel=\"noopener noreferrer\">26 listopada</a>.", "Nikifor": "<b>Nicefor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Od greckiego <i>Νικηφόρος (Nikiforos)</i>, czyli „niosący zwycięstwo”. Jego wschodniosłowiańską wersją jest <b>Nikifor</b>.", "Naftali": "<b>Neftali</b>, <b>Naftali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> נפתלי) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Etymologię tego imienia (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <i>moja walka</i>, <i>wywalczony</i>) wywodzi się z <i><a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Rodzaju</a></i> 30,8.", "Nyasha": "<p>Nyasha jest zimbabwskim imieniem pochodzenia Shona, które odnosi się do łaski, miłosierdzia lub miłosiernego serca, a jest to unisex imię nosione zarówno przez chłopców, jak i dziewczynki. Nyasha może być także pseudonimem tych, którzy noszą nazwiska takie jak Nyashadzashe,] lub Nyashadzenyu.</p>", "Nicu": "<p>Nicu jest zarówno męskim rumuńskim nazwiskiem, jak i rumuńskie nazwisko. Znani ludzie z nazwiska obejmują: Nicu Ceaușescu (1951-1996), rumuński komunista Nicu Constantin (1938-2009), rumuński aktor Nicu Constantinescu (1840-1905), rumuński polityk Nicu Covaci (ur. 1947), rumuński malarz i muzyk Nicu Paleru (ur. 1973), rumuńskiego cyganka muzyka Nicu Porsena (ur. Ionescu) (1892-1971), rumuńczyka pisarz Nicu Stoian (ur. 1957),...</p>", "Namir": "<b>Namir</b> — staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Imię to składa się z dwóch członów: <i>na</i> (\"na\"; jedno ze znaczeń <i>na</i> nazywało kogoś, ze względu na kogo coś się działo\") oraz <i>-mir</i> (\"pokój, spokój, dobro\"). Mogło ono więc oznaczać \"ten, który pojawił się w czasie pokoju\" albo \"ten, dzięki któremu zapanuje pokój\".", "Nahum": "<b>Nahum</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od imienia <i>Nahum</i>, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> słowa „ten, który przynosi ukojenie”. Nosił je <a href=\"https://pl.wikipedia.org/wiki/Nahum_(prorok)\" target=\"_blank\" rel=\"noopener noreferrer\">Nahum</a>, jeden z proroków mniejszych <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starego Testamentu</a>, który przepowiedział upadek <a href=\"https://pl.wikipedia.org/wiki/Niniwa\" target=\"_blank\" rel=\"noopener noreferrer\">Niniwy</a> w spisanej <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Nahuma\" target=\"_blank\" rel=\"noopener noreferrer\">Księdze Nahuma</a>.", "Naeem": "<p>Naim (zwany również Na'im, Naïm, Nayeem, Naeem, Naiem, Nahim, Naheem, Nyhiem, Nihiem, Nyheim, Niheem, Nahiem lub Nyiem) (arabski: نعیم, hebrajski: נעים) jest męskie imię i nazwisko.</p>", "Niclas": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Niklas</b>.</p><p>Niklas (dat. Niklas Holmgreen Fridh; rodzaj.</p>", "Nnamdi": "<p>Nnamdi to imię męskie Igbo. To znaczy \"moim ojcem żyje\".</p>", "Naga": "<p>Artykuł przedstawia listę głównych i małych ras wszechświata Warcraft - fikcyjnego świata gier komputerowych Warcraft. Większość narodów świata należy albo do Ordy, albo do Sojuszu - dwóch głównych frakcji serii - ale istnieje wiele neutralnych ras.</p>", "Nilesh": "<p>Nilesh (czasami również pisane jako Neelesh) jest indyjską nazwą opartą na jednej z dwóch bóstw, Wisnu lub Shiva, w hinduizmie, w zależności od tego, które z jego dwóch wymowy hindi są używane. 'Nilesh' oznacza 'Błękitny Bóg' i jest jednym z alternatywnych nazw dla Wisnu, \"Ochrony\". Później nazwa została również użyta do odniesienia się do Shiwy, \"Zniszczciela Zła\", \"Króla\". Nazwa jest połączeniem (sandhi) dwóch słów: Neel (\"niebieski\") i Ish (\"Pan\" lub \"Bóg\").</p>", "Neel": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nel</b>.</p><b>Nela</b> – imię żeńskie, powstałe jako usamodzielnione zdrobnienie imion z zakończeniem -<i>nela</i> lub podobnym, takich jak na przykład <a href=\"https://pl.wikipedia.org/wiki/Kornelia\" target=\"_blank\" rel=\"noopener noreferrer\">Kornelia</a> lub <a href=\"https://pl.wikipedia.org/wiki/Petronela\" target=\"_blank\" rel=\"noopener noreferrer\">Petronela</a>.", "Nizam": "<p>Nizam (arabski: نظام / niẓām; tamilski: நிசாம்) jest tytułem rządów Państwa Hyderabad i innych półautonomicznych państw w Indianie. Pod czasami Mogałskich Imperium, to był tytuł wojskowy, przypisany przez cesarzy Mogałów do zarządzania półautonomicznymi terytoriami, a później Nizamy coraz bardziej uzyskały władzę i tytuł dziedziczony w formie ojca przekazu, podobny do urzędu ostatecznego Południa.</p>", "Niazi": "<p>Niazi, Niazai lub Niyazai to jedno z największych plemion pasztunów, które mieszkają w Afganistanie i północno-zachodniej części Pakistanu.</p>", "Nikyta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nykyta</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikita</b>.</p><p>Nikita: Nikita to męskie imię w krajach postsowieckich i niektórych krajach wschodniej Europy. Nikita Wodopol (dzień Nikita) - dzień kalendarza narodowego wschodnich Słowań.</p>", "Nabeel": "<p>Nabil, Nabeel lub Nabyl (arabickie: نبيل), w niektórych językach przetłumaczony jako Nebil, jest męskim imieniem pochodzącym z arabskiego, co oznacza \"noble\". Femminina to Nabila, Nabilah, Nabeela lub Nabeelah.</p>", "Nitai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nita</b>.</p><p>Nita elsaff jest pająkiem z rodziny Pholcidae. Rośliny te występują w Egipcie i Uzbekistanie.</p>", "Nixon": "<p>Nickson, Nixon) - angielskie nazwisko.</p>", "Niki": "<p>Niki - firma lotnicza z siedzibą w Wiedniu, Austria. Służiała regularnymi lotami do Europy i Egiptu z Wiednia, Salzburg, Friedrichshafen na zamówienie turoperatora Neckermann Reisen.</p>", "Nykodym": "<p>Nykodym to ukraińskie imię męskie. Jest to wariant nazwiska Nikodemus.</p>", "Ndubuisi": "<p>Ndubuisi (czasami pisane Ndubisi) jest powszechną męską nazwą i nazwą pochodzenia Igbo. Połączenie elementów ndu + bụ + isi oznacza dosłownie \"życie jest najważniejsze\".</p>", "Nadar": "<b>Nadar</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Imię to składa się z dwóch członów: <i>na</i> („na”) oraz <i>dar</i> („upominek, dar, ofiara”). Mogło ono oznaczać „ten, który jest darem”.", "Neculai": "<p>Neculai to rumuńskie imię i nazwisko męskie i wariant Nicolae. Może odnosić się do: Neculai Munteanu (ur. 1941), rumuński antykomunistyczny dysydent Neculai Onțanu (ur., 1949), rumuńskiego polityka Neculai Păduraru (ur. 1946), rumuńskiego rzeźbiarza i malarza Neculai Rățoi (1939-2016), rumuńskiej polityki Neculai Alexandru Ursu (1926-2016), rumunskiego lingwisty, filologa i historyka literaturycznego Neculai Vasilcă (ur. 1955), rumuńczyka piłkarza handbalisty</p>", "Nuwan": "<p>Nuwan (Sinhala: නුවන්) to męskie imię z języka singalijskiego. Może odnosić się do następujących znanych kryketerów z Sri Lanki: Nuwan Chamara (ur. 1983) Nuwan Ekanayake (ur. 1980), Nuwan Indika (ur. 1985), Nuwan Jayawardene (ur. 1978) Nuwan Karunaratne (ur. 1994) Nuwan Kavinda (ur. 1992), Nuwan Kulasekara (ur. 1982), Nuwan Liyanapathirana (ur. 1987), Nuwan Pradeep (ur. 1986), Nuwan Priyadarshana (ur. 1993), Nuwan priyankara (ur. 1976), Nuwan...</p>", "Netanel": "<p>Natanael (grecki: Ναθαναήλ, hebrajsky: נְתַנְאֵל, romanized: natan'el, lit. 'dany przez Boga') jest angielską nazwą pochodzącą z hebrajskiego.</p>", "Neville": "<p>Neville - angielskie imię i nazwisko mężczyzn.</p>", "Ning": "<p>Ning (wymawia się Ning) to platforma pozwalająca użytkownikom tworzyć własne sieci społecznościowe. Usługa uruchomiona w październiku 2005 roku.</p>", "Nicklas": "<p>Nicklas to imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Najib": "<p>Najib lub Najeeb (arabickie: نجيب) to arabskie imię męskie. Do wybitnych osób z tym nazwiskiem należą:</p>", "Navid": "<p>Nawid (persański. Noyd , dosłownie Wiadomość Radzenia, pełna nazwa Nawid-e Elm-o Sanat, perskie.</p>", "Nanda": "<p>Nanda (ang. Nanda, marathi Nanda, 8 stycznia 1939 - 25 marca 2014) - indyjska aktorka.</p>", "Niaz": "<p>Niaz, NIAZ, Niyas lub Neyaz mogą odnosić się do:</p>", "Niccolo": "<p>Niccolò to włoskie imię męskie, pochodzące od greckiego Nikolaos, co oznacza \"wygrywający ludzi\" lub \"champion ludzi\". Istnieje kilka męskich wariantów nazwiska: Nicolò, Niccolò, Nicolas i Nicola.</p>", "Nepomucen": "<b>Nepomucen</b> - imię męskie pochodzenia łacińskiego. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Nepomucena\" target=\"_blank\" rel=\"noopener noreferrer\">Nepomucena</a>.", "Nasimi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nasim</b>.</p><p>Nassim (arabski: نسيم) również przetransliterowany jako Nacim, Naseem, Nasseem, Nasim, Nesim lub Nessim, jest unisex nazwisko oznaczające \"miękkie wiatr, świeży powietrze\". Jest używany głównie w kulturach i grupach językowych Bliskiego Wschodu i Azji Południowej.</p>", "Nguyên": "<p>W języku wietnamskim nazwa może wskazywać obiekty: Jednostka walutowa Chin, patrz Yuan China Wang, państwo służące Chu w chińskiej historii, ojczyzna jest Wang Ba, brat Chu Wu Wang Wang Wang Wang, państwo założone przez Cao Cao. Władca, rząd chińskiego faizy.</p>", "Nuh": "<p>Nuh to gmina z okręgu Gurgaon w stanie Haryana w Indiach.</p>", "Neta": "<p>Hozon Auto (cz. Wręcz przeciwnie.</p>", "Nikol": "<b>Pryzmat Nicola</b> (także <b>nikol</b>) – rodzaj <a href=\"https://pl.wikipedia.org/wiki/Polaryzator\" target=\"_blank\" rel=\"noopener noreferrer\">polaryzatora</a>. Polaryzacja światła zachodzi wskutek <a href=\"https://pl.wikipedia.org/wiki/Dw%C3%B3j%C5%82omno%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">dwójłomności</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Ca%C5%82kowite_wewn%C4%99trzne_odbicie\" target=\"_blank\" rel=\"noopener noreferrer\">całkowitego wewnętrznego odbicia</a> jednej ze składowych polaryzacyjnych światła. Nazwa pochodzi od wynalazcy, <a href=\"https://pl.wikipedia.org/wiki/Szkocja\" target=\"_blank\" rel=\"noopener noreferrer\">szkockiego</a> <a href=\"https://pl.wikipedia.org/wiki/Fizyka\" target=\"_blank\" rel=\"noopener noreferrer\">fizyka</a> i <a href=\"https://pl.wikipedia.org/wiki/Geologia\" target=\"_blank\" rel=\"noopener noreferrer\">geologa</a> <a href=\"https://pl.wikipedia.org/wiki/William_Nicol\" target=\"_blank\" rel=\"noopener noreferrer\">Williama Nicola</a> żyjącego w na przełomie <a href=\"https://pl.wikipedia.org/wiki/XVIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVIII</a> i <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a>.", "Namaz": "Odmawiający salat powinien być w stanie rytualnej czystości (uzyskuje się ją przez obmycie wodą – <a href=\"https://pl.wikipedia.org/wiki/Wudu_(ablucja)\" target=\"_blank\" rel=\"noopener noreferrer\">wudu</a>, a gdy jej nie ma, to piaskiem – <a href=\"https://pl.wikipedia.org/wiki/Tajammum\" target=\"_blank\" rel=\"noopener noreferrer\">tajammum</a>). Rozkłada on specjalny dywanik (<i><a href=\"https://pl.wikipedia.org/wiki/Modlitewnik_(islam)\" target=\"_blank\" rel=\"noopener noreferrer\">sadżadża</a></i>; nie jest obowiązkowy), zwraca się w kierunku <a href=\"https://pl.wikipedia.org/wiki/Mekka\" target=\"_blank\" rel=\"noopener noreferrer\">Mekki</a> i wykonuje określoną liczbę pokłonów, gestów i recytacji wersetów (<a href=\"https://pl.wikipedia.org/wiki/Aja\" target=\"_blank\" rel=\"noopener noreferrer\">ajatów</a>) <a href=\"https://pl.wikipedia.org/wiki/Koran\" target=\"_blank\" rel=\"noopener noreferrer\">Koranu</a> (przede wszystkim pierwszej sury <i><a href=\"https://pl.wikipedia.org/wiki/Al-Fatiha\" target=\"_blank\" rel=\"noopener noreferrer\">Al-Fatiha</a></i>). Największe znaczenie mają modlitwy piątkowe (<a href=\"https://pl.wikipedia.org/wiki/D%C5%BCummuah\" target=\"_blank\" rel=\"noopener noreferrer\">Dżummuah</a>) – odmawiane wspólnie w <a href=\"https://pl.wikipedia.org/wiki/Meczet\" target=\"_blank\" rel=\"noopener noreferrer\">meczecie</a>, którym często towarzyszy kazanie (<i><a href=\"https://pl.wikipedia.org/wiki/Chutba\" target=\"_blank\" rel=\"noopener noreferrer\">chutba</a></i>). Salat na całym świecie odbywa się wyłącznie w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">języku arabskim</a>.", "Naoki": "<b>Naoki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;なおき, ナオキ) – popularne <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Nhật": "<p>Japonia (jap. 日本, Hepburn: albo), pełna nazwa Japonia (日本国, Nihon-koku lub Nippon-koku), jest państwem i wyspą w regionie wschodniej Azji, znajdującym się na wschodnim krańcu Morza Japonii i Morza Chińskiego, na zachód graniczącą z północną północną Koreą przez Morze Japonii, na północ z Far Wschodnim Rosją przez Okhotsk i na południe z wyspą Taiwan przez Morze Chińskiego. Japonia jest częścią ognia i rozciąga się na wyspach...</p>", "Nicky": "<p>Trần Phong Hào (ur. 6 marca 1995), znany jako Nicky, jest wietnamskim piosenkarzem, raperem, tancerzem i aktorem. Był członkiem zespołu Monstar.</p>", "Naji": "<p>Naji (najgorętszy mężczyzna na WoS) (turski), arabski: ناجي, Nājī) to arabskie imię męskie, które pochodzi od arabskiego czasownika przetrwać. To też nazwisko.</p>", "Najeeb": "<p>Najib lub Najeeb (arabickie: نجيب) to arabskie imię męskie. Do wybitnych osób z tym nazwiskiem należą:</p>", "Nurdin": "<p>Nur al-Din (arabski: نور الدين, romanized: nūr ad-dīn) to męskie arabskie imię, tłumaczące na \"światło wiary\", nūr oznacza \"świetło\" i dīn oznacza \"religię\". Ostatnio nazwa ta była używana również jako nazwisko.</p>", "Newton": "<p>Isaac Newton (ang. Sir Isaac Newton, angielski wymowa: [ˌaɪzək ˈnjuːtən]; 25 grudnia 1642 [4 stycznia 1643] - 20 [31] marca 1727) - angielski fizyk, matematyka, mechanik i astronom, jeden z twórców fizyki klasycznej i analizy matematycznej.</p>", "Nikander": "<b>Nikander</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Grecy\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, złożone z członów <i>Nike</i> — (\"zwycięstwo\") i <i>andros</i> — (\"mężczyzna\"). Istnieje kilku świętych o tym imieniu.", "Nihal": "<p>Nihał (β Zwierzę, Beta Zwierzę - lat. Beta Leporis) - gwiazda znajdująca się w konstelarzji Zwierzę oddalona od nas około 159 lat świetlnych.</p>", "Najmiddin": "<p>Najm al-Din (arabski: نجم الدين, romanized: Najm al - Dīn, lit. 'Gwiezda Wiary'), również przetransklimatyzowany Najm ad-Din, Najmuddin itp., jest męskim imieniem pochodzenia arabskiego.</p>", "Nguyễn": "Nazwisko pochodzi z <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">Chin</a>, gdzie jest pisane 阮 i wymawiane <i>Ruǎn</i> <a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#91;</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_z_retrofleksj%C4%85_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">ʐ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_p%C3%B3%C5%82otwarta_wargowo-mi%C4%99kkopodniebienna\" target=\"_blank\" rel=\"noopener noreferrer\">w</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">à</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#93;</a>.", "Nataliia": "<p>Natalia jest nazwiskiem dla kobiet z oryginalnym późnolatynskim znaczeniem \"Dzień Bożego Narodzenia\" (por. lat. natale domini).</p>", "Nawaz": "<p>Nawaz (persk: نواز, romanized: ten, kto miłuje; transliteracje różnią się) może odnosić się do:</p>", "Nilo": "<p>Nilo jest samorządem w prowincji Cundinamarca w Kolumbii. Gmina Nilo jest stolicą terenu.</p>", "Nuraddin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nuradin</b>.</p><p>Nur al-Din (arabski: نور الدين, romanized: nūr ad-dīn) to męskie arabskie imię, tłumaczące na \"światło wiary\", nūr oznacza \"świetło\" i dīn oznacza \"religię\". Ostatnio nazwa ta była używana również jako nazwisko.</p>", "Nasr": "<p>Nasr (1 listopada 1287 - 16 listopada 1322), pełne nazwisko Abu al-Juyush Nasr ibn Muhammad (arabski: أبو الجيوش نصر بن محمد), był czwartym Nasrydskim władcą Królestwa Grenady od 14 marca 1309 roku do jego ustąpienia w dniu 8 lutego 1314 roku. Był synem Muhammada II al-Faqih i Shams al-Duha.</p>", "Navarro": "<p>Navarro (hisp. Navarro) - hiszpańska nazwisko i toponim:</p>", "Nave": "<p>Nave jest miastem Brescy w Lombardy. Miasto to ma powierzchnię 27 km2, licząc 10 306 mieszkańców.</p>", "Nikko": "<p>Nikko może być: Miasto Nikko (日光市), miasto prowincji Tochigi. 日光の社寺: społeczność świątyń, świątyni, świątyn, świąteń Nikko, światowego dziedzictwa kulturowego Mistrz Nikko (日興) (1246-1333), jeden z założycieli buddyzmu Nichiren.</p>", "Nacer": "<p>Nacer (arabski: ناصر, romanized: Nāṣir, lit. 'wielką zwycięstwa') jest męskie imię i nazwisko, powszechnie występujące w językach arabskim i perskim.</p>", "Nerses": "<p>Nerses (starożytnie armenijski: Ներսէս) jest armenijską wariantą Narse. Z dodaniem -ian i -yan, staje się armenskim nazwiskiem rodzinnym, tak jak Nersesian i Nersisyan.</p>", "Neven": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nevena</b>.</p><p>Nevena (kirylicki: Невена) to kobiece imię popularne w językach sławskich południowych. Nazwa jest kobiecością męskiego imienia Neven, co oznacza \"kalendulę oficinalną\".</p>", "Nouman": "<p>Nu'man (arabski: نعمان, romanized: Nuʿmān) to arabskie imię pochodzące z czasów przedislamskich, oznaczające krew lub czerwony. W większości przypadków islamskie imię jest powszechnie związane z arabskim słowem oznaczającym błogosławieństwo.</p>", "Nikanor": "<b>Nikanor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, zaczerpnięte z <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>, z <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99gi_deuterokanoniczne\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Machabejskiej</a>. <a href=\"https://pl.wikipedia.org/wiki/Nikanor_(diakon)\" target=\"_blank\" rel=\"noopener noreferrer\">Nikanor</a> był również jednym z pierwszych siedmiu <a href=\"https://pl.wikipedia.org/wiki/Diakon\" target=\"_blank\" rel=\"noopener noreferrer\">diakonów</a>. Imię jest formą oboczną imienia <a href=\"https://pl.wikipedia.org/wiki/Nikander_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Nikander</a>, pochodzi od greckiego słowa <i>nikao</i> = „zwyciężam”, czyli oznacza <i>zwycięzca</i>", "Nicolaj": "<p>Nicolaj to męskie imię. Do osób z tym nazwiskiem należą:</p>", "Nazareno": "<p>Nazareno - własne imię; rozpowszechnione w postaci nazwisk.</p>", "Nezar": "<p>Nizar lub Nazar lub Nezar lub Nezzar (arabski: نزار, romanized: nizār) może odnosić się do:</p>", "Nana": "<p>NANA (jap. ナナ Nana) - seria z siódmego manga autorstwa Ay Yadzawa, wydana w czasopiśmie Cookie wydawnictwa Shueisha.</p>", "Niemir": "<b>Niemir</b>, <b>Niemirz</b>, <b>Niemierz</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z dwóch członów: <i>nie-</i> (negacja) i <i>-mir</i> („pokój, spokój, dobro”). Być może oznaczało „tego, kto nie zna pokoju” albo powstało przez negację imion z członem <i>Mir-</i> (takich, jak <i><a href=\"https://pl.wikipedia.org/wiki/Mirogniew\" target=\"_blank\" rel=\"noopener noreferrer\">Mirogniew</a></i> albo <i><a href=\"https://pl.wikipedia.org/wiki/Mirogod\" target=\"_blank\" rel=\"noopener noreferrer\">Mirogod</a></i>). Pisownia z kończowym <i>-rz</i> prawdopodobnie jest zapisem imienia zdrobniałego, uformowanego przy użyciu przyrostka <i>-jь</i>, pod wpływem którego wygłosowe <i>-r</i> przeszło w <i>-rz</i>. W dawnych źródłach mazowieckich jako zamiennik tego imienia w formie <i><b>Niemierza</b></i> często pojawia się imię <a href=\"https://pl.wikipedia.org/wiki/Erazm\" target=\"_blank\" rel=\"noopener noreferrer\">Erazm</a>.", "Nicodème": "<p>Nicodème to nazwisko pochodzące z francuskiego. Odpowiada nazwa Nikodem.</p>", "Nemezjusz": "<b>Nemezjusz</b>, <b>Nemezy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>némesis</i>, oznaczającego \"przydzielenie tego, co się komu należy\", które stało się w mitologii nazwą uosobienia sprawiedliwości (<a href=\"https://pl.wikipedia.org/wiki/Nemezis\" target=\"_blank\" rel=\"noopener noreferrer\">Nemezis</a>). Istnieje kilku świętych patronów tego imienia.", "Nicole": "<p>Nichol (niem. Nicole, przyjdź.</p>", "Nelson Enrique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nelson</b>.</p><p>Edward William Nelson (ang. Edward William Nelson; 1855 - 1934) - amerykański badacz i etnolog.</p>", "Nilton": "<p>Nilton lub Nilton może odnosić się do: Nilton (komiker), portugalski komiks i sędzia w portugalskiej wersji Thank God You're Here Nílton (piłkarz, urodzony w grudniu 1987 r.), brazylijskiego piłkarza Nílton (urodzony w kwietniu 1987 r.) (urodzona w 1987 r.), brytyjskiego piłkarz Nilton César (1939-2026 r.), brzylijskiego śpiewaków Nilton Varela (urodzonych w 2001 r.), portugalskiego piłka nożego</p>", "Nawoj": "<b>Nawoj</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Imię to składa się z dwóch członów: \"na\" (\"naj\") oraz \"woj\" (\"wojownik\"). Miało ono charakter życzący i miało sprawić, że ten, kto je nosi, będzie dobrym (najlepszym) wojownikiem. Jego żeńskim odpowiednikiem jest imię <a href=\"https://pl.wikipedia.org/wiki/Nawoja\" target=\"_blank\" rel=\"noopener noreferrer\">Nawoja</a>.", "Nordin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nordine</b>.</p><p>Nur al-Din (arabski: نور الدين, romanized: nūr ad-dīn) to męskie arabskie imię, tłumaczące na \"światło wiary\", nūr oznacza \"świetło\" i dīn oznacza \"religię\". Ostatnio nazwa ta była używana również jako nazwisko.</p>", "Nedeljko": "<p>Nedeljko (Serbski: Недељко) to serbskie imię męskie. Może odnosić się do: Nedeljko Bajić Baja (ur. 1968), piosenkarz Nedeljko Bulatović (1938-2023), piłkarz i menedżer piłki nożnej Nedeljko Čabrinović (1895-1916), rewolucyjny Nedeljko Gvozdenović (1902-1988), malarz Nedeljco Jovanović (ur. 1970), piłkacha ręcznego Nedeljko Malić (ur., 1988), piłkocha Nedeljko Milosavljević (ur.1960), piłkowca Nedeljko Vukoje (ur. 1943), piłkę nożną</p>", "Nel": "<b>Nela</b> – imię żeńskie, powstałe jako usamodzielnione zdrobnienie imion z zakończeniem -<i>nela</i> lub podobnym, takich jak na przykład <a href=\"https://pl.wikipedia.org/wiki/Kornelia\" target=\"_blank\" rel=\"noopener noreferrer\">Kornelia</a> lub <a href=\"https://pl.wikipedia.org/wiki/Petronela\" target=\"_blank\" rel=\"noopener noreferrer\">Petronela</a>.", "Nykola": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikola</b>.</p><b>Nikola</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, współcześnie sprowadzony do języka polskiego żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Miko%C5%82aj\" target=\"_blank\" rel=\"noopener noreferrer\">Mikołaj</a>. Pochodzi od greckich słów <i>Nikos</i> – <i>zwycięstwo</i> i <i>laos</i> oznaczającego <i>ludzie</i>. Wśród imion nadawanych nowo narodzonym dzieciom, Nikola w 2017 r. zajmowała 26. miejsce w grupie imion żeńskich, co oznacza spadek o 16 miejsc od 2009 r., kiedy to zajmowała 10. miejsce w analogicznej grupie. W całej populacji Polek Nikola zajmowała w 2017 r. 73. miejsce (66 007 nadań). Imię zyskało jeszcze na popularności. W styczniu 2025 r. w rejestrze <a href=\"https://pl.wikipedia.org/wiki/PESEL\" target=\"_blank\" rel=\"noopener noreferrer\">PESEL</a>, wśród publicznie dostępnych danych dotyczących osób żyjących, wykazano 78429 kobiet o imieniu Nikola nadanym jako imię pierwsze.", "Nar": "<p>Nar - marka handlowa OOO ⁇ Azerfon ⁇ , operatora łączności komórkowej standardów GSM, UMTS i LTE, działającego na terytorium Azerbejdżanu.</p>", "Nandu": "<p>⁇ Nyandu ⁇ (hisp. Ñandú - ⁇ nandu ⁇) - argentyński wojskowy samochód o zwiększonej przepustowości, opracowany przez inżynierów kierownictwa DGME pod wodzą Martina Roitera.</p>", "Nuradin": "<p>Nur al-Din (arabski: نور الدين, romanized: nūr ad-dīn) to męskie arabskie imię, tłumaczące na \"światło wiary\", nūr oznacza \"świetło\" i dīn oznacza \"religię\". Ostatnio nazwa ta była używana również jako nazwisko.</p>", "Niroshan": "<p>Charles Niroshan może odnosić się do Niroshan Bandaratilleke, kryketa Sri Lankan Niroshan Dickwella, kryketeta Sri Lanka Niroshan Mani, indyjskiego piłkarza Niroshan Illeperuma, aktora Niroshan Perera, polityka Sri Lankanu Niroshan Premaratne, polityka SRL Niroshan Wijekoon, gracza badminton w Sri Lance Chaminda Niroshan, kryketar Sri Lankan</p>", "Nicefor": "<b>Nicefor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Od greckiego <i>Νικηφόρος (Nikiforos)</i>, czyli „niosący zwycięstwo”. Jego wschodniosłowiańską wersją jest <b>Nikifor</b>.", "Nazariusz": "<b>Nazariusz</b>, <b>Nazary</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające \"pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Nazaret\" target=\"_blank\" rel=\"noopener noreferrer\">Nazaretu</a>\". Wśród patronów tego imienia, <a href=\"https://pl.wikipedia.org/wiki/Nazariusz_i_Celsus\" target=\"_blank\" rel=\"noopener noreferrer\">św. Nazariusz</a>, męczennik z I lub III wieku.", "Narayanan": "<p>Narayana (z angielskiego Narayane, Narayanan, Narayankar lub Narine) (od sanskrytycznego नारायण, nārāyaṇá, dosłownie \"wieczny człowiek\") jest indyjską nazwą. Jest to identyczne w postaci z nazwą boga Narayana, innego imienia dla Wisnu.</p>", "Nimesh": "<p>Nimesh to zarówno imię, jak i nazwisko. Wśród znanych osób z tej nazwy są: Nimesh Bandara (ur. 1997), kryketar Sri Lankan Nimesh Kampani (ur. 1946), indyjski bankier inwestycyjny Nimesh Kariyawasam (ur. 1994), kryketer Sri Lankan Nimetesh Patel (ur. 1986), amerykański komikator Nimesh Perera (ur. 1977), krykator Sri Lankanin Nimesh Perer (ur. 1982), krykater Sri Lankanim Nimesh Vimukthi (ur. 1997, krykator Madhawa...</p>", "Nan": "<p>Nieliczne (NaN z angielskiego Not-a-Number) - jeden z wyjątkowych stanów liczby z płynącą wskaźnikiem.</p>", "Nitish": "<p>Nitish to indyjskie imię męskie z sanskrytu oznaczające \"władca wytycznych\". Wśród znanych osób z nazwiskiem są: Nitish Beejan, maorycjanski polityk Nitish Bharadwaj, indyjski aktor Nitish Chavan (ur. 1990), indyjski aktor filmowy i telewizyjny z języka marathi Nitish Jain, indyjscy edukacyjny Nitish Katara, indyjskie dyrektor biznesowy zamordowany w 2002 roku Nitish Kumar, premier Bihar Nitish Kumer (kryketacz), kanadyjski kryketacz Nitish Chandra Laharry...</p>", "Nadiia": "<p>Nadiya lub Nadiia (ukraina: Надія) to imię żeńskie, pochodzące z ukraińskiego słowa oznaczającego \"oczekiwanie\". Jest nosiona przez następujących osób: Nadia Al-Kokabany, jemenską pisarkę Nadiya Anderson (ur. 1986), połowę amerykańskiego duetu osobowości telewizyjnej Nadiya Babych (1943-2021), ukraińską lingwistę i filologię Nadiya Baranova (ur. 1983), ukraińską goalierkę futbolu Nadiia Bashynska (ur. 2003), ukraiński-kanadyjską tancerkę lodową Nadiia Bielkina (ur. 1990),...</p>", "Nikodym": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nykodym</b>.</p><p>Nykodym to ukraińskie imię męskie. Jest to wariant nazwiska Nikodemus.</p>", "Ngọc Sơn": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nilantha": "<p>Nilantha to imię. Znani ludzie z imieniem: Nilantha Bopage (ur. 1972), kryker Sri Lanki Nilantha Cooray (ur. 1978), krykera Sri Lanki nilantha Jayawardena, policjant Sri Lanki Neilantha Ratnayake (ur. 1968), krykerka Sri Lanki Nileantha Tillakaratne (ur. 1977), krykerkera Sri Lanka</p>", "Nishantha": "<p>Nishantha to imię z Syngaly. Znani ludzie z nazwiskiem to: Nishantha Fernando (urodzony w 1970 roku), kryketar Sri Lanki Nishantha Ferdinand (gracz karromu), mistrz świata w Karromu Nishantha Jayaweera, polityk Sri LankiNishantha Kumara (urodzona w 1985 roku), krykietar Sri Lanka Nishantha Muthuhettigamage, polityk SRL Piyal Nishantha de Silva (urodzono w 1970 roku), polityk Sri Lanka Nishantha Ranatunga (urodzone w 1966 roku),...</p>", "Nolberto": "<p>Nolberto to męskie imię. Znanymi osobami z nazwiskiem są: Nolberto Herrera (zmarł w 2014 roku), meksykański dziennikarz Nolberto Molina (ur. 1953), kolumbijski piłkarz i menedżer Nolberto Solano (ur. 1974), peruwiański piłkarze i menedżer</p>", "Niculae": "<p>Niculae to rumuńskie imię i nazwisko. Do wybitnych osób, które go posiadają, należą:</p>", "Nissan": "<p>Nissan Motor Co. , Ltd.  (Jap.</p>", "Nam Anh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nam</b>.</p><p>W wietnamskim, Nam lub mascul jest słowem do wskazania: Mężczyzna: płci męskiej ludzi, w przeciwieństwie do \"żwomen\" jest płcią (żwomen) najniższej rangi szlachty feitów: Namcowiec kierunek: Słowo-Jużny zakres południowej dzielnicy kolonii miasteczkowej, prowincji Ho Nam, China: Słowe dzielnicy okręgów (khu) o nazwie Nam, patrz Naim (distrikty). W słowach \"wstrzymanie\" wskazują kierunek: męskie leki...</p>", "Naufal": "<p>Naufal to indonezyjska męska nazwa. Znani ludzie z nazwiska to: Naufal Azman (ur. 1998), indonezyjski piłkarz Naufal Ilham (ur. 2002), indonezijski piłkerz Naufel Rahmanda (ur. 2000), indonezyjczy piłkarze Muhammad Naufal Zidan, indonezyjska ofiara morderstwa</p>", "Nykon": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikon</b>.</p><b>Nikon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, wywodzące się od greckiego <i>νικη (nike)</i>, co oznacza \"zwycięstwo\". Imię to stosunkowo największą popularnością cieszyło się u prawosławnych Słowian wschodnich. Nikon <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/23_marca\" target=\"_blank\" rel=\"noopener noreferrer\">23 marca</a> i <a href=\"https://pl.wikipedia.org/wiki/26_listopada\" target=\"_blank\" rel=\"noopener noreferrer\">26 listopada</a>.", "Nai̇l": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Naili</b>.</p><p>Naili (arabski: نائلی) to arabskie pochodzenie męskie nazwisko i nazwisko. Nazwa jest używana w Turcji z tym samym znaczeniem jak Nail: \"odniosły, podbiły\". Jest to wariant Naila przyłączony z tureckim oskarżającym markerem przypadku -i.</p>", "Nistor": "<p>Nistor to rumuńskie imię i nazwisko mężczyzn. Osoby z tą nazwą to: Nistor Grozavu Nistor Văidean Constantin Nistor (dysambigujacja), dwaj sportowcy Dan Nistor (urodzony 1988), rumuński piłkarz Ion Nistor (1876-1962), rumuńska historyk i polityk Steliana Nistor (urodzona 1989), rumuńskiego gimnastki Steven Nistor (uraty 1979), amerykański perkusista</p>", "Nisan": "Kabaliści zwracają też uwagę na fakt, iż słowo <i>Pesach</i> może być rozłożone na dwa człony: <i>Pe</i> oraz <i>Sach</i>, co oznacza <i>usta mówią</i>.", "Naseem": "<p>Nassim (arabski: نسيم) również przetransliterowany jako Nacim, Naseem, Nasseem, Nasim, Nesim lub Nessim, jest unisex nazwisko oznaczające \"miękkie wiatr, świeży powietrze\". Jest używany głównie w kulturach i grupach językowych Bliskiego Wschodu i Azji Południowej.</p>", "Ngoc Anh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nedžad": "<p>Nejat (i jego warianty Necat, Nexhat i Nedžad) to tureckie imię męskie pochodzące z Persji. Nazwa znajduje się w językach tureckim, albańskim i bosnijskim.</p>", "Nimal": "<p>Nimal może odnosić się do: Nimal Bandara, sri Lankański polityk Nimal Gamini Amaratunga, śri Lankański sędzia Nimal Gunaratne, szri Lankajski oficer sił powietrznych Nimal Mendis, sri Lankanski polityk Nima Piyatissa (ur. 1968), sri Lankajski polityk Nimar Rajapakshe, śri lankański akademik Nimal Senanayake, śri Lankański neurolog, lekarz Nimal Siripala de Silva, sri Lanki polityk Niman Wijesinghe, śry Lankański politik Ahmed Nimal (1963-2026), Malediwa...</p>", "Neymar": "<p>Neymar da Silva Santos Júnior (port. Neymar da Silva Santos Junior; portugalskie wymowy: [nejˈmaʁ dɐ ˈsiwvɐ ˈsɐ̃tus ˈʒũɲoʁ]; urodz.</p>", "Nikolo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nicolo</b>.</p><p>Nicolò (w włoskim: [nikoˈlɔ]) to włoskie imię męskie. Kolejna wariantka to Niccolò, najczęstsza w Toskanii.</p>", "Nurken": "<p>Nurken (kazachski: Нұркен, Nūrken) to kazachskie męskie imię. Do wybitnych osób z tym nazwiskiem należą: Nurken Abdirov (1919-1942), kazachski pilot Nurken Mazbayev (ur. 1972), kazachski piłkarz</p>", "Ngoc Thanh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nazaryi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nazary</b>.</p><b>Nazariasz</b>, <b>Nazary</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, oznaczające \"oddany Bogu\". Wśród patronów tego imienia — męczennik Nazary (<a href=\"https://pl.wikipedia.org/wiki/I_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">I wiek</a>).", "Nairi": "<b>Nairi</b> – <a href=\"https://pl.wikipedia.org/wiki/Asyria\" target=\"_blank\" rel=\"noopener noreferrer\">asyryjska</a> nazwa grupy plemion na terytorium starożytnego państwa <a href=\"https://pl.wikipedia.org/wiki/Urartu\" target=\"_blank\" rel=\"noopener noreferrer\">Urartu</a>. Określenie to funkcjonowało w XIII–XI wieku p.n.e. Niektóre obiekty geograficzne zachowały rdzeń „Nairi” także w późniejszych tekstach asyryjskich, na przykład <a href=\"https://pl.wikipedia.org/wiki/Wan_(jezioro)\" target=\"_blank\" rel=\"noopener noreferrer\">jezioro Wan</a> nazywane było „morzem krainy Nairi” – <i>tâmtu ša mât Nairi</i>. Niektórzy badacze pierwszej połowy XX wieku uznawali asyryjskie słowo „Nairi” za nazwę plemion <a href=\"https://pl.wikipedia.org/wiki/Huryci\" target=\"_blank\" rel=\"noopener noreferrer\">huryckich</a>. Tłumaczyłoby to pochodzenie Urartyjczyków od Hurytów. Badania lingwistyczne, prowadzone w drugiej połowie XX wieku, wykazały, że języki urartyjski i hurycki są ze sobą spokrewnione, co potwierdziło dotychczasową teorię. Niewielka liczba odkrytych źródeł pisanych nie pozwala na jednoznaczne określenie składu etnicznego plemion Nairi oraz zasięgu terytorialnego obszaru, który zamieszkiwały.", "Nova": "<p>Nova to łacińska nazwa nowej gwiazdy, stąd większość innych znaczeń:</p>", "Najibullah": "<p>Najibullah (arabski: نجيب الله) to męskie muzułmańskie imię, składające się z elementów Najib i Allah. Oznacza to wyróżniony (sługa) Boga.</p>", "Njabulo": "<p>Njabulo to południowoafrykańskie imię męskie. Znanymi osobami z nazwiskiem są: Njabulo Blom (ur. 1999), piłkarz południowoafrykański Njabulo Mabuza, Swazi biznesmen i polityk Njabulo Manqana (ur. 1986), południo Afrykański piłkarze Njabulo Ncube (ur. 1989), Zimbabwe kryketkarz Njabulo Ndebele, akademik i pisarz połudnoafrykańska Njabulo Ndlovu (ur. 1994), Swazi piłkarza Njabulo Ngcobo (ur. 1994, południoafrykańskiego piłkarka...</p>", "Natividad": "<p>Natividad może być: Natividad, Pangasinan, Filipin General Mamerto Natividad, Nueva Ecija, Filipin Natividad, Oaxaca, Meksyk</p>", "Nesim": "<p>Nassim (arabski: نسيم) również przetransliterowany jako Nacim, Naseem, Nasseem, Nasim, Nesim lub Nessim, jest unisex nazwisko oznaczające \"miękkie wiatr, świeży powietrze\". Jest używany głównie w kulturach i grupach językowych Bliskiego Wschodu i Azji Południowej.</p>", "Nazareth": "<p>Nazareth (r. Nazareth) - szkocki zespół rockowy, utworzony w 1968 roku przez muzyków zespołu The Shadettes w mieście Danfermlin.</p>", "Ngoc Hung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nicholaus": "<p>Nicholaus to męskie imię. Do osób z tym nazwiskiem należą: Nicholaus Arson (ur. 1977), szwedzki muzyk Nicholau Contreraz (1982 - 1998), amerykański ofiarę tortur Nicholaos Goossen (ur. 1978), amerykańskiego reżysera Nicholausa Johna Michaela Gordona (ur. 1991), kanadyjskiego piosenkarza, rapera i autorka piosenek znanych pod pseudonimem Lil Pappie Nicholause R.</p>", "Ngoc Son": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nandor": "<p>Nándor to węgierska forma nazwiska Ferdinand. W Starożytnym Węgrzech słowo nándor oznaczało \"Bulgarz\", ale nie było używane, prawdopodobnie wkrótce po 1000 roku n.e.</p>", "Nurulla": "<p>Nurullah (arabski: نورالله) to męskie imię pochodzenia arabskiego, co oznacza światło Boga pochodzenia muzułmańskiego. Pochodzi od arabskiego słowa nur, co oznacza światło, a Allah, co oznacza Boga.</p>", "Nimish": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nimisha</b>.</p><p>Nimisha to indyjskie imię kobiece. Może odnosić się do następujących osób: Nimisha Madhvani, ugandzkiej dyplomatki Nimisha Mehta, brytyjskiej aktorki Nimisha Mukerji, kanadyjskiej reżyserki filmowej i telewizyjnej Nimisha Pandey, indyjskiej telewizji i internetowej treści deweloper i kurator Nimisha Sajayan, indyjska aktorka Nimisha Suresh, indyjski aktorka Nimisa Suthar, indyjskich polityków Nimisha Vakharia, indyskiej aktorki</p>", "Nelio": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Neli</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nel</b>.</p><b>Nela</b> – imię żeńskie, powstałe jako usamodzielnione zdrobnienie imion z zakończeniem -<i>nela</i> lub podobnym, takich jak na przykład <a href=\"https://pl.wikipedia.org/wiki/Kornelia\" target=\"_blank\" rel=\"noopener noreferrer\">Kornelia</a> lub <a href=\"https://pl.wikipedia.org/wiki/Petronela\" target=\"_blank\" rel=\"noopener noreferrer\">Petronela</a>.", "Ngọc Thành": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngoc Long": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nuru": "<b>Nuru</b> jest formą <a href=\"https://pl.wikipedia.org/wiki/Masa%C5%BC\" target=\"_blank\" rel=\"noopener noreferrer\">masażu</a> erotycznego z pełnym kontaktem z ciałem, podczas gdy zarówno masażysta lub masażystka, jak i klient są nadzy i pokryci żelem, tradycyjnie wykonanym na bazie <a href=\"https://pl.wikipedia.org/wiki/Makroglony\" target=\"_blank\" rel=\"noopener noreferrer\">wodorostów</a>. Słowo <i>nuru</i> (ぬる) pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">języka japońskiego</a> i oznacza „śliski”.", "Ngoc Tuan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nicușor": "<p>Nicușor to rumuńskie imię męskie. Wraz z Nicolae jest to jedna z rumuńskich wersji nazwy Nicholas.</p>", "Nordine": "<p>Nur al-Din (arabski: نور الدين, romanized: nūr ad-dīn) to męskie arabskie imię, tłumaczące na \"światło wiary\", nūr oznacza \"świetło\" i dīn oznacza \"religię\". Ostatnio nazwa ta była używana również jako nazwisko.</p>", "Nizamuddin": "<p>Nizam al-Din (arabski: نظام الدّین, romanized: Niẓām al-Dīn, lit. 'Dobry Porządek Wiary'), różnie pisane Nizamuddin lub Nizamüddin lub itp.</p>", "Ngoc Dung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nalin": "<p>Nalin to zarówno imię, jak i nazwisko. Znani ludzie z nazwiska to: Nalin Angammana (1945-1995), oficer wojskowy Sri Lanki Nalin Bandara (ur. 1974), polityk Sri Lanki, narodzony w 1974 roku Nalin Bandaranayake, kryker Sri Lanki Naryn Bhatt, polityk Gujarati Naryn Fernando (ur. 1973), polityk Naryn Jayawardena (ur. 1957), śrilankański piosenkarz Nalin Kohli, indyjski polityk Narin Kumar Kateel (ur. 1966), indyjski politik Naryn...</p>", "Nanaji": "<p>Nanaji to indyjskie imię, które oznacza \"dziadek matki\". Znani ludzie z nazwiskiem to: Nanaji Deshmukh (1916-2010), indyjski aktywista Nanaji Sitaram Shamkule, indyjski polityk</p>", "Nouri": "<p>Nuri (zwanego również Nouri, Noori, Nori lub Noory, arabski: نوري, syryjski: ⁇) jest unisex nazwisko i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Nagaraj": "<p>Nagaraj, Nagaraj lub Nagaraja lub Nagarajan to indyjskie imię i nazwisko mężczyzn. Pochodzi z sanskrytu: nagराज nagaraja \"król nagów\".</p>", "Nasreddine": "<p>Nasir al-Din (arabski: نصیر الدین lub ناصرالدین lub نصر الدين, 'obrona wiary'), był pierwotnie tytułem honorowym i jest męskim nazwiskiem i nazwiskiem pochodzenia arabskiego. W języku angielskim istnieje wiele wariantów pisowni z powodu transliteracji, w tym Nasruddin i Nasiruddin.</p>", "Ngoc Minh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Naryman": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nariman</b>.</p><p>Nariman (zwany również Narriman, Nareeman, Neriman, Nəriman) jest nazwą pochodzenia perskiego (perskiego: نریمان Narīmān). Jego korzenie pochodzą z perskiego epiku Shahnameh, napisanego przez Ferdowsi.</p>", "Nand": "Uwaga: w terminologii angielskiej <i>disjunction</i> to polska <a href=\"https://pl.wikipedia.org/wiki/Alternatywa\" target=\"_blank\" rel=\"noopener noreferrer\">alternatywa</a>, odpowiednikiem polskiej dysjunkcji (Sheffera) jest natomiast <i>alternative denial</i>.", "Nnanna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nana</b>.</p><p>NANA (jap. ナナ Nana) - seria z siódmego manga autorstwa Ay Yadzawa, wydana w czasopiśmie Cookie wydawnictwa Shueisha.</p>", "Niilo": "<p>Niilo to imię męskie. Niilo Halonen (1940-2025), fiński skakacz na nartach Niilo Jääskinen (ur. 1958), fiński prawnik i polityk Niilo Mäenpää (ur. 1998), fiński piłkarz Niilo Paasivirta, fiński osobnik internetowy Niilo Saarikivi (ur. 2003), fiński futbolista Niilo Sevänen (ur. 1979), fiński muzyk death metal Niilo Tammisalo, wpływowy fiński sportowiec Niilo Wälläri (1897-1967), fiński...</p>", "Nezir": "<p>Nezir to tureckie męskie imię lub nazwisko. Może odnosić się do:</p>", "Nurudeen": "<p>Nur al-Din (arabski: نور الدين, romanized: nūr ad-dīn) to męskie arabskie imię, tłumaczące na \"światło wiary\", nūr oznacza \"świetło\" i dīn oznacza \"religię\". Ostatnio nazwa ta była używana również jako nazwisko.</p>", "Ngọc Hải": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Naoya": "<p>Naoya (w języku japońskim 直也, 直哉, 直弥, 直矢 lub 尚弥) jest japońskie imię męskie. Znani ludzie z nazwiska to: Naoya Fuji (藤 直也; ur. 1993), japoński piłkarz Naoya Fuchiwara (藤原 直哉; ur. 1965), japońska gracz shogi Naoya Gomoto (郷本 直也; Ur. 1980), japończyk Naoya Hatakeyama (⁇ 山 直哉; Ur. 1958), japowski fotograf Higonoumi Naoya (肥後ノ海 直哉;ur. 1969), japońskiego wrestlerka sumo Naoya Inose (猪瀬 直哉; u ur. 1988), japoanski artysta wizualny...</p>", "Nkosana": "<p>Nkosana to męskie afrykańskie imię, co oznacza księcia. Znani ludzie z nazwiskiem to: Nkosana Makate (ur. 1977), południowoafrykański biznesmen Nkosana Mpofu (ur. 1990), zimbabwski kryketar pierwszej klasy</p>", "Nestor Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nestor</b>.</p><b>Nestor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Istnieją liczni święci o tym imieniu.", "Nicon": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikon</b>.</p><b>Nikon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, wywodzące się od greckiego <i>νικη (nike)</i>, co oznacza \"zwycięstwo\". Imię to stosunkowo największą popularnością cieszyło się u prawosławnych Słowian wschodnich. Nikon <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/23_marca\" target=\"_blank\" rel=\"noopener noreferrer\">23 marca</a> i <a href=\"https://pl.wikipedia.org/wiki/26_listopada\" target=\"_blank\" rel=\"noopener noreferrer\">26 listopada</a>.", "Ngoc Hoang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nkem": "<p>Nkem jest unisex nazwisko występujące wśród Igbo w Nigerii. Jest to skrócona forma Nkemdilim/Nkemdirim, Nkemjika, Nkemakolam lub Nkemakonam i oznacza \"moje\" lub \"moje własne\".</p>", "Narain": "<p>Narayana (z angielskiego Narayane, Narayanan, Narayankar lub Narine) (od sanskrytycznego नारायण, nārāyaṇá, dosłownie \"wieczny człowiek\") jest indyjską nazwą. Jest to identyczne w postaci z nazwą boga Narayana, innego imienia dla Wisnu.</p>", "Ngọc Anh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Natalia": "<b>Natalia</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em><a href=\"https://pl.wikipedia.org/wiki/Dies_natalis\" target=\"_blank\" rel=\"noopener noreferrer\">Dies natalis</a> Domini</em>, tj. <i>w dniu urodzin <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Pana</a></i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie wywodzące się od męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Natal_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Natalis</a>. W Polsce to imię jest poświadczane w formie Natalia w XIV wieku. Dawniej nadawane osobom urodzonym w dniach chrześcijańskich świąt <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCe_Narodzenie\" target=\"_blank\" rel=\"noopener noreferrer\">Bożego Narodzenia</a>. Patronką imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Adrian_i_Natalia_z_Nikomedii\" target=\"_blank\" rel=\"noopener noreferrer\">Natalia z Nikomedii</a>, męczennica.", "Nelson David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nelson</b>.</p><p>Edward William Nelson (ang. Edward William Nelson; 1855 - 1934) - amerykański badacz i etnolog.</p>", "Nessim": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nesim</b>.</p><p>Nassim (arabski: نسيم) również przetransliterowany jako Nacim, Naseem, Nasseem, Nasim, Nesim lub Nessim, jest unisex nazwisko oznaczające \"miękkie wiatr, świeży powietrze\". Jest używany głównie w kulturach i grupach językowych Bliskiego Wschodu i Azji Południowej.</p>", "Narcisse": "<p>Narcisse może być zarówno nazwiskiem, jak i nazwiskiem. Do wybitnych osób z tym nazwiskiem należą:</p>", "Ngọc Minh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Namysław": "<b>Namysław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, które prawdopodobnie powstało poprzez \"poprawienie\" staropolskiego imienia <i>Namysł</i>, kiedy świadomość jego pochodzenia zatarła się i błędnie zostało ono uznane za imię kończące się członem <i>-sław</i> (zamiast <i>-mysł</i>).", "Ngọc Tuấn": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nikki": "<p>Nikodimos (Nikki) Papavaciliu (grek. Νικόδημος Παπαβασιλείου; WD-Preamblula) - cypryjski piłkarz i trener piłki nożnej, obecny trener klubu ⁇ Dynamo ⁇ Česke-Budejewice.</p>", "Ngọc Hoàng": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ndue": "<p>Ndue to albanianskie męskie imię i może odnosić się do: Ndue Marashi (1933-1975), albanianki polityk, były burmistrz Tirana Ndue Mujeci (ur. 1993), albanianka piłkarz Ndue Paluca (ur. 1966), albanian polityk Ndue Përlleshi (1908-1949), kosowskiego-albanianki wojskowy przywódca, lokalny i narodowy bohater Ndue Ukaj (ur. 1977). Albanański pisarz, publicysta, krytyka literacka i teoretyka literacki</p>", "Nehuen": "<p>Nehuén (Hiszpańska wymowa: [neˈwen]) to męskie imię pochodzenia mapucheckiego oznaczające silne.</p>", "Nadia": "<b>Nadzieja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, nawiązujące do jednej z trzech <a href=\"https://pl.wikipedia.org/wiki/Cnoty_teologalne\" target=\"_blank\" rel=\"noopener noreferrer\">cnót teologalnych</a>. <i>Nadia</i> jest zdrobnieniem od rosyjskiej wersji tego imienia – Nadieżdy. Wśród imion nadawanych nowo narodzonym dzieciom, Nadia w 2009 zajmowała 22. miejsce w grupie imion żeńskich.", "Nazary": "<b>Nazariasz</b>, <b>Nazary</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, oznaczające \"oddany Bogu\". Wśród patronów tego imienia — męczennik Nazary (<a href=\"https://pl.wikipedia.org/wiki/I_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">I wiek</a>).", "Nicki": "<p>Nicki to imię i nazwisko i może odnosić się do:</p>", "Niccolơ": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nicolo</b>.</p><p>Nicolò (w włoskim: [nikoˈlɔ]) to włoskie imię męskie. Kolejna wariantka to Niccolò, najczęstsza w Toskanii.</p>", "Ngoc Tu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngọc Long": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngọc Duy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nyl": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nil</b>.</p><b>Nilus</b>, <b>Nil</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego, od gr. <i>neilos</i> – \"rzeka\". Istnieli liczni święci o tym imieniu.", "Nelson Andres": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nelson</b>.</p><p>Edward William Nelson (ang. Edward William Nelson; 1855 - 1934) - amerykański badacz i etnolog.</p>", "Najam": "<p>Najm (arabsko: نجم) lub Najam to arabskie słowo oznaczające Gwiazdę. Najm to bezpośrednie imię koraniczne dla chłopców i dziewcząt, które oznacza \"gwiazdę\", \"światło\", \"od źródło inspiracji\".</p>", "Nawid": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Navid</b>.</p><p>Nawid (persański. Noyd , dosłownie Wiadomość Radzenia, pełna nazwa Nawid-e Elm-o Sanat, perskie.</p>", "Nagarjuna": "Inny <b>Nagardżuna</b> to tantryk, mistrz <a href=\"https://pl.wikipedia.org/wiki/Wad%C5%BCrajana\" target=\"_blank\" rel=\"noopener noreferrer\">buddyzmu Diamentowej Drogi</a> żyjący w <a href=\"https://pl.wikipedia.org/wiki/VIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VIII w.</a> Jego imię pochodzi od wężowych istot wodnych - <i><a href=\"https://pl.wikipedia.org/wiki/Nagowie\" target=\"_blank\" rel=\"noopener noreferrer\">nagów</a></i>, od których uzyskał m.in. sekretne nauki alchemiczne. W <a href=\"https://pl.wikipedia.org/wiki/Buddyzm_tybeta%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">buddyzmie tybetańskim</a> znany przede wszystkim jako uczeń <a href=\"https://pl.wikipedia.org/wiki/Saraha\" target=\"_blank\" rel=\"noopener noreferrer\">Sarahy</a>, od którego otrzymał przekaz <a href=\"https://pl.wikipedia.org/wiki/Mahamudra\" target=\"_blank\" rel=\"noopener noreferrer\">mahamudry</a> - zwieńczenie buddyjskich nauk - który to następnie przekazał <a href=\"https://pl.wikipedia.org/wiki/Shavaripa\" target=\"_blank\" rel=\"noopener noreferrer\">Shavaripie</a>. Obecnie nauki te praktykowane są w szkole <a href=\"https://pl.wikipedia.org/wiki/Kagyu\" target=\"_blank\" rel=\"noopener noreferrer\">karma kagyu</a>.", "Naren": "<p>Naren jest nazwiskiem w różnych kulturach. W Mongolii wewnętrznej, Naren jest chińskim transkrypcją mongolskiego słowa naran (наран), co oznacza \"słońce\".</p>", "Nirmal Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nirmal</b>.</p><p>Nirmal to miasto i dzielnica w hrabstwie Adilabad w stanie Telangana w Indiach.</p>", "Nethanel": "<p>Natanael (grecki: Ναθαναήλ, hebrajsky: נְתַנְאֵל, romanized: natan'el, lit. 'dany przez Boga') jest angielską nazwą pochodzącą z hebrajskiego.</p>", "Ngọc Hưng": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nam Phong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nam</b>.</p><p>W wietnamskim, Nam lub mascul jest słowem do wskazania: Mężczyzna: płci męskiej ludzi, w przeciwieństwie do \"żwomen\" jest płcią (żwomen) najniższej rangi szlachty feitów: Namcowiec kierunek: Słowo-Jużny zakres południowej dzielnicy kolonii miasteczkowej, prowincji Ho Nam, China: Słowe dzielnicy okręgów (khu) o nazwie Nam, patrz Naim (distrikty). W słowach \"wstrzymanie\" wskazują kierunek: męskie leki...</p>", "Ngọc Linh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nathanial": "<p>Natanael (grecki: Ναθαναήλ, hebrajsky: נְתַנְאֵל, romanized: natan'el, lit. 'dany przez Boga') jest angielską nazwą pochodzącą z hebrajskiego.</p>", "Nike": "<p>Nike, Inc.  (MFA: ['naɪkɪ], ⁇ Naiki ⁇) - amerykańska firma transnacjonalna specjalizująca się w ubraniach sportowych i obuwie.</p>", "Nichlas": "<p>Nichlas to męskie imię. Do wybitnych osób z tym nazwiskiem należą: Nichlas Falk (ur. 1971), szwedzki hokejista na lodzie Nichlas Hardt (ur. 1988), duński hokejista Nachlas Rohde (ur. 1992), duński piłkarz.</p>", "Nina": "<b>Nina</b> – imię żeńskie o niejasnej etymologii. Prawdopodobnie wywodzi się od imienia mitycznego założyciela <a href=\"https://pl.wikipedia.org/wiki/Niniwa\" target=\"_blank\" rel=\"noopener noreferrer\">Niniwy</a> i imperium asyryjskiego - Ninosa. W piśmiennictwie imię to występuje w formach: <i>Nina, Nino, Nunia, Nuna i Nonna</i>.", "Nicko": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nick</b>.</p><p>Nick może odnosić się do: Nick Jonas Nick Heidfeld Nick Cannon Nick Ut</p>", "Namo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nam</b>.</p><p>W wietnamskim, Nam lub mascul jest słowem do wskazania: Mężczyzna: płci męskiej ludzi, w przeciwieństwie do \"żwomen\" jest płcią (żwomen) najniższej rangi szlachty feitów: Namcowiec kierunek: Słowo-Jużny zakres południowej dzielnicy kolonii miasteczkowej, prowincji Ho Nam, China: Słowe dzielnicy okręgów (khu) o nazwie Nam, patrz Naim (distrikty). W słowach \"wstrzymanie\" wskazują kierunek: męskie leki...</p>", "Nourdine": "<p>Nur al-Din (arabski: نور الدين, romanized: nūr ad-dīn) to męskie arabskie imię, tłumaczące na \"światło wiary\", nūr oznacza \"świetło\" i dīn oznacza \"religię\". Ostatnio nazwa ta była używana również jako nazwisko.</p>", "Ngọc Tú": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngoc Van": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nestor Javier": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nestor</b>.</p><b>Nestor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Istnieją liczni święci o tym imieniu.", "Nestor David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nestor</b>.</p><b>Nestor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Istnieją liczni święci o tym imieniu.", "Ngoc Nam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nour Eddine": "<p>Nur al-Din (arabski: نور الدين, romanized: nūr ad-dīn) to męskie arabskie imię, tłumaczące na \"światło wiary\", nūr oznacza \"świetło\" i dīn oznacza \"religię\". Ostatnio nazwa ta była używana również jako nazwisko.</p>", "Ngọc Ðức": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Neftali": "Drugi syn <a href=\"https://pl.wikipedia.org/wiki/Jakub_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakuba</a> i <a href=\"https://pl.wikipedia.org/wiki/Bilha\" target=\"_blank\" rel=\"noopener noreferrer\">Bilhy</a>, niewolnicy <a href=\"https://pl.wikipedia.org/wiki/Rachela\" target=\"_blank\" rel=\"noopener noreferrer\">Racheli</a>. Imię nadała mu Rachela na znak swojego zwycięstwa ze swoją siostrą <a href=\"https://pl.wikipedia.org/wiki/Lea_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Leą</a>. Protoplasta jednego z <a href=\"https://pl.wikipedia.org/wiki/Dwana%C5%9Bcie_Plemion_Izraela\" target=\"_blank\" rel=\"noopener noreferrer\">Dwunastu Plemion Izraela</a>.", "Nikolae": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikola</b>.</p><b>Nikola</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, współcześnie sprowadzony do języka polskiego żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Miko%C5%82aj\" target=\"_blank\" rel=\"noopener noreferrer\">Mikołaj</a>. Pochodzi od greckich słów <i>Nikos</i> – <i>zwycięstwo</i> i <i>laos</i> oznaczającego <i>ludzie</i>. Wśród imion nadawanych nowo narodzonym dzieciom, Nikola w 2017 r. zajmowała 26. miejsce w grupie imion żeńskich, co oznacza spadek o 16 miejsc od 2009 r., kiedy to zajmowała 10. miejsce w analogicznej grupie. W całej populacji Polek Nikola zajmowała w 2017 r. 73. miejsce (66 007 nadań). Imię zyskało jeszcze na popularności. W styczniu 2025 r. w rejestrze <a href=\"https://pl.wikipedia.org/wiki/PESEL\" target=\"_blank\" rel=\"noopener noreferrer\">PESEL</a>, wśród publicznie dostępnych danych dotyczących osób żyjących, wykazano 78429 kobiet o imieniu Nikola nadanym jako imię pierwsze.", "Nicos": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikos</b>.</p><p>Nikos (grek. Νίκος, Níkos) jest greckim nazwiskiem. Pochodzi od greckiego Nikolaos, co oznacza \"wygrę narodu\".</p>", "Nam Khánh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nam</b>.</p><p>W wietnamskim, Nam lub mascul jest słowem do wskazania: Mężczyzna: płci męskiej ludzi, w przeciwieństwie do \"żwomen\" jest płcią (żwomen) najniższej rangi szlachty feitów: Namcowiec kierunek: Słowo-Jużny zakres południowej dzielnicy kolonii miasteczkowej, prowincji Ho Nam, China: Słowe dzielnicy okręgów (khu) o nazwie Nam, patrz Naim (distrikty). W słowach \"wstrzymanie\" wskazują kierunek: męskie leki...</p>", "Nirmal Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nirmal</b>.</p><p>Nirmal to miasto i dzielnica w hrabstwie Adilabad w stanie Telangana w Indiach.</p>", "Ngoc Tien": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Niepełka": "<b>Niepełka</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z dwóch członów: <i>nie-</i> (negacja) i <i>-pełka</i> (\"pułk\"). Być może oznaczało \"tego, kto walczy samotnie\" albo powstało przez negację imion z członem <i>-pełk</i> (takich, jak <i><a href=\"https://pl.wikipedia.org/wiki/Przedpe%C5%82k\" target=\"_blank\" rel=\"noopener noreferrer\">Przedpełk</a></i> albo <i><a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99tope%C5%82k_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Świętopełk</a></i>).", "Nao": "<b>Nao</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;なお, ナオ) – popularne <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>, rzadko noszone przez mężczyzn. Jest również używane jako skrót od imion <a href=\"https://pl.wikipedia.org/wiki/Naoko\" target=\"_blank\" rel=\"noopener noreferrer\">Naoko</a>, <a href=\"https://pl.wikipedia.org/wiki/Naoki\" target=\"_blank\" rel=\"noopener noreferrer\">Naoki</a>, Naomi, <a href=\"https://pl.wikipedia.org/wiki/Naoto\" target=\"_blank\" rel=\"noopener noreferrer\">Naoto</a> i itp.", "Noureddin": "<p>Nur al-Din (arabski: نور الدين, romanized: nūr ad-dīn) to męskie arabskie imię, tłumaczące na \"światło wiary\", nūr oznacza \"świetło\" i dīn oznacza \"religię\". Ostatnio nazwa ta była używana również jako nazwisko.</p>", "Ngọc Cường": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ntokozo": "<p>Ntokozo to imię, które oznacza \"radość\". Znanymi osobami z nazwiskiem są: Ntokozo Hlonyana, południowoafrykański polityk Ntokozo Mbambo (ur. 1985), południo Afrykański muzyk Ntokozo Mbuli, prezenter Południowo Afryki Ntokozo mdluli (ur. 1980), połudnoafrykajski muzyk Ntokzo Qwabe (ur. 1991), studentka z Południe Afryki, aktywistka Ntokozo Sikhakhane (ur. 1983), piłkarz południowej Afryki</p>", "Ngoc Vinh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nesi̇mi̇": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nesim</b>.</p><p>Nassim (arabski: نسيم) również przetransliterowany jako Nacim, Naseem, Nasseem, Nasim, Nesim lub Nessim, jest unisex nazwisko oznaczające \"miękkie wiatr, świeży powietrze\". Jest używany głównie w kulturach i grupach językowych Bliskiego Wschodu i Azji Południowej.</p>", "Naoto": "<b>Naoto</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;なおと, ナオト) – męskie popularne <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Nalaka": "<p>Nalaka może odnosić się do Nalaka, wioski w pobliżu Rajgriha, India; miejsce urodzenia Sariputry, jednego z głównych męskich uczniów Gautamy Buddy Nalaka, ucznia Buddy, syna starożytnej indyjskiej askety Asity (który przewidział, że Siddhartha Gautama stanie się Buddy) Nalaka Godahewa, przewodniczący Komisji Giełdownictwa Papierów Wartościowych w Sri Lance Nalaka Gunawardene, pisarz i dziennikarz Nalaka Kolonne, Sri Lankanki polityk Nalaka Kottegoda (ur. ...</p>", "Nani": "<p>Louis Karlus Almeida da Kuńia (port. Luís Carlos Almeida da Cunha; rodzina.</p>", "Ngọc Lâm": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nikoła": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nicola</b>.</p><p>Nicola to portugalska marka kawy, należąca do Massimo Zanetti Beverage Group. Jedna z najstarszych marek kawy w Portugalii.</p>", "Nam Cao": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nam</b>.</p><p>W wietnamskim, Nam lub mascul jest słowem do wskazania: Mężczyzna: płci męskiej ludzi, w przeciwieństwie do \"żwomen\" jest płcią (żwomen) najniższej rangi szlachty feitów: Namcowiec kierunek: Słowo-Jużny zakres południowej dzielnicy kolonii miasteczkowej, prowincji Ho Nam, China: Słowe dzielnicy okręgów (khu) o nazwie Nam, patrz Naim (distrikty). W słowach \"wstrzymanie\" wskazują kierunek: męskie leki...</p>", "Nicodeme": "<p>Nicodème to nazwisko pochodzące z francuskiego. Odpowiada nazwa Nikodem.</p>", "Ngọc Dũng": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ndumiso": "<p>Ndumiso to męskie imię, które oznacza \"chwała\" w języku zulu i \"psalm\" w język xhosa. Znani ludzie z nazwiskiem to: Ndumiso Capa (ur. 1949), południowoafrykański polityk Ndumiso Mabena (ur. 1987), piłkarz Ndumiso Madlala, południo Afrykański piwożer i biznesmen Ndumiso Mamba, minister sprawiedliwości Liswati Ndumiso Mvelase (ur. 1996), gracz kryketa z Południowej Afryki</p>", "Nerio": "<b>Nerio</b> (także <b>Neriene</b> lub <b>Nerienis</b>) – w mitologii rzymskiej jedno z bóstw z grupy <i><a href=\"https://pl.wikipedia.org/wiki/Indigetes\" target=\"_blank\" rel=\"noopener noreferrer\">indigetes</a></i>, pomniejszych lokalnych bóstw o wyraźnie sprecyzowanych kompetencjach; Nerio może być bóstwem <a href=\"https://pl.wikipedia.org/wiki/Sabinowie\" target=\"_blank\" rel=\"noopener noreferrer\">sabińskiego</a> pochodzenia. Nerio była boginią kojarzoną ze sferą wojny, uważaną za personifikację odwagi w boju. Przedstawiano ją jako towarzyszkę lub małżonkę <a href=\"https://pl.wikipedia.org/wiki/Mars\" target=\"_blank\" rel=\"noopener noreferrer\">Marsa</a>, czasami utożsamiając z <a href=\"https://pl.wikipedia.org/wiki/Bellona_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Belloną</a> lub rzadziej <a href=\"https://pl.wikipedia.org/wiki/Minerwa\" target=\"_blank\" rel=\"noopener noreferrer\">Minerwą</a>.", "Nwachukwu": "<p>Nwachukwu jest bardzo powszechną nazwą Igbo. Oznacza to \"dziecko Boże\".</p>", "Nacim": "<p>Nassim (arabski: نسيم) również przetransliterowany jako Nacim, Naseem, Nasseem, Nasim, Nesim lub Nessim, jest unisex nazwisko oznaczające \"miękkie wiatr, świeży powietrze\". Jest używany głównie w kulturach i grupach językowych Bliskiego Wschodu i Azji Południowej.</p>", "Naval": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nawal</b>.</p><p>Nawal lub Nawaal (arabickie: نوال nawāl) to arabskie imię dla kobiet, które dosłownie oznacza \"niezasłużoną łaskę Boga\" lub \"dar, dotacja, prezent, darowiznę, nagrodę, ofiarę\" lub może również oznaczać \"statu lub jakość życzliwości, akt życzliwości poza tym, co należy\" lub \"łaska, dobroć, łaska, dobroczynność\". Nazwa jest w rzeczywistości nieskończoną formą przymiotnika, który pochodzi od czasownika naala, co oznacza \"do osiągnięcia, osiągnięcia , zarabiania, zdobycia, otrzymania w...</p>", "Ngọc Thanh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nazar-Vasyl": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nazar</b>.</p><b>Nazar</b>, zwany też <b>okiem <a href=\"https://pl.wikipedia.org/wiki/Fatima_(c%C3%B3rka_Mahometa)\" target=\"_blank\" rel=\"noopener noreferrer\">Fatimy</a></b> lub <b>okiem proroka</b> – <a href=\"https://pl.wikipedia.org/wiki/Amulet\" target=\"_blank\" rel=\"noopener noreferrer\">amulet</a> mający chronić przed „<a href=\"https://pl.wikipedia.org/wiki/Z%C5%82e_oko\" target=\"_blank\" rel=\"noopener noreferrer\">złym okiem</a>”. Nazwa nazar jest pochodzenia arabskiego i znaczy tyle co spojrzenie.", "Nathaniël": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nataniel</b>.</p><b>Natanael</b> (hebr. Bóg dał) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> hebrajskie, znaczeniowo przypomina takie imiona, jak greckie z pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a> czy polskie <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCydar_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bożydar</a>.", "Ngọc Thắng": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nadyr": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nadir</b>.</p><p>W astronomii niebo (Han: 天底, niebo, do = dna), w sposób nominalny, jest punktem (niewidocznym bezpośrednio okowi) nieba leżącym prosto pod stóp obserwatora. Dokładniej mówiąc, następujące definicje są równoważne: jest to punkt o wysokości -90 stopni.</p>", "Ngoc Linh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Noel Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Noel</b>.</p><p>Święto Bożego Narodzenia, czyli Boże Narodzenie, to święto upamiętniające narodziny Jezusa, które odbywa się głównie 25 grudnia każdego roku, jest świętem religijnym i kulturalnym dla miliardów ludzi na całym świecie. Jest celebratem centralnym pięciu lat chrześcijańskich, kończącym sezon świąteczny i rozpoczynającym sezon świąteczny, historycznie trwający w Zachodzie dwanaście dni do Dwunastej Nocy (noce przed Świątą Objawienia).</p>", "Nelly": "<p>Kornell Ayrel Haynes-młodszy (ang. Cornell Iral Haynes Jr. ; rodzaj.</p>", "Nykolai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nykola</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikola</b>.</p><b>Nikola</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, współcześnie sprowadzony do języka polskiego żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Miko%C5%82aj\" target=\"_blank\" rel=\"noopener noreferrer\">Mikołaj</a>. Pochodzi od greckich słów <i>Nikos</i> – <i>zwycięstwo</i> i <i>laos</i> oznaczającego <i>ludzie</i>. Wśród imion nadawanych nowo narodzonym dzieciom, Nikola w 2017 r. zajmowała 26. miejsce w grupie imion żeńskich, co oznacza spadek o 16 miejsc od 2009 r., kiedy to zajmowała 10. miejsce w analogicznej grupie. W całej populacji Polek Nikola zajmowała w 2017 r. 73. miejsce (66 007 nadań). Imię zyskało jeszcze na popularności. W styczniu 2025 r. w rejestrze <a href=\"https://pl.wikipedia.org/wiki/PESEL\" target=\"_blank\" rel=\"noopener noreferrer\">PESEL</a>, wśród publicznie dostępnych danych dotyczących osób żyjących, wykazano 78429 kobiet o imieniu Nikola nadanym jako imię pierwsze.", "Nevan": "<b>Naomhán</b> – irlandzkie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie złożone ze słów <i>naomh</i> - \"święty\" oraz <i>àn</i> - zdrabniającego przyrostka. Imię to oznacza więc \"małego świętego\" - tym mianem określano też pomniejszych świętych w irlandzkim folklorze.", "Nam Phương": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nam</b>.</p><p>W wietnamskim, Nam lub mascul jest słowem do wskazania: Mężczyzna: płci męskiej ludzi, w przeciwieństwie do \"żwomen\" jest płcią (żwomen) najniższej rangi szlachty feitów: Namcowiec kierunek: Słowo-Jużny zakres południowej dzielnicy kolonii miasteczkowej, prowincji Ho Nam, China: Słowe dzielnicy okręgów (khu) o nazwie Nam, patrz Naim (distrikty). W słowach \"wstrzymanie\" wskazują kierunek: męskie leki...</p>", "Nykita": "<p>Nikita (rosyjski: Ники́та [njɪˈkjitə]) jest powszechną nazwą męską w Europie Wschodniej i Grecji. Rosyjski wariant pochodził z greckiego nazwiska, a następnie z rosyjskiego.</p>", "Neli": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nel</b>.</p><b>Nela</b> – imię żeńskie, powstałe jako usamodzielnione zdrobnienie imion z zakończeniem -<i>nela</i> lub podobnym, takich jak na przykład <a href=\"https://pl.wikipedia.org/wiki/Kornelia\" target=\"_blank\" rel=\"noopener noreferrer\">Kornelia</a> lub <a href=\"https://pl.wikipedia.org/wiki/Petronela\" target=\"_blank\" rel=\"noopener noreferrer\">Petronela</a>.", "Nill": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nil</b>.</p><b>Nilus</b>, <b>Nil</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego, od gr. <i>neilos</i> – \"rzeka\". Istnieli liczni święci o tym imieniu.", "Ngoc Ninh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nattawut": "<p>Nattawut lub Natthawut to męskie tajskie imię. Znani ludzie z nazwiskiem to: Nattawut Somkhun, Muay Thai boxer Nattawut Poonpiriya, tajalski reżyser Nattawut Saikua, tajalski polityk Nattawut Suksum, tajalski piłkarz Nattawut Sombatyotha, tajalski fotbalista Nattawut Jaroenboot, tajalski futbalista Nattawaut Saengsri, tajalski piesbalista Nattauut Munsuwan, tajalski futbolista Nuttawut Khamrin, tajalski Piłkarz Natttawut Madyalan, tajalski futsal...</p>", "Ngoc Thang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngoc Huy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngọc Trung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nguyen Tuan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nguyen</b>.</p>Nazwisko pochodzi z <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">Chin</a>, gdzie jest pisane 阮 i wymawiane <i>Ruǎn</i> <a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#91;</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_z_retrofleksj%C4%85_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">ʐ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_p%C3%B3%C5%82otwarta_wargowo-mi%C4%99kkopodniebienna\" target=\"_blank\" rel=\"noopener noreferrer\">w</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">à</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#93;</a>.", "Ngoc Gia Bao": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngoc Cuong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nobuo": "<b>Nobuo</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;のぶお, ノブオ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Nijo": "Przed wstąpieniem na tron nosił imię książę Morihito&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;守仁親王&#32;<i>Morihito-shinnō</i>). Był pierwszym synem cesarza <a href=\"https://pl.wikipedia.org/wiki/Go-Shirakawa\" target=\"_blank\" rel=\"noopener noreferrer\">Go-Shirakawa</a> i ojcem cesarza <a href=\"https://pl.wikipedia.org/wiki/Rokuj%C5%8D\" target=\"_blank\" rel=\"noopener noreferrer\">Rokujō</a>.", "Nexhmedin": "<p>Nexhmedin lub Nedžmedin jest albaniańskie męskie imię. Znanymi osobami z nazwiska są: Nedžmedin Memedi (ur. 1966), albanianki piłkarz Nexhmedin Zajmi (1916-1991), albanianki malarz i rzeźbiarz</p>", "Ninoslav": "<p>Ninoslav to serbskie i chorwackie imię. Wśród znanych osób z tej nazwy są: Ninoslav Erić (ur. 1976), serbski polityk Ninoslav Krstić (1946-2012), serbski i jugosławski generał Ninoslav Milenković (ur., 1977), bosniak Ninoslav Pavelić (ur.1973), chorwacki trener handbalowy Ninoslav Pavić, chorwacki magun mediów Ninoslav Parmaković (r. 1982), chorwackie piłkarz Ninoslav Radovanović (or. 1940), serbski chirurg serca...</p>", "Nguyen Khang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nguyen</b>.</p>Nazwisko pochodzi z <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">Chin</a>, gdzie jest pisane 阮 i wymawiane <i>Ruǎn</i> <a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#91;</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_z_retrofleksj%C4%85_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">ʐ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_p%C3%B3%C5%82otwarta_wargowo-mi%C4%99kkopodniebienna\" target=\"_blank\" rel=\"noopener noreferrer\">w</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">à</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#93;</a>.", "Naeim": "<p>Naim (zwany również Na'im, Naïm, Nayeem, Naeem, Naiem, Nahim, Naheem, Nyhiem, Nihiem, Nyheim, Niheem, Nahiem lub Nyiem) (arabski: نعیم, hebrajski: נעים) jest męskie imię i nazwisko.</p>", "Naqibullah": "<p>Naqibullah może odnosić się do Naqeebullah Mehsud (1991-2018), pakistańskiego narodowego etnicznego pasztuna, który zginął w fałszywym spotkaniu z policją Mullah Naqib, zwany również Naqibullah (około 1950-2007), dowódca afgańskich mujahedynów i polityk Shahwali Shaheen Naqeebyllah, afgański uwięziony w Guantanamo (ISN 834) Naqibullah</p>", "Ngọc Trường": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nestor Fabian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nestor</b>.</p><b>Nestor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Istnieją liczni święci o tym imieniu.", "Narendran": "<p>Narendran może odnosić się do T. V.</p>", "Ni̇zam": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nizami</b>.</p><b>Nizami</b>, <b>Nezami Gandżawi</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">pers.</a>&#160;&#8207;نظامی گنجوی&#8206;, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_azerbejd%C5%BCa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">azer.</a>&#160;<em>Nizami Gəncəvi</em>, właśc. Nizām ad-Dīn Abū Muhammad Ilyās ibn-Yusūf ibn-Zakī ibn-Muˤayyid Nizāmī Ganjavī; ur. ok. <a href=\"https://pl.wikipedia.org/wiki/1141\" target=\"_blank\" rel=\"noopener noreferrer\">1141</a>, zm. ok. <a href=\"https://pl.wikipedia.org/wiki/1209\" target=\"_blank\" rel=\"noopener noreferrer\">1209</a>) – perski poeta pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Gand%C5%BCa\" target=\"_blank\" rel=\"noopener noreferrer\">Gandży</a> (dzisiejszy <a href=\"https://pl.wikipedia.org/wiki/Azerbejd%C5%BCan\" target=\"_blank\" rel=\"noopener noreferrer\">Azerbejdżan</a>), mieszkający przez całe życie w tym mieście i uważany za twórcę literatury perskiej.", "Nikolin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikolina</b>.</p><b>Nikolina</b> – imię żeńskie, powstałe poprzez zdrobnienie imienia <a href=\"https://pl.wikipedia.org/wiki/Nikola\" target=\"_blank\" rel=\"noopener noreferrer\">Nikola</a>, dokonane na gruncie języków romańskich.", "Nektariusz": "<b>Nektariusz</b> – imię greckie.", "Nelson Javier": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nelson</b>.</p><p>Edward William Nelson (ang. Edward William Nelson; 1855 - 1934) - amerykański badacz i etnolog.</p>", "Ngoc Sang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngoc Quang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngọc Thuận": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nene": "<p>Nene (寧寧 (Ninh Ninh) / ねね, Nene 1547 - 17 października 1624), lub zwykle nazywana Kōdai-in (高台院 (Kato Instytut) / こうだいいん, Kōdai-i), była szlachecką kobietą w okresie Sengoku i Edo w historii Japonii. Była znana z piękna, wysokiej mądrości i małżeństwa z Toyotomi Hideyoshi, najpotężniejszym mężczyzną w Japonii w tamtym czasie.</p>", "Natia": "<p>Natia (georgijska: ნათია) to kobiece gruzińskie imię, diminutiw Natela i ostatecznie pochodzi od słowa nateli (ნათელი), co oznacza \"światło, jasność\". Według Sal Służby Publicznej jest to jedna z 10 najczęstszych gruzińskich nazwisk dla kobiet.</p>", "Noga": "<p>Noga SA (anagrafa Gaon) - szwajcarska firma handlowa zajmująca się importem i eksportem w krajach Afryki, Europy Środkowej i Wschodniej, założona w 1957 roku i zarządzana w Genewie przez szwajcarszego miliarderka pochodzenia sudanskiego Nissima Gaona. Nazwa firmy została anagramem nazwy jej właściciela i kierownika Nissima Gaona.</p>", "Ngoc Luong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngọc Bích": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngoc Phuong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nava": "<p>NAVA (skróc. od Neurally Adjusted Ventilatory Assist) - neurokontrolująca wsparcie oddechowe (NAVA) - nowa metoda mechanicznej wentylacji płuc (sztuczna wentylacja płuc, skrócona jako IVL), oparta na fiksacji impulsy nerwowych odchodzących z centrum oddechowego mózgu przez nerw diafragmalny do diafragmy.</p>", "Nicholai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nichola</b>.</p><p>Nicola lub Nichola jest łacińską wersją greckiego imienia osobistego Nikolaos (Νικόλαος), pochodzącego z nikē oznaczającego \"wygrę\", a laos oznacza \"ludzie\", co oznacza \"wygrnięcia ludzi\". Nicola to zarówno imię męskie, jak i żeńskie, w zależności od norm kulturalnych.</p>", "Nestori": "<p>Nestori to nazwisko następujących osób: Nestori Aronen (1876-1954), fiński polityk Nestori Järvelä (1893-1951), fiński biegacz średniej odległości Nestori Kaasalainen (1915-2016), fiński polityka Nestori Karhula (1893-1971), fiński-australijczyk i porucznik Nestori Lähde (ur. 1989), fiński hokejista Nestori Nättinen (1857-1932), fiński politik Nestori Nurminen (1907-1977), fiński Nestori...</p>", "Ngọc Khánh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nihar": "<p>Nihar (w literce \" mgła, mgła, dewy\") może odnosić się do Nihar Ameen, indyjskiego trenerka pływania Nihar Mukherjee, indyjski polityk Nihar Ranjan Gupta, indyskiego dermatologa i pisarza Nihar Ranjana Laskar, indyjskich polityków Nihar Christison, filantrop i przedsiębiorcy z kremem biczem</p>", "Nazar-Mykola": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nazar</b>.</p><b>Nazar</b>, zwany też <b>okiem <a href=\"https://pl.wikipedia.org/wiki/Fatima_(c%C3%B3rka_Mahometa)\" target=\"_blank\" rel=\"noopener noreferrer\">Fatimy</a></b> lub <b>okiem proroka</b> – <a href=\"https://pl.wikipedia.org/wiki/Amulet\" target=\"_blank\" rel=\"noopener noreferrer\">amulet</a> mający chronić przed „<a href=\"https://pl.wikipedia.org/wiki/Z%C5%82e_oko\" target=\"_blank\" rel=\"noopener noreferrer\">złym okiem</a>”. Nazwa nazar jest pochodzenia arabskiego i znaczy tyle co spojrzenie.", "Nestor Andres": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nestor</b>.</p><b>Nestor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Istnieją liczni święci o tym imieniu.", "Ngoc Khanh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngoc Thien": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nat": "<b>Nat</b> (skr. od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a> <i>natural unit</i> „jednostka naturalna”; czasami także <b>nit</b> lub <b>nepit</b>, skr. od <i>Neper unit</i> – „jednostka <a href=\"https://pl.wikipedia.org/wiki/John_Napier\" target=\"_blank\" rel=\"noopener noreferrer\">Nepera</a>”) – <a href=\"https://pl.wikipedia.org/wiki/Logarytm\" target=\"_blank\" rel=\"noopener noreferrer\">logarytmiczna</a> <a href=\"https://pl.wikipedia.org/wiki/Jednostka_miary\" target=\"_blank\" rel=\"noopener noreferrer\">jednostka miary</a> <a href=\"https://pl.wikipedia.org/wiki/Ilo%C5%9B%C4%87_informacji\" target=\"_blank\" rel=\"noopener noreferrer\">ilości informacji</a>. 1 nat jest ilością <a href=\"https://pl.wikipedia.org/wiki/Informacja\" target=\"_blank\" rel=\"noopener noreferrer\">informacji</a> zawartą w <a href=\"https://pl.wikipedia.org/wiki/Komunikat\" target=\"_blank\" rel=\"noopener noreferrer\">wiadomości</a> o zajściu zdarzenia, którego <a href=\"https://pl.wikipedia.org/wiki/Prawdopodobie%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">prawdopodobieństwo</a> równe jest 1/<a href=\"https://pl.wikipedia.org/wiki/Podstawa_logarytmu_naturalnego\" target=\"_blank\" rel=\"noopener noreferrer\">e</a>. Ilość informacji wyraża się w postaci <a href=\"https://pl.wikipedia.org/wiki/Logarytm_naturalny\" target=\"_blank\" rel=\"noopener noreferrer\">logarytmu naturalnego</a> liczby możliwych wariantów zdarzenia.", "Namin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Namina</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nam</b>.</p><p>W wietnamskim, Nam lub mascul jest słowem do wskazania: Mężczyzna: płci męskiej ludzi, w przeciwieństwie do \"żwomen\" jest płcią (żwomen) najniższej rangi szlachty feitów: Namcowiec kierunek: Słowo-Jużny zakres południowej dzielnicy kolonii miasteczkowej, prowincji Ho Nam, China: Słowe dzielnicy okręgów (khu) o nazwie Nam, patrz Naim (distrikty). W słowach \"wstrzymanie\" wskazują kierunek: męskie leki...</p>", "Nawazish": "<p>Nawazish (persk: نوازش) to perskie imię oznaczające \"zdrowość\". Do wybitnych osób z nazwiskiem należą: Nawazish Muhammad Khan (zmarł w 1755 r.), były Naib Nazim z Dhaka Nawajesh Ahmed (1916-2000), bangladeski polityk Noazesh Ahmed (1935-2009), bangladeski genetycznik i fotograf Nawazesh Uddin (1945-1981), bałgajski oficer armii Nawazish Alam Khan (ur. 1979), indyjski polityk Nawazish Ali Khan, bangladeski producent telewizyjny Ali Moeen ...</p>", "Nicodim": "<p>Nicodim to rumuńskie imię męskie. Jest to wariant nazwiska Nikodemus.</p>", "Nitin Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nitin</b>.</p><p>Nitin lub Nithin (Devanagari: नितिन, नीतीन, lub नीतिन) to męskie imię w Indiach i Nepalu.</p>", "Nichifor": "<p>Nichifor, również Nechifor jest rumuńskim imieniem i nazwiskiem pochodzącym z greckiego imienia Nikephoros, (Νικηφόρος), \"Przywoźnik Zwycięstwa\". Wśród znanych osób z tej nazwy są: Nichifor Crainic, rumuński pisarz, redaktor, filozof, poeta i teolog Nichifor Tarara, rumuński sprint canoer Șerban Nichifor, rumuńczyk kompozytor, wiolonczelnik i pedagog muzyczny</p>", "Nilo Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nilo</b>.</p><p>Nilo jest samorządem w prowincji Cundinamarca w Kolumbii. Gmina Nilo jest stolicą terenu.</p>", "Nataniiel": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nataniel</b>.</p><b>Natanael</b> (hebr. Bóg dał) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> hebrajskie, znaczeniowo przypomina takie imiona, jak greckie z pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a> czy polskie <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCydar_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bożydar</a>.", "Nil Prasad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nil</b>.</p><b>Nilus</b>, <b>Nil</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego, od gr. <i>neilos</i> – \"rzeka\". Istnieli liczni święci o tym imieniu.", "Ngan": "<p>Łączniak lub łupiec węszywy to ogólne nazwy zwierzęcia z dwustronnym nazwiskiem Cairina moschata. W Wietnamie żółtki są nazywane żółtkami, żółtkiem, żółtymi, żółtaczami.</p>", "Ngoc Thuan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngoc Ha": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nazi": "<p>Nationalsozialistische Deutsche Arbeiterpartei (NSDAP), powszechnie nazywana w Wietnamie Partią Nazijną, była rządzącą partią w Niemczech w czasach nazistowskich pod kierownictwem Adolfa Hitlera, który został mianowany przez prezydenta Paula von Hindenburg premierem niemieckiego imperium. Po śmierci Hindenburga Hitler szybko ustanowił dyktaturę, zwaną III Imperium, w której Partia Narodowa...</p>", "Natiq": "<p>Natig, Natik lub Natiq (arabski: ناطق), to nazwisko i nazwisko pochodzenia arabskiego, które oznacza mówienie. Do wybitnych osób z tym nazwiskiem należą:</p>", "Nkululeko": "<p>Nkululeko (kobieta nonkululeko) to męskie imię pochodzące od słowa Nguni Inkululeko, co oznacza \"wolność/wolność\". Znani ludzie z nazwiska to: Nkululeko Gwala (-2013), aktywista z Południowej Afryki Nkululeko Hlophe, sędzia Liswati Nkululeko Serame (ur. 1987), kryketarka z Połedniowej Afriki Nkululeko Mkastos Sibanda (ur. 1979), Zimbabweński polityk</p>", "Navtej": "<p>Navtej to indyjskie imię męskie. Znani ludzie z nazwiskiem to: Navtej Bharati (ur. 1938), poeta kanadyjski z Punjabi Navtej Singh Cheema, indyjski polityk Navtej Hundal (1933-2019), aktor indyjski Navtej Johar (ur. 1959), indyjski choreograf Navtej Singh Rehal, indyjsko-danowski piosenkarz Navtej Sarna (ur. 1957), indyjski autor, kolumnista i dyplomat</p>", "Nguyên Khang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nguyen</b>.</p>Nazwisko pochodzi z <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">Chin</a>, gdzie jest pisane 阮 i wymawiane <i>Ruǎn</i> <a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#91;</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_z_retrofleksj%C4%85_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">ʐ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_p%C3%B3%C5%82otwarta_wargowo-mi%C4%99kkopodniebienna\" target=\"_blank\" rel=\"noopener noreferrer\">w</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">à</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#93;</a>.", "Ngọc Quý": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nyaz": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Niaz</b>.</p><p>Niaz, NIAZ, Niyas lub Neyaz mogą odnosić się do:</p>", "Nazariyi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nazariy</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nazariusz</b>.</p><b>Nazariusz</b>, <b>Nazary</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające \"pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Nazaret\" target=\"_blank\" rel=\"noopener noreferrer\">Nazaretu</a>\". Wśród patronów tego imienia, <a href=\"https://pl.wikipedia.org/wiki/Nazariusz_i_Celsus\" target=\"_blank\" rel=\"noopener noreferrer\">św. Nazariusz</a>, męczennik z I lub III wieku.", "Nayagam": "<p>Nayagam może odnosić się do: S. M.</p>", "Ngọc Thái": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngoc Thu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nasruddin": "<p>Nasir al-Din (arabski: نصیر الدین lub ناصرالدین lub نصر الدين, 'obrona wiary'), był pierwotnie tytułem honorowym i jest męskim nazwiskiem i nazwiskiem pochodzenia arabskiego. W języku angielskim istnieje wiele wariantów pisowni z powodu transliteracji, w tym Nasruddin i Nasiruddin.</p>", "Nguyen Khoi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nguyen</b>.</p>Nazwisko pochodzi z <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">Chin</a>, gdzie jest pisane 阮 i wymawiane <i>Ruǎn</i> <a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#91;</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_z_retrofleksj%C4%85_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">ʐ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_p%C3%B3%C5%82otwarta_wargowo-mi%C4%99kkopodniebienna\" target=\"_blank\" rel=\"noopener noreferrer\">w</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">à</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#93;</a>.", "Nelson Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nelson</b>.</p><p>Edward William Nelson (ang. Edward William Nelson; 1855 - 1934) - amerykański badacz i etnolog.</p>", "Ngoc Binh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nikolino": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikolin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikolina</b>.</p><b>Nikolina</b> – imię żeńskie, powstałe poprzez zdrobnienie imienia <a href=\"https://pl.wikipedia.org/wiki/Nikola\" target=\"_blank\" rel=\"noopener noreferrer\">Nikola</a>, dokonane na gruncie języków romańskich.", "Nebojsa": "<p>Nebojša to serbskie imię, co oznacza \"bez obaw\". Do osób z tym nazwiskiem należą:</p>", "Nam Long": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nam</b>.</p><p>W wietnamskim, Nam lub mascul jest słowem do wskazania: Mężczyzna: płci męskiej ludzi, w przeciwieństwie do \"żwomen\" jest płcią (żwomen) najniższej rangi szlachty feitów: Namcowiec kierunek: Słowo-Jużny zakres południowej dzielnicy kolonii miasteczkowej, prowincji Ho Nam, China: Słowe dzielnicy okręgów (khu) o nazwie Nam, patrz Naim (distrikty). W słowach \"wstrzymanie\" wskazują kierunek: męskie leki...</p>", "Ngọc Tĩnh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngọc Cương": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngoc Duc": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nitish Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nitish</b>.</p><p>Nitish to indyjskie imię męskie z sanskrytu oznaczające \"władca wytycznych\". Wśród znanych osób z nazwiskiem są: Nitish Beejan, maorycjanski polityk Nitish Bharadwaj, indyjski aktor Nitish Chavan (ur. 1990), indyjski aktor filmowy i telewizyjny z języka marathi Nitish Jain, indyjscy edukacyjny Nitish Katara, indyjskie dyrektor biznesowy zamordowany w 2002 roku Nitish Kumar, premier Bihar Nitish Kumer (kryketacz), kanadyjski kryketacz Nitish Chandra Laharry...</p>", "Noordin": "<p>Nur al-Din (arabski: نور الدين, romanized: nūr ad-dīn) to męskie arabskie imię, tłumaczące na \"światło wiary\", nūr oznacza \"świetło\" i dīn oznacza \"religię\". Ostatnio nazwa ta była używana również jako nazwisko.</p>", "Nubar": "<p>Nubar (Wschodni Armejski: Նուբար, Zachodni Armeński: Նուպար) to męskie imię. Pochodzi z perskiego Nobr (nowbar, \"nowo dojrzewany owoc, pierwszy owoc\"), składający się z نو (obecnie \"nowy\") i بر (bar, \"owoc\").</p>", "Naila": "<p>Naila jest miastem w niemieckim Bawaryjskim rządzie Hof.</p>", "Nicco": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nico</b>.</p><p>Nico (Nico, prawdziwe imię Christa Päffgen, niemiecki Christa Päck; 16 października 1938, Köln, Trzeci Reich - 18 lipca 1988, Ivis, Hiszpania) - niemiecka piosenkarka, kompozytorka, autorka piosenek, poetka, fotomodelka i aktorka.</p>", "Ngọc Lan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nelson Fernando": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nelson</b>.</p><p>Edward William Nelson (ang. Edward William Nelson; 1855 - 1934) - amerykański badacz i etnolog.</p>", "Ngoc Tan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngoc An": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nestor Ivan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nestor</b>.</p><b>Nestor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Istnieją liczni święci o tym imieniu.", "Nosson": "<p>Nosson (aszkenazyjska forma Nathana (hebrajski: נָתָן) może odnosić się do: Rabina Nosson Scherman, amerykańskiego rabina Haredi Orthodox Rabina Nossa Tzvi Finkel (Mir) (1943-2011), Rosh Yeshiva Mir Yeshiva w Beis Yisroel, Jerozolimy Rabina Nossona Tzvi Finkla (Slabodka) (1849-1927), przywódcy judaizmu prawosławnego w Europie Wschodniej Rabina Shlomo Nosson Kotler (1856-1920), rabina prawosławieńskiego, Rosh yeshiva i Talmudic uczony Rabina Nosso Slifkin, znany jako...</p>", "Narimon": "<p>Nariman (zwany również Narriman, Nareeman, Neriman, Nəriman) jest nazwą pochodzenia perskiego (perskiego: نریمان Narīmān). Jego korzenie pochodzą z perskiego epiku Shahnameh, napisanego przez Ferdowsi.</p>", "Ngoc Quy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nadeesha": "<p>Nadeesha (tamilsky: நதீஷா; sinhalasky: නදීෂා) to imiona pochodzenia kobiety z Sri Lanki. Znani ludzie z nazwiska to: Nadeesha Gayanthi (ur. 1984), Sri Lankanka badmintonista Nadeesha Dilhani Lekamge (ur. 1987), Sri Lanka rzucacz włóczni Nadeesha Ramanayake (ur. 1994), Sri Lankowa atletka torbów i pola Nadeesha Uyangoda (ur. 1993), Sri Lanki-italijczyk, pisarz, autor i podcast.</p>", "Ngoc Lam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngoc Lan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngọc Khương": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngọc Quang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nadbor": "<b>Nadbor</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Nad-</i> (\"nad\" lub człon pochodzący od innych wyrazów) i <i>-bor</i> („walczyć, zmagać się”). Być może oznaczało „tego, kto najlepiej walczy”.", "Ngoc Hao": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nandi": "<p>Nandi Awards to najwyższa nagroda za wyróżnienie się w dziedzinie kina, teatru, telewizji i żywotnego wkładu w indyjskie kino, przyznawana corocznie przez rząd stanu Andhra Pradesh. Nazwa Nandi, co oznacza ⁇ byk ⁇ , otrzymała nagrodę w cześć wielkiego byka granitowego w Lepaksi - kulturalnego i historycznego symbolu narodu telugu.</p>", "Ngọc Phong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Naranbhai": "<p>Narandbhai może odnosić się do Narandbhay Kachhadia, indyjski polityk Narandbhayi Keshavlal Parikh, indyjskiego polityka Narandbhaya Rathwa, indyjska polityka</p>", "Ngoc Que": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nari": "<p>W północnej mityce Nafri, znany również jako Nari, był synem Loki i Sigyn. Nafri został zabity, by ukarać Loki za grzechy, które popełnił.</p>", "Nikołoz": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikolozi</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikoloz</b>.</p><b>Nikoloz</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_gruzi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">gruz.</a> ნიკოლოზი) – <a href=\"https://pl.wikipedia.org/wiki/Gruzja\" target=\"_blank\" rel=\"noopener noreferrer\">gruzińskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Miko%C5%82aj\" target=\"_blank\" rel=\"noopener noreferrer\">Mikołaj</a>.", "Nila": "<b>Nila</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia greckiego, od gr. <i>neilos</i> - \"rzeka\". Forma żeńska imienia <a href=\"https://pl.wikipedia.org/wiki/Nilus\" target=\"_blank\" rel=\"noopener noreferrer\">Nilus</a>.", "Nano": "<b>Nano</b> (<b>n</b>) (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr</a>. νάνος, <i>nanos</i> – „karzeł”) – <a href=\"https://pl.wikipedia.org/wiki/Przedrostek_SI\" target=\"_blank\" rel=\"noopener noreferrer\">przedrostek jednostki miary</a> oznaczający mnożnik 0,000&#160;000&#160;001 = 10 (jedna miliardowa).", "Ngai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nga</b>.</p><b>Nga</b> (ڠ) – litera rozszerzonego <a href=\"https://pl.wikipedia.org/wiki/Alfabet_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu arabskiego</a>. Wykorzystywana jest w <a href=\"https://pl.wikipedia.org/wiki/Pismo_jawi\" target=\"_blank\" rel=\"noopener noreferrer\">piśmie jawi</a>, na którym oparty jest jeden z alfabetów języka <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_malajski\" target=\"_blank\" rel=\"noopener noreferrer\">malajskiego</a>. Używana jest do oznaczenia dźwięku [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_tylnoj%C4%99zykowo-mi%C4%99kkopodniebienna_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">ŋ</a>], tj. <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_tylnoj%C4%99zykowo-mi%C4%99kkopodniebienna_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">spółgłoski nosowej tylnojęzykowo-miękkopodniebiennej dźwięcznej</a>.", "Nam Duong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nam</b>.</p><p>W wietnamskim, Nam lub mascul jest słowem do wskazania: Mężczyzna: płci męskiej ludzi, w przeciwieństwie do \"żwomen\" jest płcią (żwomen) najniższej rangi szlachty feitów: Namcowiec kierunek: Słowo-Jużny zakres południowej dzielnicy kolonii miasteczkowej, prowincji Ho Nam, China: Słowe dzielnicy okręgów (khu) o nazwie Nam, patrz Naim (distrikty). W słowach \"wstrzymanie\" wskazują kierunek: męskie leki...</p>", "Nazli": "<p>Nazlı to powszechne kobiece turskie imię. To znaczy \"słodkie\" lub \"miłosierdzie\" w tureckim.</p>", "Navai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nava</b>.</p><p>NAVA (skróc. od Neurally Adjusted Ventilatory Assist) - neurokontrolująca wsparcie oddechowe (NAVA) - nowa metoda mechanicznej wentylacji płuc (sztuczna wentylacja płuc, skrócona jako IVL), oparta na fiksacji impulsy nerwowych odchodzących z centrum oddechowego mózgu przez nerw diafragmalny do diafragmy.</p>", "Nikodém": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikodema</b>.</p><b>Nikodema</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Nikodem\" target=\"_blank\" rel=\"noopener noreferrer\">Nikodem</a>, które jest złożone z wyrazów <i>níkē</i> (gr. „zwycięstwo”) i <i>dēmos</i> (gr. „lud”). Imię <b>Nikodema</b> nadawane jest w Polsce co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1846\" target=\"_blank\" rel=\"noopener noreferrer\">1846</a> roku, zaś w rodzinach polskich poza ziemiami rdzennie polskimi co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1793\" target=\"_blank\" rel=\"noopener noreferrer\">1793</a> roku.", "Ngọc Bảo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nelson De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nelson</b>.</p><p>Edward William Nelson (ang. Edward William Nelson; 1855 - 1934) - amerykański badacz i etnolog.</p>", "Ngoc Thieu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Noemi": "<b>Noemi</b> (hebr. Naomi, נָעֳמִי) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się od hebrajskiego słowa oznaczającego „moja słodycz”.", "Ngoc Lanh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nelson Alexander": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nelson</b>.</p><p>Edward William Nelson (ang. Edward William Nelson; 1855 - 1934) - amerykański badacz i etnolog.</p>", "Nematullah": "<p>Nimatullah, również pisane Ni'matullāh, Nematollah itp. (arabijski: نعمة الله) to arabskie imię męskie.</p>", "Ngoc Thinh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngọc Tài": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nelson Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nelson</b>.</p><p>Edward William Nelson (ang. Edward William Nelson; 1855 - 1934) - amerykański badacz i etnolog.</p>", "Ngoc Vuong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngọc Thùy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Niyi": "<p>Niyi to męskie imię. Niyi oznacza \"honor, prestiż, sławę\"Wśród osób znanych z tego nazwiska są: Niyi Adebayo (ur. 1958), nigerijski polityk i prawnik Niyi Adeolokun (ur. 1990), irlandzki gracz rugby Niyi Akinmolayan (ur. 1982), nigeriński filmowiec, reżyser i konsultant mediów Niyi Makanjuola (ur. 1980), nigerianin Niyi Ogunlana (ur. 1984), nigerianski piłkarz Niyi Ojuolape (ur. 1970), nigeriany dyplomat Niyi...</p>", "Nittai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nitai</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nita</b>.</p><p>Nita elsaff jest pająkiem z rodziny Pholcidae. Rośliny te występują w Egipcie i Uzbekistanie.</p>", "Nelson Rafael": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nelson</b>.</p><p>Edward William Nelson (ang. Edward William Nelson; 1855 - 1934) - amerykański badacz i etnolog.</p>", "Nazarii-Mykhailo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nazarii</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nazariusz</b>.</p><b>Nazariusz</b>, <b>Nazary</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające \"pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Nazaret\" target=\"_blank\" rel=\"noopener noreferrer\">Nazaretu</a>\". Wśród patronów tego imienia, <a href=\"https://pl.wikipedia.org/wiki/Nazariusz_i_Celsus\" target=\"_blank\" rel=\"noopener noreferrer\">św. Nazariusz</a>, męczennik z I lub III wieku.", "Nadeesh": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nadeesha</b>.</p><p>Nadeesha (tamilsky: நதீஷா; sinhalasky: නදීෂා) to imiona pochodzenia kobiety z Sri Lanki. Znani ludzie z nazwiska to: Nadeesha Gayanthi (ur. 1984), Sri Lankanka badmintonista Nadeesha Dilhani Lekamge (ur. 1987), Sri Lanka rzucacz włóczni Nadeesha Ramanayake (ur. 1994), Sri Lankowa atletka torbów i pola Nadeesha Uyangoda (ur. 1993), Sri Lanki-italijczyk, pisarz, autor i podcast.</p>", "Nasif": "<p>Nassif (zwany również Naseef, Nassef lub Nasiff, arabski: ناصيف) jest arabskim męskim imieniem i nazwiskiem pochodzącym z Wschodniego Morza Śródziemnego, głównie z Libanu i Syrii, pochodzącym od arabskiego słowa nasif oznaczającego sprawiedliwy lub uczciwy.</p>", "Nazar-Ivan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nazar</b>.</p><b>Nazar</b>, zwany też <b>okiem <a href=\"https://pl.wikipedia.org/wiki/Fatima_(c%C3%B3rka_Mahometa)\" target=\"_blank\" rel=\"noopener noreferrer\">Fatimy</a></b> lub <b>okiem proroka</b> – <a href=\"https://pl.wikipedia.org/wiki/Amulet\" target=\"_blank\" rel=\"noopener noreferrer\">amulet</a> mający chronić przed „<a href=\"https://pl.wikipedia.org/wiki/Z%C5%82e_oko\" target=\"_blank\" rel=\"noopener noreferrer\">złym okiem</a>”. Nazwa nazar jest pochodzenia arabskiego i znaczy tyle co spojrzenie.", "Nagaraja": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nagaraj</b>.</p><p>Nagaraj, Nagaraj lub Nagaraja lub Nagarajan to indyjskie imię i nazwisko mężczyzn. Pochodzi z sanskrytu: nagराज nagaraja \"król nagów\".</p>", "Netta": "<p>Nirka (lat. Netta) - rodzaj ptaków pływających wodą rodziny ugotów.</p>", "Nił": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nyl</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nil</b>.</p><b>Nilus</b>, <b>Nil</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego, od gr. <i>neilos</i> – \"rzeka\". Istnieli liczni święci o tym imieniu.", "Nela": "<b>Nela</b> – imię żeńskie, powstałe jako usamodzielnione zdrobnienie imion z zakończeniem -<i>nela</i> lub podobnym, takich jak na przykład <a href=\"https://pl.wikipedia.org/wiki/Kornelia\" target=\"_blank\" rel=\"noopener noreferrer\">Kornelia</a> lub <a href=\"https://pl.wikipedia.org/wiki/Petronela\" target=\"_blank\" rel=\"noopener noreferrer\">Petronela</a>.", "Ngoc Han": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nadin Ricardo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nadin</b>.</p><p>⁇ Nadin ⁇ - pierwsza w Rosji fryzjerka, której stan składa się z głuchych i słuchalnych ludzi. Otwarto w 2012 roku w Moskwie.</p>", "Nomar": "<p>Nomar to męskie imię i nazwisko. Wśród znanych osób z tym nazwiskiem są: Nomar Garciaparra (ur. 1973), amerykański gracz baseballu i analityk sportowy Nomar Angeles Isla (ur. 1970), filipiński trener koszykówki Nomar Mazara (ur. 1995), dominikanin Ramón Nomar (ur. 1974), wenezuelski aktor porno hiszpański.</p>", "Nun": "<b>Nun</b> – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_egipska\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii egipskiej</a> pramateria, pierwszy materialny przejaw bytu, Nun jest przede wszystkim żywiołem kosmicznym. Jest on stworzeniem morza, na którym unosi się ziemia. Prawdopodobnie Nun był najpierw personifikowany w <a href=\"https://pl.wikipedia.org/wiki/Hermopolis\" target=\"_blank\" rel=\"noopener noreferrer\">Hermopolis</a> jako bóstwo męskie. Niekiedy, jako jedno z bóstw Ósemki, miewał głowę żaby. Jako najstarszy z bogów, pochodzący jeszcze z czasów chaosu, nosił przydomki \"stary\" i <i>ojciec czasów</i>. Jako personifikacja wód kosmicznych miał za atrybut głowę byka.", "Ngoc Hieu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngọc Huy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nithin Raj": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nithin</b>.</p><p>Nitin Kumar Reddy (ang. Nithin Kumar Reddy, teлугу niitin kumar reddy, bardziej znany pod mononimem Nitin; rod.</p>", "Nilanka": "<p>Nilanka to imię. Znani ludzie z nazwiskiem to: Nilanka Premaratne (ur. 1988), Sri Lankanka Kryketkarz Nilanka Rukshitha (ur. 1998), Sri Lanka Kryketer Nilanka Sandakan (ur. 1996), Sri Lanki Kryketarka</p>", "Nesanel": "<p>Natanael (grecki: Ναθαναήλ, hebrajsky: נְתַנְאֵל, romanized: natan'el, lit. 'dany przez Boga') jest angielską nazwą pochodzącą z hebrajskiego.</p>", "Nazar-Dmytro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nazar</b>.</p><b>Nazar</b>, zwany też <b>okiem <a href=\"https://pl.wikipedia.org/wiki/Fatima_(c%C3%B3rka_Mahometa)\" target=\"_blank\" rel=\"noopener noreferrer\">Fatimy</a></b> lub <b>okiem proroka</b> – <a href=\"https://pl.wikipedia.org/wiki/Amulet\" target=\"_blank\" rel=\"noopener noreferrer\">amulet</a> mający chronić przed „<a href=\"https://pl.wikipedia.org/wiki/Z%C5%82e_oko\" target=\"_blank\" rel=\"noopener noreferrer\">złym okiem</a>”. Nazwa nazar jest pochodzenia arabskiego i znaczy tyle co spojrzenie.", "Neyaz": "<p>Niaz, NIAZ, Niyas lub Neyaz mogą odnosić się do:</p>", "Nanda Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nanda</b>.</p><p>Nanda (ang. Nanda, marathi Nanda, 8 stycznia 1939 - 25 marca 2014) - indyjska aktorka.</p>", "Ni̇zami̇": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nizam</b>.</p><p>Nizam (arabski: نظام / niẓām; tamilski: நிசாம்) jest tytułem rządów Państwa Hyderabad i innych półautonomicznych państw w Indianie. Pod czasami Mogałskich Imperium, to był tytuł wojskowy, przypisany przez cesarzy Mogałów do zarządzania półautonomicznymi terytoriami, a później Nizamy coraz bardziej uzyskały władzę i tytuł dziedziczony w formie ojca przekazu, podobny do urzędu ostatecznego Południa.</p>", "Noriaki": "<b>Noriaki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;のりあき, ノリアキ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Nélio": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Neli</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nel</b>.</p><b>Nela</b> – imię żeńskie, powstałe jako usamodzielnione zdrobnienie imion z zakończeniem -<i>nela</i> lub podobnym, takich jak na przykład <a href=\"https://pl.wikipedia.org/wiki/Kornelia\" target=\"_blank\" rel=\"noopener noreferrer\">Kornelia</a> lub <a href=\"https://pl.wikipedia.org/wiki/Petronela\" target=\"_blank\" rel=\"noopener noreferrer\">Petronela</a>.", "Nourddine": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nourdine</b>.</p><p>Nur al-Din (arabski: نور الدين, romanized: nūr ad-dīn) to męskie arabskie imię, tłumaczące na \"światło wiary\", nūr oznacza \"świetło\" i dīn oznacza \"religię\". Ostatnio nazwa ta była używana również jako nazwisko.</p>", "Nazar-Marko": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nazar</b>.</p><b>Nazar</b>, zwany też <b>okiem <a href=\"https://pl.wikipedia.org/wiki/Fatima_(c%C3%B3rka_Mahometa)\" target=\"_blank\" rel=\"noopener noreferrer\">Fatimy</a></b> lub <b>okiem proroka</b> – <a href=\"https://pl.wikipedia.org/wiki/Amulet\" target=\"_blank\" rel=\"noopener noreferrer\">amulet</a> mający chronić przed „<a href=\"https://pl.wikipedia.org/wiki/Z%C5%82e_oko\" target=\"_blank\" rel=\"noopener noreferrer\">złym okiem</a>”. Nazwa nazar jest pochodzenia arabskiego i znaczy tyle co spojrzenie.", "Ngọc Sang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Niklot": "Od jego syna, <a href=\"https://pl.wikipedia.org/wiki/Przybys%C5%82aw_(ksi%C4%85%C5%BC%C4%99_meklemburski)\" target=\"_blank\" rel=\"noopener noreferrer\">Przybysława</a> (<i>Pribislav</i>), wywodzi się <a href=\"https://pl.wikipedia.org/wiki/Dynastia_meklemburska\" target=\"_blank\" rel=\"noopener noreferrer\">dynastia książęca</a> panująca w <a href=\"https://pl.wikipedia.org/wiki/Niemcy\" target=\"_blank\" rel=\"noopener noreferrer\">niemieckiej</a> <a href=\"https://pl.wikipedia.org/wiki/Meklemburgia\" target=\"_blank\" rel=\"noopener noreferrer\">Meklemburgii</a> do 1918 roku.", "Nestor Jr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nestor</b>.</p><b>Nestor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Istnieją liczni święci o tym imieniu.", "Nang": "<b>Nang</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_tajski\" target=\"_blank\" rel=\"noopener noreferrer\">język tajski</a>: หนัง) – tajski <a href=\"https://pl.wikipedia.org/wiki/Teatr_cieni\" target=\"_blank\" rel=\"noopener noreferrer\">teatr cieni</a>, oparty na lokalnej wersji <a href=\"https://pl.wikipedia.org/wiki/Ramajana\" target=\"_blank\" rel=\"noopener noreferrer\">Ramajany</a>. Do przedstawień wykorzystuje się specjalnie wykrojone skóry bawole. Przedstawieniu towarzyszy akompaniament muzyczny. Najstarsza zachowana wzmianka o tej formie sztuki pochodzi z XV w. Istnieją dwie regionalne odmiany: <i>nang yai</i> (zachodnia) oraz <i>nang talung</i> (południowa).", "Nawal": "<p>Nawal lub Nawaal (arabickie: نوال nawāl) to arabskie imię dla kobiet, które dosłownie oznacza \"niezasłużoną łaskę Boga\" lub \"dar, dotacja, prezent, darowiznę, nagrodę, ofiarę\" lub może również oznaczać \"statu lub jakość życzliwości, akt życzliwości poza tym, co należy\" lub \"łaska, dobroć, łaska, dobroczynność\". Nazwa jest w rzeczywistości nieskończoną formą przymiotnika, który pochodzi od czasownika naala, co oznacza \"do osiągnięcia, osiągnięcia , zarabiania, zdobycia, otrzymania w...</p>", "Niecisław": "<b>Niecisław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie nienotowane w źródłach staropolskich, prawdopodobnie <a href=\"https://pl.wikipedia.org/wiki/Neologizm\" target=\"_blank\" rel=\"noopener noreferrer\">neologizm</a> z początku <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX</a> wieku. Złożone z członu \"Nieci-\" (\"wzniecać, wzbudzać\"), który jest niespotykany w staropolskich imionach dwuczłonowych, oraz członu \"-sław\" (\"sława\").", "Nicolaos": "<p>Nikolaos (grek. Νικόλαος, Nikólaos) jest powszechną grecką nazwą, która oznacza \"wygrywający lud\", związany z νίκη nikē \"wygrę\" i λαός laos \"ludzie\". Konotatywa jest \"champion ludzi\" lub \"wygrywający ludzi\".</p>", "Nicolino": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikolino</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikolin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikolina</b>.</p><b>Nikolina</b> – imię żeńskie, powstałe poprzez zdrobnienie imienia <a href=\"https://pl.wikipedia.org/wiki/Nikola\" target=\"_blank\" rel=\"noopener noreferrer\">Nikola</a>, dokonane na gruncie języków romańskich.", "Nato": "<p>⁇ Nató ⁇ , ⁇ n.A.T.o. ⁇ (prawdziwe imię - Natalia Shevlakova; urodzona 3 października 1979, Tbilisi, Gruzja SSR) - rosyjska piosenkarka, występowała pod pseudonimem.</p>", "Ngọc Khôi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nestor Raul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nestor</b>.</p><b>Nestor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Istnieją liczni święci o tym imieniu.", "Ngọc Thiên": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nicu-Adrian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nicu</b>.</p><p>Nicu jest zarówno męskim rumuńskim nazwiskiem, jak i rumuńskie nazwisko. Znani ludzie z nazwiska obejmują: Nicu Ceaușescu (1951-1996), rumuński komunista Nicu Constantin (1938-2009), rumuński aktor Nicu Constantinescu (1840-1905), rumuński polityk Nicu Covaci (ur. 1947), rumuński malarz i muzyk Nicu Paleru (ur. 1973), rumuńskiego cyganka muzyka Nicu Porsena (ur. Ionescu) (1892-1971), rumuńczyka pisarz Nicu Stoian (ur. 1957),...</p>", "Namika": "<b>Namika</b>, właśc. <b>Hanan Hamdi</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/7_wrze%C5%9Bnia\" target=\"_blank\" rel=\"noopener noreferrer\">7 września</a> <a href=\"https://pl.wikipedia.org/wiki/1991\" target=\"_blank\" rel=\"noopener noreferrer\">1991</a> we <a href=\"https://pl.wikipedia.org/wiki/Frankfurt_nad_Menem\" target=\"_blank\" rel=\"noopener noreferrer\">Frankfurcie nad Menem</a>) – <a href=\"https://pl.wikipedia.org/wiki/Niemcy\" target=\"_blank\" rel=\"noopener noreferrer\">niemiecka</a> <a href=\"https://pl.wikipedia.org/wiki/Piosenkarz\" target=\"_blank\" rel=\"noopener noreferrer\">piosenkarka</a> <a href=\"https://pl.wikipedia.org/wiki/Maroko\" target=\"_blank\" rel=\"noopener noreferrer\">marokańskiego</a> pochodzenia.", "Norbert Charles": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Norbert</b>.</p><b>Norbert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">starogermańskiego</a>. Wywodzi się od słów <i>nord</i> – tj. północ i <i>beraht</i> – czyli błyszczeć, jaśnieć. Całość znaczy więc „ten, który dokonuje wielkich czynów na północy”, „sławny mąż z północy”.", "Nikša": "<p>Nikša (cyrylicki: Никша) to męskie imię, bosniacko-chorwackie i serbskie odmianie Nikola (przybliżone do Nicolasa). Do wybitnych osób z tym nazwiskiem należą: Nikša Bratoš (ur. 1959), bosnianki muzyczny, który zdobył sławę w byłej Jugosławii, członek zespołów Valentino i Crvena jabuka Nikša Dobud (ur. 1985), chorwacki gracz w wodopalo Nikša Gligo (1946-2024), chorwański muzyka i profesor uniwersytecki Nikša Gradić lub Nikola Gradić / Nicoló...</p>", "Nurddin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nurdin</b>.</p><p>Nur al-Din (arabski: نور الدين, romanized: nūr ad-dīn) to męskie arabskie imię, tłumaczące na \"światło wiary\", nūr oznacza \"świetło\" i dīn oznacza \"religię\". Ostatnio nazwa ta była używana również jako nazwisko.</p>", "Nelson Eduardo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nelson</b>.</p><p>Edward William Nelson (ang. Edward William Nelson; 1855 - 1934) - amerykański badacz i etnolog.</p>", "Nguyen Anh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nguyen</b>.</p>Nazwisko pochodzi z <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">Chin</a>, gdzie jest pisane 阮 i wymawiane <i>Ruǎn</i> <a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#91;</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_z_retrofleksj%C4%85_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">ʐ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_p%C3%B3%C5%82otwarta_wargowo-mi%C4%99kkopodniebienna\" target=\"_blank\" rel=\"noopener noreferrer\">w</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">à</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#93;</a>.", "Nollan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nolan</b>.</p><p>Nolan (Nolan) - irlandzkie nazwisko i toponim.</p>", "Neth": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Netha</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Neta</b>.</p><p>Hozon Auto (cz. Wręcz przeciwnie.</p>", "Ngoc Quan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nguyên Khoa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nguyen</b>.</p>Nazwisko pochodzi z <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">Chin</a>, gdzie jest pisane 阮 i wymawiane <i>Ruǎn</i> <a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#91;</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_z_retrofleksj%C4%85_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">ʐ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_p%C3%B3%C5%82otwarta_wargowo-mi%C4%99kkopodniebienna\" target=\"_blank\" rel=\"noopener noreferrer\">w</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">à</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#93;</a>.", "Ngọc Phương": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nazar-Volodymyr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nazar</b>.</p><b>Nazar</b>, zwany też <b>okiem <a href=\"https://pl.wikipedia.org/wiki/Fatima_(c%C3%B3rka_Mahometa)\" target=\"_blank\" rel=\"noopener noreferrer\">Fatimy</a></b> lub <b>okiem proroka</b> – <a href=\"https://pl.wikipedia.org/wiki/Amulet\" target=\"_blank\" rel=\"noopener noreferrer\">amulet</a> mający chronić przed „<a href=\"https://pl.wikipedia.org/wiki/Z%C5%82e_oko\" target=\"_blank\" rel=\"noopener noreferrer\">złym okiem</a>”. Nazwa nazar jest pochodzenia arabskiego i znaczy tyle co spojrzenie.", "Nissanka": "<p>Nissanka to imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Ngoc Hoa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Niky": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Niki</b>.</p><p>Niki - firma lotnicza z siedzibą w Wiedniu, Austria. Służiała regularnymi lotami do Europy i Egiptu z Wiednia, Salzburg, Friedrichshafen na zamówienie turoperatora Neckermann Reisen.</p>", "Nehoray": "<p>Nehorai (przekładane również jako Nehoray, Neoray, neorai) jest męskie hebrajskie imię נְהוֹרַאי, z aramejskiego נְהוּר nehor lub נְהֹרָא nehora oznaczające \"światło\". Nazwa ta pojawia się trzy razy w Miśnie.</p>", "Nam Chol": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nam</b>.</p><p>W wietnamskim, Nam lub mascul jest słowem do wskazania: Mężczyzna: płci męskiej ludzi, w przeciwieństwie do \"żwomen\" jest płcią (żwomen) najniższej rangi szlachty feitów: Namcowiec kierunek: Słowo-Jużny zakres południowej dzielnicy kolonii miasteczkowej, prowincji Ho Nam, China: Słowe dzielnicy okręgów (khu) o nazwie Nam, patrz Naim (distrikty). W słowach \"wstrzymanie\" wskazują kierunek: męskie leki...</p>", "Ngọc Vinh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nam Thang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nam</b>.</p><p>W wietnamskim, Nam lub mascul jest słowem do wskazania: Mężczyzna: płci męskiej ludzi, w przeciwieństwie do \"żwomen\" jest płcią (żwomen) najniższej rangi szlachty feitów: Namcowiec kierunek: Słowo-Jużny zakres południowej dzielnicy kolonii miasteczkowej, prowincji Ho Nam, China: Słowe dzielnicy okręgów (khu) o nazwie Nam, patrz Naim (distrikty). W słowach \"wstrzymanie\" wskazują kierunek: męskie leki...</p>", "Nemi": "Miejsce, w którym leży miejscowość, uznawane było za święte już w <a href=\"https://pl.wikipedia.org/wiki/Epoka_br%C4%85zu\" target=\"_blank\" rel=\"noopener noreferrer\">epoce brązu</a>. Jego nazwa pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> słowa <i>nemus</i>, oznaczającego \"święty gaj\" i wiąże się z faktem, iż w <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">starożytności</a> rosnący tu las był jednym z najbardziej znanych miejsc kultu bogini <a href=\"https://pl.wikipedia.org/wiki/Diana_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Diany</a> i głównym sanktuarium <a href=\"https://pl.wikipedia.org/wiki/Zwi%C4%85zek_Laty%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Ligi Latyńskiej</a>. Szczególnym poważaniem otoczył to miejsce cesarz <a href=\"https://pl.wikipedia.org/wiki/Kaligula\" target=\"_blank\" rel=\"noopener noreferrer\">Kaligula</a>, który rozkazał odnowić istniejącą tu starą świątynię, a na jeziorze Nemi zbudować dwa wielkie <a href=\"https://pl.wikipedia.org/wiki/Statki_z_jeziora_Nemi\" target=\"_blank\" rel=\"noopener noreferrer\">statki</a>, pełniące funkcje kultowe.", "Ngoc Sam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngọc Ðại": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nattan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Natan</b>.</p><b>Natan</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> נָתָן, <i>dar, podarunek</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> hebrajskie. Imieniu Natan etymologicznie bliskie są imiona <a href=\"https://pl.wikipedia.org/wiki/Natanael\" target=\"_blank\" rel=\"noopener noreferrer\">Natanael</a> (<a href=\"https://pl.wikipedia.org/wiki/Natanael\" target=\"_blank\" rel=\"noopener noreferrer\">Nataniel</a>). <b>Natan</b> <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/12_lipca\" target=\"_blank\" rel=\"noopener noreferrer\">12 lipca</a> oraz <a href=\"https://pl.wikipedia.org/wiki/25_grudnia\" target=\"_blank\" rel=\"noopener noreferrer\">25 grudnia</a>.", "Ninos": "Imię Semiramida nadal jest popularne na obszarze Bliskiego Wschodu.", "Nuruddin": "<p>Nur al-Din (arabski: نور الدين, romanized: nūr ad-dīn) to męskie arabskie imię, tłumaczące na \"światło wiary\", nūr oznacza \"świetło\" i dīn oznacza \"religię\". Ostatnio nazwa ta była używana również jako nazwisko.</p>", "Nguyen Cuong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nguyen</b>.</p>Nazwisko pochodzi z <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">Chin</a>, gdzie jest pisane 阮 i wymawiane <i>Ruǎn</i> <a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#91;</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_z_retrofleksj%C4%85_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">ʐ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_p%C3%B3%C5%82otwarta_wargowo-mi%C4%99kkopodniebienna\" target=\"_blank\" rel=\"noopener noreferrer\">w</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">à</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#93;</a>.", "Nam Jin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nam</b>.</p><p>W wietnamskim, Nam lub mascul jest słowem do wskazania: Mężczyzna: płci męskiej ludzi, w przeciwieństwie do \"żwomen\" jest płcią (żwomen) najniższej rangi szlachty feitów: Namcowiec kierunek: Słowo-Jużny zakres południowej dzielnicy kolonii miasteczkowej, prowincji Ho Nam, China: Słowe dzielnicy okręgów (khu) o nazwie Nam, patrz Naim (distrikty). W słowach \"wstrzymanie\" wskazują kierunek: męskie leki...</p>", "Nicolo '": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nicolo</b>.</p><p>Nicolò (w włoskim: [nikoˈlɔ]) to włoskie imię męskie. Kolejna wariantka to Niccolò, najczęstsza w Toskanii.</p>", "Nadmir": "<b>Nadmir</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Nad-</i> („nad” lub człon pochodzący od innych wyrazów) i <i>-mir</i> („pokój, spokój, dobro”). Być może oznaczało „tego, kto przynosi prawdziwy pokój”.", "N": "<b>N</b> (<i>en</i>, <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>n</b>) – czternasta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a> i osiemnasta <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskiego</a>. Oznacza zwykle w danym języku <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">spółgłoskę przedniojęzykową nosową</a>, np. [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a>].", "Nezhdet": "<p>Nejdet to tureckie męskie imię. Do wybitnych osób z nazwiskiem należą: Nejdet Atalay (ur. 1978), turecki polityk Nejdet Sançar (1910-1975), turecki nauczyciel literatury Nejdet Zalev (ur. 1937), bułgarski wrestler olimpijski</p>", "Naftaly": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Naftali</b>.</p><b>Neftali</b>, <b>Naftali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> נפתלי) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Etymologię tego imienia (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <i>moja walka</i>, <i>wywalczony</i>) wywodzi się z <i><a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Rodzaju</a></i> 30,8.", "Najm": "<p>Najm (arabsko: نجم) lub Najam to arabskie słowo oznaczające Gwiazdę. Najm to bezpośrednie imię koraniczne dla chłopców i dziewcząt, które oznacza \"gwiazdę\", \"światło\", \"od źródło inspiracji\".</p>", "Nathane": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nathan</b>.</p><p>Nathan Allan de Souza (ur. 13 marca 1996), znany jako Nathan, jest brazylijskim piłkarzem, który gra za Atlético Mineiro, wypożyczonym z English Premier League Chelsea. grając w strzelaninie, może grać także jako lewicowy lub w stronę.</p>", "Nomi": "<p>Nomi jest miastem w prowincji Trento w włoskiej regionie Trentino-Alto Adige/Südtirol, 15 km na południe od Trento. Na dzień 31 grudnia 2004 roku mieście miało 1.298 mieszkańców i obszar 6.5 km2.</p>", "Ngọc An": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nepali": "Język nepalski jest <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_urz%C4%99dowy\" target=\"_blank\" rel=\"noopener noreferrer\">językiem urzędowym</a> w Nepalu. Zapisuje się go w alfabecie <a href=\"https://pl.wikipedia.org/wiki/Pismo_dewanagari\" target=\"_blank\" rel=\"noopener noreferrer\">dewanagari</a>; najstarsze zabytki piśmiennictwa w nepali pochodzą z XIV wieku.", "Nurlani": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nurlan</b>.</p><p>Nurlan (kazachski: Нұрлан) to turkijska męska nazwa, która jest powszechna w Azerbejdżanie, Kazachstanie i Uzbekistanie. Nazwa jest w istocie połączeniem arabskiego słowa Noor (także śpiewany jako \"Nur\") oznaczającego światło, promienie lub blask oraz tureckiego słowa \"Lan/Ulan\", który oznacza lwa w większości języków tureckich.</p>", "Nic": "<p>Nic to imię, prawie zawsze męskie, często skrótowane od Nicholas, Nicolas lub ich wariantów. Jest również elementem irlandzkiego nazwiska kobiet.</p>", "Ngoc Duong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngoc Châu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nami": "<p>Nami (jap. ナミ, Nami [na̠mji]), znany również jako \"Piraty\" Nami, jest postacią fikcyjną w serii One Piece stworzonym przez Oda Eiichiro. Jest ona oparta na Ann i Silk - dwóch postaciach z starego manga Romance Dawn od Oda.</p>", "Nestor Eduardo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nestor</b>.</p><b>Nestor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Istnieją liczni święci o tym imieniu.", "Natasza": "<b>Natalia</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em><a href=\"https://pl.wikipedia.org/wiki/Dies_natalis\" target=\"_blank\" rel=\"noopener noreferrer\">Dies natalis</a> Domini</em>, tj. <i>w dniu urodzin <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Pana</a></i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie wywodzące się od męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Natal_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Natalis</a>. W Polsce to imię jest poświadczane w formie Natalia w XIV wieku. Dawniej nadawane osobom urodzonym w dniach chrześcijańskich świąt <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCe_Narodzenie\" target=\"_blank\" rel=\"noopener noreferrer\">Bożego Narodzenia</a>. Patronką imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Adrian_i_Natalia_z_Nikomedii\" target=\"_blank\" rel=\"noopener noreferrer\">Natalia z Nikomedii</a>, męczennica.", "Natallia": "<p>Natallia to kobiece imię, wariant nazwy Natalia.</p>", "Nataliya": "<p>Natalia (ukraina: Наталія, rosyjska: Наталия) jest ukraińską i rosyjską formą nazwiska Natalia. Książka jest ukraińska: Наталка, romanizowana: Natalka (patrz: Natalka Poltavka), a po rosyjsku: Наташа, romanized: Natasha.</p>", "Nadzieja": "<b>Nadzieja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, nawiązujące do jednej z trzech <a href=\"https://pl.wikipedia.org/wiki/Cnoty_teologalne\" target=\"_blank\" rel=\"noopener noreferrer\">cnót teologalnych</a>. <i>Nadia</i> jest zdrobnieniem od rosyjskiej wersji tego imienia – Nadieżdy. Wśród imion nadawanych nowo narodzonym dzieciom, Nadia w 2009 zajmowała 22. miejsce w grupie imion żeńskich.", "Nelia": "<p>Nelia (lat. Nelia) - rodzaj sukkulatów rodziny Aizoaceae, podrodzinnego rodu Ruschioideae, rosnący na terytorium prowincji Kapskiej Republiki Południowej Afryki.</p>", "Natalie": "<p>Natalie (jap. ナタリー Natari:) - japońska strona internetowa poświęcona wiadomościom z branży rozrywkowej.</p>", "Naomi": "<p>Trynity Lachon Fatu (ang. Trinity LaShawn Fatu, urodziny.</p>", "Nadiya": "<b>Nâdiya</b> (właściwie <b>Nadia Zighem</b>, ur. <a href=\"https://pl.wikipedia.org/wiki/19_czerwca\" target=\"_blank\" rel=\"noopener noreferrer\">19 czerwca</a> <a href=\"https://pl.wikipedia.org/wiki/1973\" target=\"_blank\" rel=\"noopener noreferrer\">1973</a>) – <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">francuska</a> piosenkarka pochodzenia algiersko-włoskiego, wykonuje muzykę <a href=\"https://pl.wikipedia.org/wiki/Muzyka_pop\" target=\"_blank\" rel=\"noopener noreferrer\">pop</a> i <a href=\"https://pl.wikipedia.org/wiki/Rhythm_and_blues\" target=\"_blank\" rel=\"noopener noreferrer\">R&amp;B</a>. W młodości uprawiała zawodowo <a href=\"https://pl.wikipedia.org/wiki/Lekkoatletyka\" target=\"_blank\" rel=\"noopener noreferrer\">lekkoatletykę</a> – była mistrzynią Francji juniorek w <a href=\"https://pl.wikipedia.org/wiki/Bieg_na_800_metr%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">biegu na 800 metrów</a>.", "Nadzeya": "<p>Nadeżda lub Nadeżta (czyli w cyrylskich: Надежда) to słowiańskie imię kobiety popularne w Białorusi, Bułgarii, Macedonii Północnej, Rosji, Serbii, Ukrainie i innych słowiańskich krajach w mniejszym stopniu, a także w innych dawnych państwach sowieckich, takich jak Azerbejdżan i Uzbekistan. Pochodzenie nazwy w staroślawskim słowiańskim oznaczało \"oczekiwanie\", ale znaczenie to zachowało się tylko w bułgarskim, makedonii i rosyjskim.</p>", "Nathalie": "<p>Nie należy mylić z piosenką ⁇ Nathalie ⁇ wykonanej przez Julio Iglesias z jego 1982 roku albumu ⁇ Momentos ⁇ .  ⁇ Nathalie ⁇ (Natali) - piosenka francuskiego piosenkarza Gilberra Beco.</p>", "Nella": "<b>Nela</b> – imię żeńskie, powstałe jako usamodzielnione zdrobnienie imion z zakończeniem -<i>nela</i> lub podobnym, takich jak na przykład <a href=\"https://pl.wikipedia.org/wiki/Kornelia\" target=\"_blank\" rel=\"noopener noreferrer\">Kornelia</a> lub <a href=\"https://pl.wikipedia.org/wiki/Petronela\" target=\"_blank\" rel=\"noopener noreferrer\">Petronela</a>.", "Nell": "<p>Nell - wielomiennik: Nell - zmniejszające się nazwisko Eleanor. Nell - film z 1994 roku.</p>", "Narcyza": "<b>Narcyza</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Jest żeńskim odpowiednikiem męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Narcyz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Narcyz</a>.", "Natalya": "<p>Natalya (rosyjski: Наталья) to rosyjskie imię Natalii.</p>", "Nikolina": "<b>Nikolina</b> – imię żeńskie, powstałe poprzez zdrobnienie imienia <a href=\"https://pl.wikipedia.org/wiki/Nikola\" target=\"_blank\" rel=\"noopener noreferrer\">Nikola</a>, dokonane na gruncie języków romańskich.", "Nikoleta": "<b>Nikoleta</b>, <b>Nikoletta</b> – imię żeńskie pochodzenia włoskiego. Powstało od imienia <a href=\"https://pl.wikipedia.org/wiki/Nikola\" target=\"_blank\" rel=\"noopener noreferrer\">Nikola</a>, gdyż we <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włoszech</a> i <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">Francji</a> <i>Nicola</i>, <i>Nicolai</i> jest imieniem męskim, a jako żeński odpowiednik powstała <i>Nicolette</i>, <i>Nicoletta</i> ze względu na popularne we Włoszech końcówki imion <i>-etta</i>. Od Nikolety powstało imię <a href=\"https://pl.wikipedia.org/wiki/Koleta\" target=\"_blank\" rel=\"noopener noreferrer\">Koleta</a>, które jednak posiada w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> o wiele dłuższą tradycję niż Nikoleta.", "Nastia": "<p>Nastja jest nazwiskiem używanym w krajach Europy Wschodniej. Jest to drobna forma greckiej nazwy Anastasia.</p>", "Neonila": "<b>Nunilona</b>, <b>Nunila</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Jego patronką jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ta_Nunilona\" target=\"_blank\" rel=\"noopener noreferrer\">święta Nunilona</a>. Formą tego imienia, spotykaną w krajach wschodniosłowiańskich, jest <i>Neonila</i> lub <i>Neonilla</i>.", "Noelia": "<b>Natalia</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em><a href=\"https://pl.wikipedia.org/wiki/Dies_natalis\" target=\"_blank\" rel=\"noopener noreferrer\">Dies natalis</a> Domini</em>, tj. <i>w dniu urodzin <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Pana</a></i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie wywodzące się od męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Natal_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Natalis</a>. W Polsce to imię jest poświadczane w formie Natalia w XIV wieku. Dawniej nadawane osobom urodzonym w dniach chrześcijańskich świąt <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCe_Narodzenie\" target=\"_blank\" rel=\"noopener noreferrer\">Bożego Narodzenia</a>. Patronką imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Adrian_i_Natalia_z_Nikomedii\" target=\"_blank\" rel=\"noopener noreferrer\">Natalia z Nikomedii</a>, męczennica.", "Nastazja": "<b>Nastazja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Pochodzi z języka greckiego, w którym oznacza osobę <a href=\"https://pl.wikipedia.org/wiki/Zmartwychwstanie\" target=\"_blank\" rel=\"noopener noreferrer\">zmartwychwstałą</a>, wskrzeszoną. W Polsce imię nadawane jest od XII wieku. Forma&#160;<i>Nastazja</i> jest w polszczyźnie rzadka, jednak, jak informują źródła, wystąpiła w dokumentach polskich już ok. roku 1265 (jako:&#160;<i>Nastazyja</i>).", "Nora": "<b>Eleonora</b> – imię żeńskie nieustalonego pochodzenia; być może <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> (może od <i>el</i> – „Bóg” oraz <i>or</i> – „światło”; czyli „Bóg mi światłem”), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> lub <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (od <i>eleo</i> – „lituję się”).", "Nancy": "<p>Nancy (francuski Nancy [nɑ̃.si]; historyczny.</p>", "Nadja": "<p>Nadja to duet Edyna Baker i Lii Bacaréff. Grupa została założona w 2002 roku jako solowy projekt Baker.</p>", "Nonna": "<b>Nonna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „dziewiąta” (dziewiąte dziecko w rodzinie) (analogicznie do <a href=\"https://pl.wikipedia.org/wiki/Oktawia\" target=\"_blank\" rel=\"noopener noreferrer\">Oktawia</a> – „ósma”). Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Nonna_z_Nazjanzu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Nonna</a>, matka św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Grzegorz_z_Nazjanzu\" target=\"_blank\" rel=\"noopener noreferrer\">Grzegorza z Nazjanzu</a>.", "Nicoleta": "<p>Nicoleta to rumuńskie imię żeńskie pochodzące od greckiego Nikolaos. Wśród znanych osób z tej nazwy są: Nicoleta Alexandru, piosenkarka reprezentująca Rumunię na konkursie piosenki Eurovision Song Contest 2003 Nicoleta Grasu, rumuńska dyskowerka Nicoleta Onel, rumuńskiej gimnastki Nicoleta Daniela Șofronie, artystyczna gimnastka</p>", "Narine": "<p>Narine to zarówno kobiece imię pochodzenia armenijskiego, jak i nazwisko, które może pochodzić z Indian. Mieszkańcy tej nazwy to:</p>", "Nawojka": "Prawdziwe imię tej studentki nie jest znane. Nie wymienia go jedyne źródło historyczne, którym jest autobiograficzne dzieło <i>Senatorium sive dialogus historicus</i> współczesnego jej Marcina ze Spisza&#65279;<a href=\"https://www.wikidata.org/wiki/Q1231085#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a>. Upowszechnione imię Nawojka wynikało z błędnego domniemania polskiego historyka literatury, który w drugiej połowie XIX w. mylnie wiązał średniowieczną studentkę z autorką XVI-wiecznego „<a href=\"https://pl.wikipedia.org/wiki/Modlitewnik_Nawojki\" target=\"_blank\" rel=\"noopener noreferrer\">Modlitewnika Nawojki</a>”. Domniemane imię przylgnęło do postaci najwcześniejszej studentki i weszło na stałe do legend Krakowa i Uniwersytetu Jagiellońskiego.", "Ni": "<p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Naama": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nama</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nam</b>.</p><p>W wietnamskim, Nam lub mascul jest słowem do wskazania: Mężczyzna: płci męskiej ludzi, w przeciwieństwie do \"żwomen\" jest płcią (żwomen) najniższej rangi szlachty feitów: Namcowiec kierunek: Słowo-Jużny zakres południowej dzielnicy kolonii miasteczkowej, prowincji Ho Nam, China: Słowe dzielnicy okręgów (khu) o nazwie Nam, patrz Naim (distrikty). W słowach \"wstrzymanie\" wskazują kierunek: męskie leki...</p>", "Natalka": "<p>Natalia (ukraina: Наталія, rosyjska: Наталия) jest ukraińską i rosyjską formą nazwiska Natalia. Książka jest ukraińska: Наталка, romanizowana: Natalka (patrz: Natalka Poltavka), a po rosyjsku: Наташа, romanized: Natasha.</p>", "Nelya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nelia</b>.</p><p>Nelia (lat. Nelia) - rodzaj sukkulatów rodziny Aizoaceae, podrodzinnego rodu Ruschioideae, rosnący na terytorium prowincji Kapskiej Republiki Południowej Afryki.</p>", "Nataly": "<p>Nataly to nazwisko dla kobiet, wariant nazwiska Natalie (zdanie).</p>", "Neha": "<p>Neha (Hindi i sanskryt: नेहा; wymowa hindi: [neː.ɦɑː]) jest popularną hinduską / sanskrytską imieniem indyjskiego, często występującym w społeczności hinduskich. Oznacza to \"miłość\" / \"poczucie\", \"płódź\" / \"płod\", a czasami tłumaczana jest jako \"piękne oczy\".</p>", "Natela": "<p>Natela lub Natella (georgijski: ნათელა; cyrylski: Нателла) to gruzińskie imię żeńskie, pochodzące od słowa nateli (ნათელი), co oznacza \"światło, jasność\". Według Sal Służby Publicznej jest to jedna z dziesięciu najczęstszych gruzińskich nazwisk dla kobiet.</p>", "Nadya": "<p>Nadya to kobiece imię, czasami krótka forma (hipokoryzm) Nadezhdy lub innych nazw. Nadya jest używana głównie w całym regionie Morza Śródziemnego, Europie Wschodniej, Ameryce Łacińskiej, Kaukazie i świecie arabskim.</p>", "Nargiz": "<p>Nargiz Polatyna Zakirova (z. Nargiz Po'latovna Zokirova; rod.</p>", "Nada": "<p>Nada (ita. Nada), prawdziwe imię ─ Nada Malańim (ita.</p>", "Nicolle": "<p>Nicolle to kobiece imię i nazwisko.</p>", "Nicolette": "<b>Nicolette</b>, właściwie <b>Nicolette Love Suwoton</b> (ur. 1964 w <a href=\"https://pl.wikipedia.org/wiki/Glasgow\" target=\"_blank\" rel=\"noopener noreferrer\">Glasgow</a>) – szkocka piosenkarka, kompozytorka i DJ-ka <a href=\"https://pl.wikipedia.org/wiki/Nigeria\" target=\"_blank\" rel=\"noopener noreferrer\">nigeryjskiego</a> pochodzenia, wykonawczyni muzyki elektronicznej z kręgu <a href=\"https://pl.wikipedia.org/wiki/Ambient_techno\" target=\"_blank\" rel=\"noopener noreferrer\">ambient techno</a>, <a href=\"https://pl.wikipedia.org/wiki/Techno\" target=\"_blank\" rel=\"noopener noreferrer\">techno</a> i <a href=\"https://pl.wikipedia.org/wiki/Trip_hop\" target=\"_blank\" rel=\"noopener noreferrer\">trip hop</a>. Nagrała trzy albumy studyjne i jeden DJ mix.", "Nathalia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Natalia</b>.</p><b>Natalia</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em><a href=\"https://pl.wikipedia.org/wiki/Dies_natalis\" target=\"_blank\" rel=\"noopener noreferrer\">Dies natalis</a> Domini</em>, tj. <i>w dniu urodzin <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Pana</a></i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie wywodzące się od męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Natal_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Natalis</a>. W Polsce to imię jest poświadczane w formie Natalia w XIV wieku. Dawniej nadawane osobom urodzonym w dniach chrześcijańskich świąt <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCe_Narodzenie\" target=\"_blank\" rel=\"noopener noreferrer\">Bożego Narodzenia</a>. Patronką imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Adrian_i_Natalia_z_Nikomedii\" target=\"_blank\" rel=\"noopener noreferrer\">Natalia z Nikomedii</a>, męczennica.", "Nadina": "<p>Nadina (lat. Nadina) - rodzaj bezczelnych turbellariów, jedyny w rodzinie Nadinidae. W rodzaj wchodzą trzy gatunki.</p>", "Norma": "<b>Norma</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie stworzone przez <a href=\"https://pl.wikipedia.org/wiki/Felice_Romani\" target=\"_blank\" rel=\"noopener noreferrer\">Felice Romaniego</a>, <a href=\"https://pl.wikipedia.org/wiki/Libretto\" target=\"_blank\" rel=\"noopener noreferrer\">librecistę</a> <i><a href=\"https://pl.wikipedia.org/wiki/Norma_(opera)\" target=\"_blank\" rel=\"noopener noreferrer\">Normy</a></i> <a href=\"https://pl.wikipedia.org/wiki/Vincenzo_Bellini\" target=\"_blank\" rel=\"noopener noreferrer\">Belliniego</a>, dla tytułowej bohaterki tej opery, prawdopodobnie w związku z <a href=\"https://pl.wikipedia.org/wiki/Norma\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskim znaczeniem tego słowa</a> – reguła, zasada. Stosowane także jako żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Norman_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Norman</a>.", "Nellie": "<p>Chanel Mary Stires (ang. Shanele Marie Stires; urodzona 21 maja 1972 roku w okręgu Claude, stan Kansas, USA) - amerykańska profesjonalna basketballistka, występująca w kobiecej krajowej stowarzyszeniach koszykówki.</p>", "Nia": "<p>Nia jest grzybkiem z rodziny Niaceae. W tym zestawie znajdują się trzy gatunki, które są dostosowane do środowiska morskiego.</p>", "Nadin": "<p>⁇ Nadin ⁇ - pierwsza w Rosji fryzjerka, której stan składa się z głuchych i słuchalnych ludzi. Otwarto w 2012 roku w Moskwie.</p>", "Nga": "<b>Nga</b> (ڠ) – litera rozszerzonego <a href=\"https://pl.wikipedia.org/wiki/Alfabet_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu arabskiego</a>. Wykorzystywana jest w <a href=\"https://pl.wikipedia.org/wiki/Pismo_jawi\" target=\"_blank\" rel=\"noopener noreferrer\">piśmie jawi</a>, na którym oparty jest jeden z alfabetów języka <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_malajski\" target=\"_blank\" rel=\"noopener noreferrer\">malajskiego</a>. Używana jest do oznaczenia dźwięku [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_tylnoj%C4%99zykowo-mi%C4%99kkopodniebienna_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">ŋ</a>], tj. <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_tylnoj%C4%99zykowo-mi%C4%99kkopodniebienna_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">spółgłoski nosowej tylnojęzykowo-miękkopodniebiennej dźwięcznej</a>.", "Ni Kadek": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Niamh": "<b>Niamh</b>, inaczej <b>Niam Złotowłosa</b> – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_celtycka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii celtyckiej</a> była córką <a href=\"https://pl.wikipedia.org/wiki/Manannan\" target=\"_blank\" rel=\"noopener noreferrer\">Manannan mac Lira</a> i królowej <a href=\"https://pl.wikipedia.org/wiki/T%C3%ADr_na_n%C3%93g\" target=\"_blank\" rel=\"noopener noreferrer\">Tír na nÓg</a>. Jej imię oznacza \"Piękna\".", "Natalja": "<b>Natalia</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em><a href=\"https://pl.wikipedia.org/wiki/Dies_natalis\" target=\"_blank\" rel=\"noopener noreferrer\">Dies natalis</a> Domini</em>, tj. <i>w dniu urodzin <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Pana</a></i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie wywodzące się od męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Natal_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Natalis</a>. W Polsce to imię jest poświadczane w formie Natalia w XIV wieku. Dawniej nadawane osobom urodzonym w dniach chrześcijańskich świąt <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCe_Narodzenie\" target=\"_blank\" rel=\"noopener noreferrer\">Bożego Narodzenia</a>. Patronką imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Adrian_i_Natalia_z_Nikomedii\" target=\"_blank\" rel=\"noopener noreferrer\">Natalia z Nikomedii</a>, męczennica.", "Nefeli": "<p>Nephele jest boginią chmur w greckiej mityce. Nephele lub Nefeli może być: Nephele, ptaszką 431 Nephele, asteroidą \"Nephele\", piosenka Animals as Leaders z 2014 roku The Joy of Motion Nefeli Chatziioannidou, greckiego polityka Nefeli Mousoura, greckiej pianisty Nefeli Papadakis (ur. 1998), amerykańskiej bokserkiej judoka</p>", "Nazira": "<p>Nazira jest miastem i miejscem położenia urzędu (municipal board) w hrabstwie Sibsagar w stanie Assam, India.</p>", "Ni Luh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Nili": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nil</b>.</p><b>Nilus</b>, <b>Nil</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego, od gr. <i>neilos</i> – \"rzeka\". Istnieli liczni święci o tym imieniu.", "Ni Wayan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Nikodema": "<b>Nikodema</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Nikodem\" target=\"_blank\" rel=\"noopener noreferrer\">Nikodem</a>, które jest złożone z wyrazów <i>níkē</i> (gr. „zwycięstwo”) i <i>dēmos</i> (gr. „lud”). Imię <b>Nikodema</b> nadawane jest w Polsce co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1846\" target=\"_blank\" rel=\"noopener noreferrer\">1846</a> roku, zaś w rodzinach polskich poza ziemiami rdzennie polskimi co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1793\" target=\"_blank\" rel=\"noopener noreferrer\">1793</a> roku.", "Nisa": "<p>Nisa jest dzielnicą portugalskiej prowincji Portalegre. Ogromnie liczy się 575 km2, a w 2001 roku liczba ludności wynosiła 8585 mieszkańców.</p>", "Ni Komang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Nawoja": "<b>Nawoja</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Nawoj\" target=\"_blank\" rel=\"noopener noreferrer\">Nawoj</a>. \"Na\" posiada liczne znaczenia, m.in. nazywające kogoś, ze względu na kogo dzieje się jakaś akcja&#8201;. W źródłach polskich poświadczone od XV wieku (1411 rok).", "Norberta": "<b>Norberta</b> – żeński odpowiednik starogermańskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Norbert\" target=\"_blank\" rel=\"noopener noreferrer\">Norbert</a>.", "Nailia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Naili</b>.</p><p>Naili (arabski: نائلی) to arabskie pochodzenie męskie nazwisko i nazwisko. Nazwa jest używana w Turcji z tym samym znaczeniem jak Nail: \"odniosły, podbiły\". Jest to wariant Naila przyłączony z tureckim oskarżającym markerem przypadku -i.</p>", "Nikandra": "<b>Nikandra</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Grecy\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, złożone z członów <i>Nike</i> - (\"zwycięstwo\") i <i>andros</i> - (\"lud\"). Odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Nikander_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Nikander</a>.", "Noela": "<p>Noela to kobiece imię. To wariant Noela.</p>", "Ni Putu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Na": "<p>Natrium (chemiczny symbol - Na, od łacińskiego Natrium) - element chemiczny 1 grupy (po przestarzałej klasyfikacji - główną podgrupa pierwszej grupy, IA), trzeciego okresu okresowego systemu elementów chemicznych D.</p>", "Natella": "<p>Natela lub Natella (georgijski: ნათელა; cyrylski: Нателла) to gruzińskie imię żeńskie, pochodzące od słowa nateli (ნათელი), co oznacza \"światło, jasność\". Według Sal Służby Publicznej jest to jedna z dziesięciu najczęstszych gruzińskich nazwisk dla kobiet.</p>", "Neila": "<p>Neila jest miastem w prowincji Burgos, Kastilia i Leon, Hiszpania. Według przeprowadzonego w 2004 roku popytu (INE) mieście miało 235 mieszkańców.</p>", "Ni Made": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Nicolla": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikolla</b>.</p><p>Nikolla (nieokreślona forma Nikollë) jest albaniańska pierwotna nazwa i nazwisko pochodzące od greckiego Nikolaos (Νικόλαος). Często używają go chrześcijanie albańscy.</p>", "Noémi": "<p>Noémie (Noemie, Noemi, Noémi) to imię kobiety pochodzące z hebrajskiego języka, pochodzące od hebrajskiego \"Naomi\", co oznacza łaskawe, piękne lub piękne. Niezwykłe wersje pisowni francuskiej obejmują Noëmie (tylko wymowa).</p>", "Ni Ketut": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Nita": "<p>Nita elsaff jest pająkiem z rodziny Pholcidae. Rośliny te występują w Egipcie i Uzbekistanie.</p>", "Nathaly": "<p>Natalie to kobiece imię pochodzące od łacińskiego wyrazu natale domini, co oznacza \"narodziny Pana\". Kolejne alternatywne pisowni nazwy obejmują Nathalie, Natalee i Natalia/Natalija.</p>", "Nneka": "<p>Włóczko (ang. Nneka, pełne imię Nneca Egbana (ang.</p>", "Ni Nyoman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Neringa": "<p>Neringa - miasto i kurort na Kęśku, między Morzem Bałtyckim a Zatokiem Kęśkim w Litwie.</p>", "Nutsa": "<p>Nutsa to gruzińskie imię kobiece, pierwotnie diminutiw Nino. Do osób z tym nazwiskiem należą: Nutsa Buzaladze (ur. 1997), znana również jako Nutsa, gruzińska piosenkarka i autorka utworów Nutsa Chkheidze (1881-1963), gruzińska i sowiecka aktorka Nutsa Gogoberidze (1903-1966), gruziński i radziecki reżyser filmowy Nutsa Kukhianidze (ur. 1983), gruzijska aktorka</p>", "Noemie": "<p>Noémie (Noemie, Noemi, Noémi) to imię kobiety pochodzące z hebrajskiego języka, pochodzące od hebrajskiego \"Naomi\", co oznacza łaskawe, piękne lub piękne. Niezwykłe wersje pisowni francuskiej obejmują Noëmie (tylko wymowa).</p>", "Nevena": "<p>Nevena (kirylicki: Невена) to kobiece imię popularne w językach sławskich południowych. Nazwa jest kobiecością męskiego imienia Neven, co oznacza \"kalendulę oficinalną\".</p>", "Naja": "<p>Prawdziwe kobra, lub kobra, czy też węże oczkowe (lat. Naja), to rodzaj toksycznych węże z rodziny aspydów.</p>", "Nijola": "<p>Nijolė to litewska żeńska nazwa. Jest to jedno z licznych pseudomythologicznych nazw wynalezionych w XIX wieku przez litewskiego pisarza Teodora Narbutta dla litewskiej mitologii pogańskiej (w jego książce nazwa została podana w języku polskim stylu \"Nijola\").</p>", "Noura": "<p>Fatima Zohra Badji (1942 - 2014) (arabski: فاطمة الزهراء باجي) znana pod nazwiskiem Noura (arabsko: نورة) była algerijską piosenkarką. Była piosenkarką z północnej Afryki i pierwszą algierską piosenkarkę, która zdobyła złoty certyfikat i była pierwszą algejerką, która pojawiła się na pierwszej stronie gazety Paris Match.</p>", "Nena": "Przydomek „Nena” nadały jej hiszpańskie dzieci, z którymi w młodości spędziła wakacje w <a href=\"https://pl.wikipedia.org/wiki/Alicante\" target=\"_blank\" rel=\"noopener noreferrer\">Alicante</a> i które nie znały jej imienia, dlatego wołały do niej „niña” (dziewczynka).", "Nida": "<p>Nida (lit. Nida, do niego.</p>", "Nubia": "<p>Nubia (nobiin: Nobīn, arabski: النُوبَة, latynikowany: an-Nūba) jest regionem wzdłuż rzeki Nilu, znajdującym się w północnym Sudanie i południowym Egipcie. Było wiele wielkich nobijskich królestw w okresie postklasycznym, a ostatnie upadło w 1504 roku, kiedy Nubia została podzielona między Egiptem i sultanatem Sennar, co stworzyło arabskie przypisanie większości mieszkańców Nubie. Nubia została następnie złączona z Egiptem w 19 wieku w Sudanie, który był władzem Anglii i Egiptu od 1899 do...</p>", "Nargis": "<p>Nargis - czasopismo o modzie i sztuce, wydane od 2012 roku w Azerbejdżanie przez dom wydawniczy ⁇ Nargis ⁇ . Czasopismo jest publikowane w formie drukowanym w języku angielskim i ma wersję elektroniczną na trzech językach: rosyjskim, azerbajdżajskim i angielskim.</p>", "Nechama": "<p>Nechama lub Nehama (Hebrajskie: נחמה) to hebrajskie imię żeńskie, co dosłownie oznacza \"pocieszenie\". Znani ludzie z nazwy to: Nechama Hendel (1936-1998), izraelska piosenkarka Nechama Leibowitz (1905-19977), izraelska biblika Nechama Lifshitz (1927-2017), język jidish i później hebrajskiego soprano i artystyczna utwór wykonawczy Nechama Rivlin (1945-2019), izraelski badacz, sekretarz nauki i pierwsza dama Izraela Nehama Ronen ...</p>", "Natalí": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nataly</b>.</p><p>Nataly to nazwisko dla kobiet, wariant nazwiska Natalie (zdanie).</p>", "Noriko": "<b>Noriko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;のりこ, ノリコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Ni̇l": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nyl</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nil</b>.</p><b>Nilus</b>, <b>Nil</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego, od gr. <i>neilos</i> – \"rzeka\". Istnieli liczni święci o tym imieniu.", "Nichola": "<p>Nicola lub Nichola jest łacińską wersją greckiego imienia osobistego Nikolaos (Νικόλαος), pochodzącego z nikē oznaczającego \"wygrę\", a laos oznacza \"ludzie\", co oznacza \"wygrnięcia ludzi\". Nicola to zarówno imię męskie, jak i żeńskie, w zależności od norm kulturalnych.</p>", "Nikolet": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikoleta</b>.</p><b>Nikoleta</b>, <b>Nikoletta</b> – imię żeńskie pochodzenia włoskiego. Powstało od imienia <a href=\"https://pl.wikipedia.org/wiki/Nikola\" target=\"_blank\" rel=\"noopener noreferrer\">Nikola</a>, gdyż we <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włoszech</a> i <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">Francji</a> <i>Nicola</i>, <i>Nicolai</i> jest imieniem męskim, a jako żeński odpowiednik powstała <i>Nicolette</i>, <i>Nicoletta</i> ze względu na popularne we Włoszech końcówki imion <i>-etta</i>. Od Nikolety powstało imię <a href=\"https://pl.wikipedia.org/wiki/Koleta\" target=\"_blank\" rel=\"noopener noreferrer\">Koleta</a>, które jednak posiada w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> o wiele dłuższą tradycję niż Nikoleta.", "Nurlana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nurlan</b>.</p><p>Nurlan (kazachski: Нұрлан) to turkijska męska nazwa, która jest powszechna w Azerbejdżanie, Kazachstanie i Uzbekistanie. Nazwa jest w istocie połączeniem arabskiego słowa Noor (także śpiewany jako \"Nur\") oznaczającego światło, promienie lub blask oraz tureckiego słowa \"Lan/Ulan\", który oznacza lwa w większości języków tureckich.</p>", "Nevada": "<p>Nevada (ang. Nevada, amerykańskie wymowa: [nəˈvadə]; hiszpańskie wymawianie: [neˈβaða]) - stan w zachodniej części Stanów Zjednoczonych.</p>", "Naoko": "<b>Naoko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;なおこ, ナオコ) − <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>, które jest czasami pisane <b>Nahoko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;なほこ, ナホコ).", "Nellya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nelly</b>.</p><p>Kornell Ayrel Haynes-młodszy (ang. Cornell Iral Haynes Jr. ; rodzaj.</p>", "Nasturcja": "<b>Nasturcja</b> (<i>Tropaeolum</i> L.) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> roślin z rodziny <a href=\"https://pl.wikipedia.org/wiki/Nasturcjowate\" target=\"_blank\" rel=\"noopener noreferrer\">nasturcjowatych</a> (<i>Tropaeolaceae</i>). Należy do niego ponad 80 gatunków pochodzących z <a href=\"https://pl.wikipedia.org/wiki/Ameryka_Po%C5%82udniowa\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryki Południowej</a> i <a href=\"https://pl.wikipedia.org/wiki/Ameryka_%C5%9Arodkowa\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryki Środkowej</a>, największe zróżnicowanie osiąga wzdłuż <a href=\"https://pl.wikipedia.org/wiki/Andy\" target=\"_blank\" rel=\"noopener noreferrer\">Andów</a> od Kolumbii po południowe <a href=\"https://pl.wikipedia.org/wiki/Chile\" target=\"_blank\" rel=\"noopener noreferrer\">Chile</a>. W naturze rośliny te zasiedlają wilgotne lasy, suche zarośla i górskie <a href=\"https://pl.wikipedia.org/wiki/Piarg\" target=\"_blank\" rel=\"noopener noreferrer\">piargi</a>. Nasturcja bulwiasta jest ważną rośliną spożywczą dla ludności Ameryki Południowej. Mięsiste owoce i pąki kwiatowe nasturcji większej zakonserwowane w słonej wodzie lub occie stosowane są jak przyprawa (przypominają <a href=\"https://pl.wikipedia.org/wiki/Kapary\" target=\"_blank\" rel=\"noopener noreferrer\">kapary</a>). Niektóre gatunki są uprawiane jako ozdobne, dotyczy to zwłaszcza: <a href=\"https://pl.wikipedia.org/wiki/Nasturcja_wi%C4%99ksza\" target=\"_blank\" rel=\"noopener noreferrer\">nasturcji większej</a>, mniejszej, <i>Tropaeolum peltophorum</i> i mieszańce między nimi. W <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> najczęściej w uprawie ogrodowej lub na balkonach.", "Nasima": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nasim</b>.</p><p>Nassim (arabski: نسيم) również przetransliterowany jako Nacim, Naseem, Nasseem, Nasim, Nesim lub Nessim, jest unisex nazwisko oznaczające \"miękkie wiatr, świeży powietrze\". Jest używany głównie w kulturach i grupach językowych Bliskiego Wschodu i Azji Południowej.</p>", "Neonilla": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Neonila</b>.</p><b>Nunilona</b>, <b>Nunila</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Jego patronką jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ta_Nunilona\" target=\"_blank\" rel=\"noopener noreferrer\">święta Nunilona</a>. Formą tego imienia, spotykaną w krajach wschodniosłowiańskich, jest <i>Neonila</i> lub <i>Neonilla</i>.", "Nnenna": "<p>Nnenna to kobiece imię Igbo, które tłumaczy \"matka ojca\". Tradycyjnie jest ona nadawana dziewczynkom, które są uważane za reinkarnacje ich babci.</p>", "Nazanin": "<p>Nazanin (perskie: نَازَنِین, romanized: Nāzanīn, lit. 'słodko, miłe, kochanie, urocze', perskie wymowa: [naː.za.ˈniːn]) i także śpiewany Nazenin, Naznin lub Nazneen, jest perską nazwą dla kobiet w Iranie, Afganistanie, Azerbejdżanie, Turcji, Pakistanie i Indiach.</p>", "Nimfa": "<b>Nimfa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, od gr. <i>νύμφη (nymphe)</i> – \"dziewczyna, narzeczona\". Patronką tego imienia w Kościele katolickim jest św. Nimfa, córka prefekta <a href=\"https://pl.wikipedia.org/wiki/Palermo\" target=\"_blank\" rel=\"noopener noreferrer\">Palermo</a> w czasach <a href=\"https://pl.wikipedia.org/wiki/Konstantyn_I_Wielki\" target=\"_blank\" rel=\"noopener noreferrer\">Konstantyna Wielkiego</a>.", "Neetu": "<p>Neetu to imię kobiety. Znani ludzie z nazwiskiem to: Neetu Chandra (ur. 1984), indyjska aktorka filmowa, model i artysta walki Neetu David (ur. 1977), indyjski kryketer Neetu Singh (ur. 1958), indyjskie aktorka Neetu Singh, ur. 1990), indyska aktorka i model</p>", "Ni Luh Putu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Nea": "<p>Linnéa, Linnea, skrócona forma - Neya, Nea, łaskawa forma - Nennne, Nenne) - żeńskie imię pochodzenia szwedzkiego.</p>", "Naiara": "<p>Naiara to kobiece imię. Znanymi osobami z nazwiska są: Naiara Azevedo (ur. 1989), brazylijska piosenkarka-zespółkarka Naiara Beristain (ur. 1992), hiszpańska piłkarka Naiira Egozkue (ur. 1983), hiszpanka piłkarz handbalowy Naiara Moreno (ur. 1997), hiszpanii Naiara Telletxea (ur. 1984), hiszpaniacka rowerka</p>", "Nely": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Neli</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nel</b>.</p><b>Nela</b> – imię żeńskie, powstałe jako usamodzielnione zdrobnienie imion z zakończeniem -<i>nela</i> lub podobnym, takich jak na przykład <a href=\"https://pl.wikipedia.org/wiki/Kornelia\" target=\"_blank\" rel=\"noopener noreferrer\">Kornelia</a> lub <a href=\"https://pl.wikipedia.org/wiki/Petronela\" target=\"_blank\" rel=\"noopener noreferrer\">Petronela</a>.", "Neva": "<p>Neva - gra komputerowa w gatunku akcji-platformera, opracowana przez niezależną hiszpańską studio Nomada Studio. Wydawnictwo odbyło się 15 października 2024 roku na platformach PlayStation 5, Xbox Series X/S, Nintendo Switch i Windows.</p>", "Nailya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nailia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Naili</b>.</p><p>Naili (arabski: نائلی) to arabskie pochodzenie męskie nazwisko i nazwisko. Nazwa jest używana w Turcji z tym samym znaczeniem jak Nail: \"odniosły, podbiły\". Jest to wariant Naila przyłączony z tureckim oskarżającym markerem przypadku -i.</p>", "Nayeon": "<p>To jest jeden z Korejczyków, imieniem Im. Im Na-yeon (Korejski: 임나연, urodzona 22 września 1995), popularnie znana pod pseudonimem Nayeon, jest koreańską piosenkarką.</p>", "Natalyia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nataliia</b>.</p><p>Natalia jest nazwiskiem dla kobiet z oryginalnym późnolatynskim znaczeniem \"Dzień Bożego Narodzenia\" (por. lat. natale domini).</p>", "Negin": "<p>Negin (perskie: نگین: [nə'giːn]) to perskie słowo. Oznacza to rzadki diament lub kamień i odnosi się do kamienia szlachetnego na biżuterii, na przykład pierścionku lub naszyjnika.</p>", "Neeta": "<p>Neeta to kobiece imię. Wśród znanych osób z tym nazwiskiem są: Neeta Choudhary, indyjska polityka Neeta Devi, indyjskie graczko Neeta Dhungana, nepalejska aktorka Neeta Kadam, indyjski kryker Neeta Lulla, indycka projektantka kostiumów Neeta Madahar, artystka brytyjska Neeta Mehta, aktorka Neet Pateriya, indyckie parlamentarz Neeta Pillai, indyskiej aktorka Neetha Puri, indyjsko-amerykańska aktorka i modelka Neeta Ramaiya, indyska pisarka Neeta Sen,...</p>", "Nomsa": "<p>Nomsa to kobiece imię. Wśród znanych osób z nazwiskiem są: Helene Nomsa Brath (ur. 1942), amerykański model i aktywista Nomsa Buthelezi (ur. 1982), południowoafrykańska aktorka i prezenterka telewizyjna Nomsa Kubheka (ur. 1970), połudnoafrykański polityk Nomsa Marchesi (ur. 1970), południo Afrykański politik Nomsa Manaka (ur. 1965), południeafrykańskiego tancerza, choreografa i aktorka Nomsa Mdlalose, południowaafrykańczy folklorysta, opowiadacz historii,...</p>", "Nasreen": "<p>Nasrin (przekładowany \"nisriyn/ nisrīn\"; Nesrin, Nesrine, Nazreen lub Nasreen; perskie: نسرين) to żeńskie imię w perskim, co oznacza \"dzikie róże\".</p>", "Ngoc Diep": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nothando": "<p>Nothando to nazwa kobieca z Południowej Afryki. Znani ludzie z nazwiska to: Nothando Dube (1988-2019), Swazi królewski Nothando Hlophe (urodzony 1989), Swazi królowa i śpiewa gospel Nothando Vilakazi (urodzona 1988), piłkarz południowoafrykański</p>", "Najma": "<p>Najma (arabsko: نجمة) lub Al-Najma mogą odnosić się do:</p>", "Ni Nengah": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Nanami": "<b>Nanami</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ななみ, ナナミ) – popularne <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>, jest używane także jako nazwisko.", "Ndeye": "<p>Ndeye, Ndèye lub N'deye to senegalijskie imię żeńskie. Do wybitnych osób z tym nazwiskiem należą:</p>", "Naime": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Naim</b>.</p><p>naim to kompaktowy program do natychmiastowej wymiany wiadomości, obsługujący protokół AIM, ICQ, IRC. W przeciwieństwie do większości takich programów, nie jest graficzny.</p>", "Nerina": "<b>Nerina</b> (<i>Nerine</i>) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> roślin z rodziny <a href=\"https://pl.wikipedia.org/wiki/Amarylkowate\" target=\"_blank\" rel=\"noopener noreferrer\">amarylkowatych</a>. Obejmuje 23 gatunków. Rośliny te występują w <a href=\"https://pl.wikipedia.org/wiki/Afryka_Po%C5%82udniowa\" target=\"_blank\" rel=\"noopener noreferrer\">Afryce Południowej</a>, na północy sięgając <a href=\"https://pl.wikipedia.org/wiki/Namibia\" target=\"_blank\" rel=\"noopener noreferrer\">Namibii</a>, <a href=\"https://pl.wikipedia.org/wiki/Botswana\" target=\"_blank\" rel=\"noopener noreferrer\">Botswany</a> i <a href=\"https://pl.wikipedia.org/wiki/Zimbabwe\" target=\"_blank\" rel=\"noopener noreferrer\">Zimbabwe</a>. Dwa gatunki zostały <a href=\"https://pl.wikipedia.org/wiki/Introdukcja\" target=\"_blank\" rel=\"noopener noreferrer\">introdukowane</a> do <a href=\"https://pl.wikipedia.org/wiki/Europa\" target=\"_blank\" rel=\"noopener noreferrer\">Europy</a>: <i>Nerine sarniensis</i> do <a href=\"https://pl.wikipedia.org/wiki/Wielka_Brytania\" target=\"_blank\" rel=\"noopener noreferrer\">Wielkiej Brytanii</a>, <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">Francji</a>, na <a href=\"https://pl.wikipedia.org/wiki/Madera\" target=\"_blank\" rel=\"noopener noreferrer\">Maderze</a> i <a href=\"https://pl.wikipedia.org/wiki/Azory\" target=\"_blank\" rel=\"noopener noreferrer\">Azorach</a>, a nerina ogrodowa do Wielkiej Brytanii. Rosną na <a href=\"https://pl.wikipedia.org/wiki/Klif\" target=\"_blank\" rel=\"noopener noreferrer\">klifach</a>, skałach, piaskach i mokradłach i kwitną jesienią. Kilka gatunków i liczne mieszańce uprawiane są jako rośliny ozdobne. Z powodu łatwości z jaką rośliny te się krzyżują – oznaczanie roślin z tego rodzaju bywa kłopotliwe.", "Nazia": "<p>Nazia to żeńskie imię pochodzące z Persów. Do wybitnych osób z tym nazwiskiem należą:</p>", "Neena": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nena</b>.</p>Przydomek „Nena” nadały jej hiszpańskie dzieci, z którymi w młodości spędziła wakacje w <a href=\"https://pl.wikipedia.org/wiki/Alicante\" target=\"_blank\" rel=\"noopener noreferrer\">Alicante</a> i które nie znały jej imienia, dlatego wołały do niej „niña” (dziewczynka).", "Natsuki": "<b>Natsuki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;なつき, ナツキ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, częściej noszone przez kobiety niż przez mężczyzn, jest także używane jako nazwisko.", "Nemezja": "<b>Nemezja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeński odpowiednik imion: <a href=\"https://pl.wikipedia.org/wiki/Nemezjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Nemezjusz</a> i <a href=\"https://pl.wikipedia.org/wiki/Nemezy\" target=\"_blank\" rel=\"noopener noreferrer\">Nemezy</a>. Wywodzi się od słowa <i>némesis</i>, oznaczającego „przydzielenie tego, co się komu należy”, które stało się w mitologii nazwą uosobienia sprawiedliwości (<a href=\"https://pl.wikipedia.org/wiki/Nemezis\" target=\"_blank\" rel=\"noopener noreferrer\">Nemezis</a>).", "Ni̇lay": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nilai</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nila</b>.</p><b>Nila</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia greckiego, od gr. <i>neilos</i> - \"rzeka\". Forma żeńska imienia <a href=\"https://pl.wikipedia.org/wiki/Nilus\" target=\"_blank\" rel=\"noopener noreferrer\">Nilus</a>.", "Nonhlanhla": "<p>Nonhlanhla (Nhlanhla unisex) to kobiece imię, pochodzące od słowa Nguni nhlanhla, co oznacza \"szczęście\". Inne znaczenie obejmuje bogini szczęścia.</p>", "Najiba": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Najib</b>.</p><p>Najib lub Najeeb (arabickie: نجيب) to arabskie imię męskie. Do wybitnych osób z tym nazwiskiem należą:</p>", "Neliia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nelia</b>.</p><p>Nelia (lat. Nelia) - rodzaj sukkulatów rodziny Aizoaceae, podrodzinnego rodu Ruschioideae, rosnący na terytorium prowincji Kapskiej Republiki Południowej Afryki.</p>", "Nazaria": "<b>Nazaria</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające \"pochodząca z <a href=\"https://pl.wikipedia.org/wiki/Nazaret\" target=\"_blank\" rel=\"noopener noreferrer\">Nazaretu</a>\". Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Nazaria_Ignacia_March_Mesa\" target=\"_blank\" rel=\"noopener noreferrer\">św. Nazaria Ignacja March Mesa</a>.", "Niloofar": "<p>Niloufar, Nilophur, Nelofar, Nilofar, Nilufar, Neloofar, Neelofar, Neiloufar lub Nîlûfar (perskiej: نیلوفر), oznaczający cenny, rzadki, niebieski lotos, nimfaea lub lilia wodna to żeńskie imię pochodzenia perskiego, ostatecznie z sanskrytu: नीलोत्पल (nīlotpala, \"niebieski lotus\"). Nounoufar (armejski: Նունուֆար) jest jego armeńską wersją.</p>", "Norbertyna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Norbert</b>.</p><b>Norbert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">starogermańskiego</a>. Wywodzi się od słów <i>nord</i> – tj. północ i <i>beraht</i> – czyli błyszczeć, jaśnieć. Całość znaczy więc „ten, który dokonuje wielkich czynów na północy”, „sławny mąż z północy”.", "Nupur": "<p>Nupur to imiona kobiece i nazwisko pochodzące z Indii. Mieszkańcy tej nazwy to:</p>", "Nádia": "<p>Nadia to imię kobiety. Wśród różnych wersji znajdują się Nadja, Nadya, Nadine, Nadiya i Nadiia.</p>", "Ni Kadek Ayu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Nagisa": "<b>Nagisa</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;渚, なぎさ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">japońskie imię</a>, noszone zarówno przez kobiety i mężczyzn.", "Nataliia-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nataliia</b>.</p><p>Natalia jest nazwiskiem dla kobiet z oryginalnym późnolatynskim znaczeniem \"Dzień Bożego Narodzenia\" (por. lat. natale domini).</p>", "Naili": "<p>Naili (arabski: نائلی) to arabskie pochodzenie męskie nazwisko i nazwisko. Nazwa jest używana w Turcji z tym samym znaczeniem jak Nail: \"odniosły, podbiły\". Jest to wariant Naila przyłączony z tureckim oskarżającym markerem przypadku -i.</p>", "Nimisha": "<p>Nimisha to indyjskie imię kobiece. Może odnosić się do następujących osób: Nimisha Madhvani, ugandzkiej dyplomatki Nimisha Mehta, brytyjskiej aktorki Nimisha Mukerji, kanadyjskiej reżyserki filmowej i telewizyjnej Nimisha Pandey, indyjskiej telewizji i internetowej treści deweloper i kurator Nimisha Sajayan, indyjska aktorka Nimisha Suresh, indyjski aktorka Nimisa Suthar, indyjskich polityków Nimisha Vakharia, indyskiej aktorki</p>", "Natally": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nataly</b>.</p><p>Nataly to nazwisko dla kobiet, wariant nazwiska Natalie (zdanie).</p>", "Niculina": "<p>Niculina to rumuńskie imię. Wśród znanych osób z nazwiskiem są: Niculina Oprea (ur. 1957), rumuński poeta Niculina Sasu (ur. 1952), rumuńska piłkarka handbalowa Niculina Vasile (ur. 1958), rumuńskiego wysokiego skakacza</p>", "Nurbanu": "<b>Afife Nurbanu Sultan</b> (pełne imię <i>Haseki Afife Nûr-Banû Vâlide Sultân Aliyyetü'ş-Şân Hazretleri</i>; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_osma%C5%84skoturecki\" target=\"_blank\" rel=\"noopener noreferrer\">osmań.</a> نور بانو سلطان; (ur. ok. <a href=\"https://pl.wikipedia.org/wiki/1525\" target=\"_blank\" rel=\"noopener noreferrer\">1525</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/7_grudnia\" target=\"_blank\" rel=\"noopener noreferrer\">7 grudnia</a> <a href=\"https://pl.wikipedia.org/wiki/1583\" target=\"_blank\" rel=\"noopener noreferrer\">1583</a>) – <a href=\"https://pl.wikipedia.org/wiki/Haseki\" target=\"_blank\" rel=\"noopener noreferrer\">Haseki Sultan</a> jako ulubiona nałożnica, a później prawowita żona sułtana <a href=\"https://pl.wikipedia.org/wiki/Selim_II\" target=\"_blank\" rel=\"noopener noreferrer\">Selima II</a>, <a href=\"https://pl.wikipedia.org/wiki/Valide_Sultan\" target=\"_blank\" rel=\"noopener noreferrer\">Valide Sultan</a> oraz koregentka jako matka <a href=\"https://pl.wikipedia.org/wiki/Murad_III\" target=\"_blank\" rel=\"noopener noreferrer\">Murada III</a>.", "Neela": "<p>Neela to żeńskie imię, które może odnosić się do:</p>", "Natsumi": "<b>Natsumi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;なつみ, ナツミ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>, używane jest też jako nazwisko.", "Nikitha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikita</b>.</p><p>Nikita: Nikita to męskie imię w krajach postsowieckich i niektórych krajach wschodniej Europy. Nikita Wodopol (dzień Nikita) - dzień kalendarza narodowego wschodnich Słowań.</p>", "Nazariia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nazaria</b>.</p><b>Nazaria</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające \"pochodząca z <a href=\"https://pl.wikipedia.org/wiki/Nazaret\" target=\"_blank\" rel=\"noopener noreferrer\">Nazaretu</a>\". Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Nazaria_Ignacia_March_Mesa\" target=\"_blank\" rel=\"noopener noreferrer\">św. Nazaria Ignacja March Mesa</a>.", "Nuha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nuh</b>.</p><p>Nuh to gmina z okręgu Gurgaon w stanie Haryana w Indiach.</p>", "Natalee": "<p>Natalee to imię kobiece. Jest to wariant nazwiska Natalie, choć rzadko znany według Stanów Zjednoczonych.</p>", "Nikolla": "<p>Nikolla (nieokreślona forma Nikollë) jest albaniańska pierwotna nazwa i nazwisko pochodzące od greckiego Nikolaos (Νικόλαος). Często używają go chrześcijanie albańscy.</p>", "Nijole": "<p>Nijolė to litewska żeńska nazwa. Jest to jedno z licznych pseudomythologicznych nazw wynalezionych w XIX wieku przez litewskiego pisarza Teodora Narbutta dla litewskiej mitologii pogańskiej (w jego książce nazwa została podana w języku polskim stylu \"Nijola\").</p>", "Newena": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nevena</b>.</p><p>Nevena (kirylicki: Невена) to kobiece imię popularne w językach sławskich południowych. Nazwa jest kobiecością męskiego imienia Neven, co oznacza \"kalendulę oficinalną\".</p>", "Niña": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nyna</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nina</b>.</p><b>Nina</b> – imię żeńskie o niejasnej etymologii. Prawdopodobnie wywodzi się od imienia mitycznego założyciela <a href=\"https://pl.wikipedia.org/wiki/Niniwa\" target=\"_blank\" rel=\"noopener noreferrer\">Niniwy</a> i imperium asyryjskiego - Ninosa. W piśmiennictwie imię to występuje w formach: <i>Nina, Nino, Nunia, Nuna i Nonna</i>.", "Nilofar": "<p>Niloufar, Nilophur, Nelofar, Nilofar, Nilufar, Neloofar, Neelofar, Neiloufar lub Nîlûfar (perskiej: نیلوفر), oznaczający cenny, rzadki, niebieski lotos, nimfaea lub lilia wodna to żeńskie imię pochodzenia perskiego, ostatecznie z sanskrytu: नीलोत्पल (nīlotpala, \"niebieski lotus\"). Nounoufar (armejski: Նունուֆար) jest jego armeńską wersją.</p>", "Nilly": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nily</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nili</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nil</b>.</p><b>Nilus</b>, <b>Nil</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego, od gr. <i>neilos</i> – \"rzeka\". Istnieli liczni święci o tym imieniu.", "Noaa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Noa</b>.</p><p>Ahinóam Nińi (br. אחינועם ניני) (znana również pod pseudonimem Noego (br.</p>", "Nicolet": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nicoleta</b>.</p><p>Nicoleta to rumuńskie imię żeńskie pochodzące od greckiego Nikolaos. Wśród znanych osób z tej nazwy są: Nicoleta Alexandru, piosenkarka reprezentująca Rumunię na konkursie piosenki Eurovision Song Contest 2003 Nicoleta Grasu, rumuńska dyskowerka Nicoleta Onel, rumuńskiej gimnastki Nicoleta Daniela Șofronie, artystyczna gimnastka</p>", "Nadeen": "<p>Nadine (z wariantami pisowni: Nadeen, Nadene) to żeńskie imię. Jest to francuska opracowanie (minucywne feminino; cf.</p>", "Najia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Naji</b>.</p><p>Naji (najgorętszy mężczyzna na WoS) (turski), arabski: ناجي, Nājī) to arabskie imię męskie, które pochodzi od arabskiego czasownika przetrwać. To też nazwisko.</p>", "Nivetha": "<p>Nivetha to indyjskie imienne imię. Znani ludzie z nazwiskiem to: Nivetha Pethuraj (ur. 1991), indyjska aktorka i modelka Nivetha Thomas (ur. 1995), indyjskie aktorka, tancerka i model.</p>", "Ngoc Bich": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ni Luh Gede": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Nebahat": "<p>Nabahat lub Nabahat to kobiece turskie imię arabskiego pochodzenia oznaczające przebudzone lub honor. Do wybitnych osób z nazwiskiem należą: Nebahat Çehre (ur. 1944), turecka aktorka, piosenkarka i model Nebahat Akkoç (ur. 1956), turecka działaczka za prawa kobiet Nebahat Albayrak (ur. 1968), turecko-holenderska polityka Nabahat Jah Begum, jedna z córek Muhammada Khair ud-din Mirzy, Khurshid Jah Bahadur uznana za szefa dynastii Timurid ...</p>", "Ngoc Nhi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngọc Diệp": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Noeline": "<p>Noeline to kobiece imię.</p>", "Namira": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Namir</b>.</p><b>Namir</b> — staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Imię to składa się z dwóch członów: <i>na</i> (\"na\"; jedno ze znaczeń <i>na</i> nazywało kogoś, ze względu na kogo coś się działo\") oraz <i>-mir</i> (\"pokój, spokój, dobro\"). Mogło ono więc oznaczać \"ten, który pojawił się w czasie pokoju\" albo \"ten, dzięki któremu zapanuje pokój\".", "Neethu": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Neetu</b>.</p><p>Neetu to imię kobiety. Znani ludzie z nazwiskiem to: Neetu Chandra (ur. 1984), indyjska aktorka filmowa, model i artysta walki Neetu David (ur. 1977), indyjski kryketer Neetu Singh (ur. 1958), indyjskie aktorka Neetu Singh, ur. 1990), indyska aktorka i model</p>", "Nadiia-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nadiia</b>.</p><p>Nadiya lub Nadiia (ukraina: Надія) to imię żeńskie, pochodzące z ukraińskiego słowa oznaczającego \"oczekiwanie\". Jest nosiona przez następujących osób: Nadia Al-Kokabany, jemenską pisarkę Nadiya Anderson (ur. 1986), połowę amerykańskiego duetu osobowości telewizyjnej Nadiya Babych (1943-2021), ukraińską lingwistę i filologię Nadiya Baranova (ur. 1983), ukraińską goalierkę futbolu Nadiia Bashynska (ur. 2003), ukraiński-kanadyjską tancerkę lodową Nadiia Bielkina (ur. 1990),...</p>", "Noëmi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Noemy</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Noemi</b>.</p><b>Noemi</b> (hebr. Naomi, נָעֳמִי) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się od hebrajskiego słowa oznaczającego „moja słodycz”.", "Nepomucena": "<b>Nepomucena</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Nepomucen\" target=\"_blank\" rel=\"noopener noreferrer\">Nepomucen</a>.", "Ni Made Ayu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Naana": "<p>Naana jest kobiece imię pochodzenia ghanskiego.</p>", "Nefertiti": "Pochodzenie Nefertiti nie jest jasne. Przedstawia się teorię, jakoby była księżniczką <a href=\"https://pl.wikipedia.org/wiki/Mitanni\" target=\"_blank\" rel=\"noopener noreferrer\">mitannijską</a> – co tłumaczyłoby jej imię, utożsamia się ją też z <a href=\"https://pl.wikipedia.org/wiki/Taduhepa\" target=\"_blank\" rel=\"noopener noreferrer\">Taduhepą</a>. Przyjmuje się także, że była córką doradcy dworu <a href=\"https://pl.wikipedia.org/wiki/Aj_(faraon)\" target=\"_blank\" rel=\"noopener noreferrer\">Aja</a>, który wstąpił na tron po śmierci <a href=\"https://pl.wikipedia.org/wiki/Tutanchamon\" target=\"_blank\" rel=\"noopener noreferrer\">Tutanchamona</a>.", "Natsuko": "<b>Natsuko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;なつこ, ナツコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Nuala": "<p>Nuala lub Fionnuala jest irlandzką nazwą żeńską, pochodzącą z mitologii irlandzkiej - jest albo diminutiwną formą Fionnuala (\"piękny ramię\"), córką Lir, albo alternatywną nazwą Úna (może oznacza \"lamb\"), żoną Finvarry, króla wróżek. W współczesnym irlandzkim opowieścianiu Nuala oznacza \"narodzony z morza\".</p>", "Nobuko": "<b>Nobuko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;のぶこ, ノブコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Nily": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nili</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nil</b>.</p><b>Nilus</b>, <b>Nil</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego, od gr. <i>neilos</i> – \"rzeka\". Istnieli liczni święci o tym imieniu.", "Netsanet": "<p>Netsanet (amharski: ነፃነት) to etyopskie imię przede wszystkim kobiece. Znani ludzie z nazwiska obejmują: Netsanet Achamo (ur. 1987), etyopski biegacz długodystansowy Netsanett Desta (ur. 2000), etyopijski biegacz średniej dystancji Netsanette Gudeta (ur. 1991), etypijski biegaczy długodystans Netsanetet Mekonnen (ur. 1988), etyopiyańska aktorka izraelska Netsaneta Workneh (1983-2026), etypijskie aktorka, filmowca i telewizyjna osobowość</p>", "Nikhitha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikhita</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nichita</b>.</p><p>Nichita to rumuńska męska nazwa i nazwisko. Do wybitnych osób z tym nazwiskiem należą: Nichita Danilov (ur. 1952), rumuński poeta Nichita Iurașco (ur. 1999), moldawska piłkarka Nichita Moțpan (ur. 2001), moldawska piłkarz Nichita Smochină (1894-1980), rosyjsko-rumuńska aktywistka, uczona i polityczna figura Nichita Stănescu (1933-1983), rumuńska poetka i esejistka</p>", "Nomthandazo": "<p>Nomthandazo to kobiece imię pochodzące od słowa Nguni thandaza, co oznacza \"modlitwę\". W skróconych znanych wersjach znajdują się Thandi lub Thandie.</p>", "Ngọc Hân": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngọc Hà": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngọc Ánh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nabeela": "<p>Nabila, z jej wariantami napisu Nabeela, Nabillah, Nebila i Nabeelah, jest kobiece odmiana nazwiska Nabil, co oznacza szlachetny. Do wybitnych osób z tym nazwiskiem należą:</p>", "Nicoleta-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nicoleta</b>.</p><p>Nicoleta to rumuńskie imię żeńskie pochodzące od greckiego Nikolaos. Wśród znanych osób z tej nazwy są: Nicoleta Alexandru, piosenkarka reprezentująca Rumunię na konkursie piosenki Eurovision Song Contest 2003 Nicoleta Grasu, rumuńska dyskowerka Nicoleta Onel, rumuńskiej gimnastki Nicoleta Daniela Șofronie, artystyczna gimnastka</p>", "Natalia Andrea": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Natalia</b>.</p><b>Natalia</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em><a href=\"https://pl.wikipedia.org/wiki/Dies_natalis\" target=\"_blank\" rel=\"noopener noreferrer\">Dies natalis</a> Domini</em>, tj. <i>w dniu urodzin <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Pana</a></i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie wywodzące się od męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Natal_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Natalis</a>. W Polsce to imię jest poświadczane w formie Natalia w XIV wieku. Dawniej nadawane osobom urodzonym w dniach chrześcijańskich świąt <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCe_Narodzenie\" target=\"_blank\" rel=\"noopener noreferrer\">Bożego Narodzenia</a>. Patronką imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Adrian_i_Natalia_z_Nikomedii\" target=\"_blank\" rel=\"noopener noreferrer\">Natalia z Nikomedii</a>, męczennica.", "Noëmie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Noemi</b>.</p><b>Noemi</b> (hebr. Naomi, נָעֳמִי) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się od hebrajskiego słowa oznaczającego „moja słodycz”.", "Natallya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Natalya</b>.</p><p>Natalya (rosyjski: Наталья) to rosyjskie imię Natalii.</p>", "Ni Komang Ayu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Negina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Negin</b>.</p><p>Negin (perskie: نگین: [nə'giːn]) to perskie słowo. Oznacza to rzadki diament lub kamień i odnosi się do kamienia szlachetnego na biżuterii, na przykład pierścionku lub naszyjnika.</p>", "Nobuhle": "<p>Nobuhle to kobiece imię. Znanymi osobami z nazwiska są: Nobuhle Dlamini (ur. 1991), Liswati golfer Nobuhle Mahlasela (ur. 1982), południowoafrykańska aktorka i model Nobuhle Majika (ur. 1991), zimbabwskie piłkarz Nobuhle Nkabane (ur. 1979), połudnoafrykański polityk</p>", "Noami": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Noam</b>.</p><p>Noam (Hebrajskie: נעם/נועם) to hebrajskie imię, które oznacza \"miękkość\", \"miękczynię\" lub \"pokój\". Zaczęło się jako męska wersja Naomi (ang. \"Naomi\" lub \"Noémie\"), ale dziś jest bardzo powszechną hebrajską nazwą dla ludzi każdej płci.</p>", "Ngoc Minh Chau": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nefretete": "Pochodzenie Nefertiti nie jest jasne. Przedstawia się teorię, jakoby była księżniczką <a href=\"https://pl.wikipedia.org/wiki/Mitanni\" target=\"_blank\" rel=\"noopener noreferrer\">mitannijską</a> – co tłumaczyłoby jej imię, utożsamia się ją też z <a href=\"https://pl.wikipedia.org/wiki/Taduhepa\" target=\"_blank\" rel=\"noopener noreferrer\">Taduhepą</a>. Przyjmuje się także, że była córką doradcy dworu <a href=\"https://pl.wikipedia.org/wiki/Aj_(faraon)\" target=\"_blank\" rel=\"noopener noreferrer\">Aja</a>, który wstąpił na tron po śmierci <a href=\"https://pl.wikipedia.org/wiki/Tutanchamon\" target=\"_blank\" rel=\"noopener noreferrer\">Tutanchamona</a>.", "Ngoc Huyen": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Niceta": "<b>Niceta</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Nicetas\" target=\"_blank\" rel=\"noopener noreferrer\">Nicetas</a>. U Słowian zachodnich znana jest też inna forma tego imienia, <b>Nikita</b>, które jest imieniem zarówno żeńskim, jak i męskim.", "Nabilah": "<p>Nabila, z jej wariantami napisu Nabeela, Nabillah, Nebila i Nabeelah, jest kobiece odmiana nazwiska Nabil, co oznacza szlachetny. Do wybitnych osób z tym nazwiskiem należą:</p>", "Niya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nia</b>.</p><p>Nia jest grzybkiem z rodziny Niaceae. W tym zestawie znajdują się trzy gatunki, które są dostosowane do środowiska morskiego.</p>", "Natiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Natia</b>.</p><p>Natia (georgijska: ნათია) to kobiece gruzińskie imię, diminutiw Natela i ostatecznie pochodzi od słowa nateli (ნათელი), co oznacza \"światło, jasność\". Według Sal Służby Publicznej jest to jedna z 10 najczęstszych gruzińskich nazwisk dla kobiet.</p>", "Nicoleta-Antonia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nicoleta</b>.</p><p>Nicoleta to rumuńskie imię żeńskie pochodzące od greckiego Nikolaos. Wśród znanych osób z tej nazwy są: Nicoleta Alexandru, piosenkarka reprezentująca Rumunię na konkursie piosenki Eurovision Song Contest 2003 Nicoleta Grasu, rumuńska dyskowerka Nicoleta Onel, rumuńskiej gimnastki Nicoleta Daniela Șofronie, artystyczna gimnastka</p>", "Nicoleta-Andreea": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nicoleta</b>.</p><p>Nicoleta to rumuńskie imię żeńskie pochodzące od greckiego Nikolaos. Wśród znanych osób z tej nazwy są: Nicoleta Alexandru, piosenkarka reprezentująca Rumunię na konkursie piosenki Eurovision Song Contest 2003 Nicoleta Grasu, rumuńska dyskowerka Nicoleta Onel, rumuńskiej gimnastki Nicoleta Daniela Șofronie, artystyczna gimnastka</p>", "Nomalanga": "<p>Nomalanga to imiona żeńskie, pochodzące od słowa Nguni langa, co oznacza \"słońce\".</p>", "Nemezis": "<b>Nemezis</b> (także <b>Nemezys</b>; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Νέμεσις Némesis, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Nemesis</em>, <i>Rivalitas</i> ‘postanowienie’, ‘rozdająca to, co należne’) – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a> <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">bogini</a> zemsty, sprawiedliwości i przeznaczenia. Nazywana kobietą bez winy i wstydu. Znana była także jako <b>Adrasteja</b> (gr. Ἀδράστεια <i>Adrásteia</i>, łac. <i>Adrastea</i> – 'nieunikniona'). Zsyłała na ludzi szczęście lub niepowodzenie, ścigała przestępców i decydowała o losie w zależności od zasług. Córka <a href=\"https://pl.wikipedia.org/wiki/Nyks\" target=\"_blank\" rel=\"noopener noreferrer\">Nyks</a> i <a href=\"https://pl.wikipedia.org/wiki/Ereb\" target=\"_blank\" rel=\"noopener noreferrer\">Ereba</a>, uważana za uosobienie gniewu <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">bogów</a>. Ośrodkiem jej kultu było <a href=\"https://pl.wikipedia.org/wiki/Ramnus\" target=\"_blank\" rel=\"noopener noreferrer\">Ramnus</a> w <a href=\"https://pl.wikipedia.org/wiki/Attyka_(kraina_historyczna)\" target=\"_blank\" rel=\"noopener noreferrer\">Attyce</a>, stąd była nazywana <b>Ramnuzją</b> (gr. Ῥαμνουσία <i>Rhamnusía</i>, łac. <i>Rhamnusia virgo</i>). Stała na straży równowagi świata wraz z <a href=\"https://pl.wikipedia.org/wiki/Erynie\" target=\"_blank\" rel=\"noopener noreferrer\">Eryniami</a>.", "Nailie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Naili</b>.</p><p>Naili (arabski: نائلی) to arabskie pochodzenie męskie nazwisko i nazwisko. Nazwa jest używana w Turcji z tym samym znaczeniem jak Nail: \"odniosły, podbiły\". Jest to wariant Naila przyłączony z tureckim oskarżającym markerem przypadku -i.</p>", "Naomi-Rahela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Naomi</b>.</p><p>Trynity Lachon Fatu (ang. Trinity LaShawn Fatu, urodziny.</p>", "Ngọc Thảo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nikoline": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikolin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikolina</b>.</p><b>Nikolina</b> – imię żeńskie, powstałe poprzez zdrobnienie imienia <a href=\"https://pl.wikipedia.org/wiki/Nikola\" target=\"_blank\" rel=\"noopener noreferrer\">Nikola</a>, dokonane na gruncie języków romańskich.", "Nadyia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nadiia</b>.</p><p>Nadiya lub Nadiia (ukraina: Надія) to imię żeńskie, pochodzące z ukraińskiego słowa oznaczającego \"oczekiwanie\". Jest nosiona przez następujących osób: Nadia Al-Kokabany, jemenską pisarkę Nadiya Anderson (ur. 1986), połowę amerykańskiego duetu osobowości telewizyjnej Nadiya Babych (1943-2021), ukraińską lingwistę i filologię Nadiya Baranova (ur. 1983), ukraińską goalierkę futbolu Nadiia Bashynska (ur. 2003), ukraiński-kanadyjską tancerkę lodową Nadiia Bielkina (ur. 1990),...</p>", "Nanditha": "<p>Nandita lub Nanditha to indyjskie imienne. To północno-indyjska nazwa.</p>", "Niloufar": "<p>Niloufar, Nilophur, Nelofar, Nilofar, Nilufar, Neloofar, Neelofar, Neiloufar lub Nîlûfar (perskiej: نیلوفر), oznaczający cenny, rzadki, niebieski lotos, nimfaea lub lilia wodna to żeńskie imię pochodzenia perskiego, ostatecznie z sanskrytu: नीलोत्पल (nīlotpala, \"niebieski lotus\"). Nounoufar (armejski: Նունուֆար) jest jego armeńską wersją.</p>", "Namina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nam</b>.</p><p>W wietnamskim, Nam lub mascul jest słowem do wskazania: Mężczyzna: płci męskiej ludzi, w przeciwieństwie do \"żwomen\" jest płcią (żwomen) najniższej rangi szlachty feitów: Namcowiec kierunek: Słowo-Jużny zakres południowej dzielnicy kolonii miasteczkowej, prowincji Ho Nam, China: Słowe dzielnicy okręgów (khu) o nazwie Nam, patrz Naim (distrikty). W słowach \"wstrzymanie\" wskazują kierunek: męskie leki...</p>", "Nihara": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nihar</b>.</p><p>Nihar (w literce \" mgła, mgła, dewy\") może odnosić się do Nihar Ameen, indyjskiego trenerka pływania Nihar Mukherjee, indyjski polityk Nihar Ranjan Gupta, indyskiego dermatologa i pisarza Nihar Ranjana Laskar, indyjskich polityków Nihar Christison, filantrop i przedsiębiorcy z kremem biczem</p>", "Nama": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nam</b>.</p><p>W wietnamskim, Nam lub mascul jest słowem do wskazania: Mężczyzna: płci męskiej ludzi, w przeciwieństwie do \"żwomen\" jest płcią (żwomen) najniższej rangi szlachty feitów: Namcowiec kierunek: Słowo-Jużny zakres południowej dzielnicy kolonii miasteczkowej, prowincji Ho Nam, China: Słowe dzielnicy okręgów (khu) o nazwie Nam, patrz Naim (distrikty). W słowach \"wstrzymanie\" wskazują kierunek: męskie leki...</p>", "Niła": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nil</b>.</p><b>Nilus</b>, <b>Nil</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego, od gr. <i>neilos</i> – \"rzeka\". Istnieli liczni święci o tym imieniu.", "Ni Kadek Sri": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Nalina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nalin</b>.</p><p>Nalin to zarówno imię, jak i nazwisko. Znani ludzie z nazwiska to: Nalin Angammana (1945-1995), oficer wojskowy Sri Lanki Nalin Bandara (ur. 1974), polityk Sri Lanki, narodzony w 1974 roku Nalin Bandaranayake, kryker Sri Lanki Naryn Bhatt, polityk Gujarati Naryn Fernando (ur. 1973), polityk Naryn Jayawardena (ur. 1957), śrilankański piosenkarz Nalin Kohli, indyjski polityk Narin Kumar Kateel (ur. 1966), indyjski politik Naryn...</p>", "Ngoc Bao Anh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nargisa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nargis</b>.</p><p>Nargis - czasopismo o modzie i sztuce, wydane od 2012 roku w Azerbejdżanie przez dom wydawniczy ⁇ Nargis ⁇ . Czasopismo jest publikowane w formie drukowanym w języku angielskim i ma wersję elektroniczną na trzech językach: rosyjskim, azerbajdżajskim i angielskim.</p>", "Naziya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nazia</b>.</p><p>Nazia to żeńskie imię pochodzące z Persów. Do wybitnych osób z tym nazwiskiem należą:</p>", "Nélia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nelya</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nelia</b>.</p><p>Nelia (lat. Nelia) - rodzaj sukkulatów rodziny Aizoaceae, podrodzinnego rodu Ruschioideae, rosnący na terytorium prowincji Kapskiej Republiki Południowej Afryki.</p>", "Neveen": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Neven</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nevena</b>.</p><p>Nevena (kirylicki: Невена) to kobiece imię popularne w językach sławskich południowych. Nazwa jest kobiecością męskiego imienia Neven, co oznacza \"kalendulę oficinalną\".</p>", "Niluka": "<p>Niluka (sinhala: නිලූක/නිලූකා; tamil: நிலுக) jest unisex nazwisko znajdujące się w Sri Lance. Wśród znanych osób z tym nazwiskiem są: Niluka Ekanayake, sri Lankański polityk i astrolog Niluka Geethani Rajasekara (ur. 1982), sri lankański biegacz długodystansowy Niluka Karunaratne (ur. 1985), sri lankijski gracz badminton Niluka Karunaaratne (roketarka) (ur. 1979), sri lankanski gracz w kryket</p>", "Ni Gusti Ayu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Naomy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Naomi</b>.</p><p>Trynity Lachon Fatu (ang. Trinity LaShawn Fatu, urodziny.</p>", "Ngọc Bảo An": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nilai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nila</b>.</p><b>Nila</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia greckiego, od gr. <i>neilos</i> - \"rzeka\". Forma żeńska imienia <a href=\"https://pl.wikipedia.org/wiki/Nilus\" target=\"_blank\" rel=\"noopener noreferrer\">Nilus</a>.", "Natalia Isabel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Natalia</b>.</p><b>Natalia</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em><a href=\"https://pl.wikipedia.org/wiki/Dies_natalis\" target=\"_blank\" rel=\"noopener noreferrer\">Dies natalis</a> Domini</em>, tj. <i>w dniu urodzin <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Pana</a></i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie wywodzące się od męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Natal_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Natalis</a>. W Polsce to imię jest poświadczane w formie Natalia w XIV wieku. Dawniej nadawane osobom urodzonym w dniach chrześcijańskich świąt <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCe_Narodzenie\" target=\"_blank\" rel=\"noopener noreferrer\">Bożego Narodzenia</a>. Patronką imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Adrian_i_Natalia_z_Nikomedii\" target=\"_blank\" rel=\"noopener noreferrer\">Natalia z Nikomedii</a>, męczennica.", "Nashwa": "<p>Nashwa to kobiece imię arabskiego pochodzenia. Do wybitnych osób i miejsc z tą nazwą należą:</p>", "Natalia-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Natalia</b>.</p><b>Natalia</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em><a href=\"https://pl.wikipedia.org/wiki/Dies_natalis\" target=\"_blank\" rel=\"noopener noreferrer\">Dies natalis</a> Domini</em>, tj. <i>w dniu urodzin <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Pana</a></i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie wywodzące się od męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Natal_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Natalis</a>. W Polsce to imię jest poświadczane w formie Natalia w XIV wieku. Dawniej nadawane osobom urodzonym w dniach chrześcijańskich świąt <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCe_Narodzenie\" target=\"_blank\" rel=\"noopener noreferrer\">Bożego Narodzenia</a>. Patronką imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Adrian_i_Natalia_z_Nikomedii\" target=\"_blank\" rel=\"noopener noreferrer\">Natalia z Nikomedii</a>, męczennica.", "Nataliiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nataliia</b>.</p><p>Natalia jest nazwiskiem dla kobiet z oryginalnym późnolatynskim znaczeniem \"Dzień Bożego Narodzenia\" (por. lat. natale domini).</p>", "Neilia": "<b>Neilia</b>, <b>tawulec</b> (<i>Neillia</i>) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> roślin należący do rodziny <a href=\"https://pl.wikipedia.org/wiki/R%C3%B3%C5%BCowate\" target=\"_blank\" rel=\"noopener noreferrer\">różowatych</a> (<i>Rosaceae</i>). W tradycyjnym ujęciu rodzaj obejmował 11 gatunków. Na początku XXI wieku zostały tu także włączone cztery gatunki wyróżniane dotąd jako osobny rodzaj tawulec <i>Stephanandra</i>, po tym jak okazało się, że są ściśle spokrewnione i nie ma między nimi znaczących różnic morfologicznych. Są to <a href=\"https://pl.wikipedia.org/wiki/Krzew\" target=\"_blank\" rel=\"noopener noreferrer\">krzewy</a> występujące w naturze we wschodniej Azji: od <a href=\"https://pl.wikipedia.org/wiki/Japonia\" target=\"_blank\" rel=\"noopener noreferrer\">Japonii</a>, <a href=\"https://pl.wikipedia.org/wiki/Korea\" target=\"_blank\" rel=\"noopener noreferrer\">Korei</a> i <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">Chin</a> po <a href=\"https://pl.wikipedia.org/wiki/Nepal\" target=\"_blank\" rel=\"noopener noreferrer\">Nepal</a> i <a href=\"https://pl.wikipedia.org/wiki/Indonezja\" target=\"_blank\" rel=\"noopener noreferrer\">Indonezję</a>. Introdukowany i zdziczały Tawulec pogięty <i>N. inicisa</i> występuje w <a href=\"https://pl.wikipedia.org/wiki/Ameryka_P%C3%B3%C5%82nocna\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryce Północnej</a> i <a href=\"https://pl.wikipedia.org/wiki/Europa\" target=\"_blank\" rel=\"noopener noreferrer\">Europie</a>. Rośliny te zasiedlają lasy, górskie formacje zaroślowe i tereny skaliste.", "Nomathemba": "<p>Nomathemba (męski: Themba) to imię kobiety pochodzące od słowa Nguni themba, co oznacza \"wiarę\". Znani ludzie z nazwiskiem to: Nomathemba Maseko-Jele (ur. 1964), południowoafrykański polityk Nomathemba Mokgethi, południowaafrykacki polityk Nomethemba Ntsibande (ur. 1986), piłkarz południowej Afryki</p>", "Ni̇sa Nur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nisa</b>.</p><p>Nisa jest dzielnicą portugalskiej prowincji Portalegre. Ogromnie liczy się 575 km2, a w 2001 roku liczba ludności wynosiła 8585 mieszkańców.</p>", "Nekane": "<b>Dolores</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia hiszpańskiego wywodzące się od słowa <i>dolor</i> oznaczającego <i>ból</i>. W języku hiszpańskim używane w <i>María de los Dolores</i> – <a href=\"https://pl.wikipedia.org/wiki/Matka_Boska_Bolesna\" target=\"_blank\" rel=\"noopener noreferrer\">Matka Boska Bolesna</a>. Popularnym zdrobnieniem imienia Dolores jest Lola lub <a href=\"https://pl.wikipedia.org/wiki/Lolita_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Lolita</a>.", "Nanako": "<b>Nanako</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ななこ, ナナコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Ni Putu Sri": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Nthabiseng": "<p>Nthabiseng to kobiece imię. Znani ludzie z nazwiska to: Nthabiseng Khunou (ur. 1969), południowoafrykański polityk Nthabiseng Majiya (ur. 2004), połudnoafrykacki piłkarz Nthabiseng Mokoena, południoafrykańska interseksowa aktywistka Nthabiseng Mokena (archeolog), archeolog i akademik Nthabiseng Mosia, połudnoafrykański-ghanajski biznesmen</p>", "Ngọc Yến": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nyna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nina</b>.</p><b>Nina</b> – imię żeńskie o niejasnej etymologii. Prawdopodobnie wywodzi się od imienia mitycznego założyciela <a href=\"https://pl.wikipedia.org/wiki/Niniwa\" target=\"_blank\" rel=\"noopener noreferrer\">Niniwy</a> i imperium asyryjskiego - Ninosa. W piśmiennictwie imię to występuje w formach: <i>Nina, Nino, Nunia, Nuna i Nonna</i>.", "Nadiia-Anastasiia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nadiia</b>.</p><p>Nadiya lub Nadiia (ukraina: Надія) to imię żeńskie, pochodzące z ukraińskiego słowa oznaczającego \"oczekiwanie\". Jest nosiona przez następujących osób: Nadia Al-Kokabany, jemenską pisarkę Nadiya Anderson (ur. 1986), połowę amerykańskiego duetu osobowości telewizyjnej Nadiya Babych (1943-2021), ukraińską lingwistę i filologię Nadiya Baranova (ur. 1983), ukraińską goalierkę futbolu Nadiia Bashynska (ur. 2003), ukraiński-kanadyjską tancerkę lodową Nadiia Bielkina (ur. 1990),...</p>", "Nataliia-Oksana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nataliia</b>.</p><p>Natalia jest nazwiskiem dla kobiet z oryginalnym późnolatynskim znaczeniem \"Dzień Bożego Narodzenia\" (por. lat. natale domini).</p>", "Ngọc Minh Châu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ni Kadek Dwi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Ni Made Dwi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Nelly-Shirley": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nelly</b>.</p><p>Kornell Ayrel Haynes-młodszy (ang. Cornell Iral Haynes Jr. ; rodzaj.</p>", "Nicoleta-Sorina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nicoleta</b>.</p><p>Nicoleta to rumuńskie imię żeńskie pochodzące od greckiego Nikolaos. Wśród znanych osób z tej nazwy są: Nicoleta Alexandru, piosenkarka reprezentująca Rumunię na konkursie piosenki Eurovision Song Contest 2003 Nicoleta Grasu, rumuńska dyskowerka Nicoleta Onel, rumuńskiej gimnastki Nicoleta Daniela Șofronie, artystyczna gimnastka</p>", "Nogga": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Noga</b>.</p><p>Noga SA (anagrafa Gaon) - szwajcarska firma handlowa zajmująca się importem i eksportem w krajach Afryki, Europy Środkowej i Wschodniej, założona w 1957 roku i zarządzana w Genewie przez szwajcarszego miliarderka pochodzenia sudanskiego Nissima Gaona. Nazwa firmy została anagramem nazwy jej właściciela i kierownika Nissima Gaona.</p>", "Nombulelo": "<p>Nombulelo (mbulelo male) to kobiece imię z południowej Afryki pochodzące od słowa xhosa bulela, co oznacza \"dzięczność\". Znani ludzie z nazwiskiem to: Nombulelo Hermans (1970-2021), południowoafrykański polityk Nombulelo Mabandla (zmarł 2011), połudnoafrykańska polityk Nombolelo Mhlongo (urodzony w 1992 roku), aktorka z Południowej Afryki</p>", "Natallie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Natalie</b>.</p><p>Natalie (jap. ナタリー Natari:) - japońska strona internetowa poświęcona wiadomościom z branży rozrywkowej.</p>", "Nikhila": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikhil</b>.</p><p>Nikhil (sanskrit: निखिल) to męskie imię pochodzenia sanskrytu. Znajduje się głównie w Indiach, Nepalu i diasporze tych krajów.</p>", "Naomi-Lidia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Naomi</b>.</p><p>Trynity Lachon Fatu (ang. Trinity LaShawn Fatu, urodziny.</p>", "Nicole Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nicole</b>.</p><p>Nichol (niem. Nicole, przyjdź.</p>", "Nu": "<b>Ny</b> (<b>ni</b>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_starogrecki\" target=\"_blank\" rel=\"noopener noreferrer\">st.gr.</a> <b>νῦ</b>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_nowogrecki\" target=\"_blank\" rel=\"noopener noreferrer\">nw.gr.</a> <b>νι</b>, pisana <b>Νν</b>) – trzynasta <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">litera</a> <a href=\"https://pl.wikipedia.org/wiki/Alfabet_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu greckiego</a> oznaczająca spółgłoskę nosową przedniojęzykowo-dziąsłową „n”. W <a href=\"https://pl.wikipedia.org/wiki/Grecki_system_liczbowy\" target=\"_blank\" rel=\"noopener noreferrer\">greckim systemie liczbowym</a> oznaczała liczbę <a href=\"https://pl.wikipedia.org/wiki/50_(liczba)\" target=\"_blank\" rel=\"noopener noreferrer\">50</a>.", "Ngoc Trang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Naómi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Naomy</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Naomi</b>.</p><p>Trynity Lachon Fatu (ang. Trinity LaShawn Fatu, urodziny.</p>", "Nykol": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nykola</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikola</b>.</p><b>Nikola</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, współcześnie sprowadzony do języka polskiego żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Miko%C5%82aj\" target=\"_blank\" rel=\"noopener noreferrer\">Mikołaj</a>. Pochodzi od greckich słów <i>Nikos</i> – <i>zwycięstwo</i> i <i>laos</i> oznaczającego <i>ludzie</i>. Wśród imion nadawanych nowo narodzonym dzieciom, Nikola w 2017 r. zajmowała 26. miejsce w grupie imion żeńskich, co oznacza spadek o 16 miejsc od 2009 r., kiedy to zajmowała 10. miejsce w analogicznej grupie. W całej populacji Polek Nikola zajmowała w 2017 r. 73. miejsce (66 007 nadań). Imię zyskało jeszcze na popularności. W styczniu 2025 r. w rejestrze <a href=\"https://pl.wikipedia.org/wiki/PESEL\" target=\"_blank\" rel=\"noopener noreferrer\">PESEL</a>, wśród publicznie dostępnych danych dotyczących osób żyjących, wykazano 78429 kobiet o imieniu Nikola nadanym jako imię pierwsze.", "Natija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Natia</b>.</p><p>Natia (georgijska: ნათია) to kobiece gruzińskie imię, diminutiw Natela i ostatecznie pochodzi od słowa nateli (ნათელი), co oznacza \"światło, jasność\". Według Sal Służby Publicznej jest to jedna z 10 najczęstszych gruzińskich nazwisk dla kobiet.</p>", "Ngoc Nha Uyen": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngọc Gia Hân": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nikia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Niki</b>.</p><p>Niki - firma lotnicza z siedzibą w Wiedniu, Austria. Służiała regularnymi lotami do Europy i Egiptu z Wiednia, Salzburg, Friedrichshafen na zamówienie turoperatora Neckermann Reisen.</p>", "Nitisha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nitish</b>.</p><p>Nitish to indyjskie imię męskie z sanskrytu oznaczające \"władca wytycznych\". Wśród znanych osób z nazwiskiem są: Nitish Beejan, maorycjanski polityk Nitish Bharadwaj, indyjski aktor Nitish Chavan (ur. 1990), indyjski aktor filmowy i telewizyjny z języka marathi Nitish Jain, indyjscy edukacyjny Nitish Katara, indyjskie dyrektor biznesowy zamordowany w 2002 roku Nitish Kumar, premier Bihar Nitish Kumer (kryketacz), kanadyjski kryketacz Nitish Chandra Laharry...</p>", "Nicole-Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nicole</b>.</p><p>Nichol (niem. Nicole, przyjdź.</p>", "Nuna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nun</b>.</p><b>Nun</b> – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_egipska\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii egipskiej</a> pramateria, pierwszy materialny przejaw bytu, Nun jest przede wszystkim żywiołem kosmicznym. Jest on stworzeniem morza, na którym unosi się ziemia. Prawdopodobnie Nun był najpierw personifikowany w <a href=\"https://pl.wikipedia.org/wiki/Hermopolis\" target=\"_blank\" rel=\"noopener noreferrer\">Hermopolis</a> jako bóstwo męskie. Niekiedy, jako jedno z bóstw Ósemki, miewał głowę żaby. Jako najstarszy z bogów, pochodzący jeszcze z czasów chaosu, nosił przydomki \"stary\" i <i>ojciec czasów</i>. Jako personifikacja wód kosmicznych miał za atrybut głowę byka.", "Natalia Valentina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Natalia</b>.</p><b>Natalia</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em><a href=\"https://pl.wikipedia.org/wiki/Dies_natalis\" target=\"_blank\" rel=\"noopener noreferrer\">Dies natalis</a> Domini</em>, tj. <i>w dniu urodzin <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Pana</a></i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie wywodzące się od męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Natal_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Natalis</a>. W Polsce to imię jest poświadczane w formie Natalia w XIV wieku. Dawniej nadawane osobom urodzonym w dniach chrześcijańskich świąt <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCe_Narodzenie\" target=\"_blank\" rel=\"noopener noreferrer\">Bożego Narodzenia</a>. Patronką imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Adrian_i_Natalia_z_Nikomedii\" target=\"_blank\" rel=\"noopener noreferrer\">Natalia z Nikomedii</a>, męczennica.", "Naylya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nailia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Naili</b>.</p><p>Naili (arabski: نائلی) to arabskie pochodzenie męskie nazwisko i nazwisko. Nazwa jest używana w Turcji z tym samym znaczeniem jak Nail: \"odniosły, podbiły\". Jest to wariant Naila przyłączony z tureckim oskarżającym markerem przypadku -i.</p>", "Naveeda": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Naveed</b>.</p><p>Naveed to debiutancki album kanadyjskiego zespołu rockowego Our Lady Peace, produkowany przez Arnolda Lenny'ego, wydany 22 marca 1994 roku przez Sony Music Canada. Naveed odniosł sukces komercyjny w Kanadzie, rozbił się w liczbie ponad 100,000 egzemplarzy do końca roku i stał się platynem.</p>", "Ni Ketut Ayu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Ni Nyoman Sri": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Netha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Neta</b>.</p><p>Hozon Auto (cz. Wręcz przeciwnie.</p>", "Nam Soon": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nam</b>.</p><p>W wietnamskim, Nam lub mascul jest słowem do wskazania: Mężczyzna: płci męskiej ludzi, w przeciwieństwie do \"żwomen\" jest płcią (żwomen) najniższej rangi szlachty feitów: Namcowiec kierunek: Słowo-Jużny zakres południowej dzielnicy kolonii miasteczkowej, prowincji Ho Nam, China: Słowe dzielnicy okręgów (khu) o nazwie Nam, patrz Naim (distrikty). W słowach \"wstrzymanie\" wskazują kierunek: męskie leki...</p>", "Neta-Ly": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Neta</b>.</p><p>Hozon Auto (cz. Wręcz przeciwnie.</p>", "Nataliia-Olha": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nataliia</b>.</p><p>Natalia jest nazwiskiem dla kobiet z oryginalnym późnolatynskim znaczeniem \"Dzień Bożego Narodzenia\" (por. lat. natale domini).</p>", "Natika": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Natik</b>.</p><p>Natig, Natik lub Natiq (arabski: ناطق), to nazwisko i nazwisko pochodzenia arabskiego, które oznacza mówienie. Do wybitnych osób z tym nazwiskiem należą:</p>", "Ni Kadek Diah": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Ni Putu Ayu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Ngoc Tram": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Na Rae": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Na</b>.</p><p>Natrium (chemiczny symbol - Na, od łacińskiego Natrium) - element chemiczny 1 grupy (po przestarzałej klasyfikacji - główną podgrupa pierwszej grupy, IA), trzeciego okresu okresowego systemu elementów chemicznych D.</p>", "Natalia Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Natalia</b>.</p><b>Natalia</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em><a href=\"https://pl.wikipedia.org/wiki/Dies_natalis\" target=\"_blank\" rel=\"noopener noreferrer\">Dies natalis</a> Domini</em>, tj. <i>w dniu urodzin <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Pana</a></i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie wywodzące się od męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Natal_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Natalis</a>. W Polsce to imię jest poświadczane w formie Natalia w XIV wieku. Dawniej nadawane osobom urodzonym w dniach chrześcijańskich świąt <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCe_Narodzenie\" target=\"_blank\" rel=\"noopener noreferrer\">Bożego Narodzenia</a>. Patronką imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Adrian_i_Natalia_z_Nikomedii\" target=\"_blank\" rel=\"noopener noreferrer\">Natalia z Nikomedii</a>, męczennica.", "Niemira": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Niemir</b>.</p><b>Niemir</b>, <b>Niemirz</b>, <b>Niemierz</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z dwóch członów: <i>nie-</i> (negacja) i <i>-mir</i> („pokój, spokój, dobro”). Być może oznaczało „tego, kto nie zna pokoju” albo powstało przez negację imion z członem <i>Mir-</i> (takich, jak <i><a href=\"https://pl.wikipedia.org/wiki/Mirogniew\" target=\"_blank\" rel=\"noopener noreferrer\">Mirogniew</a></i> albo <i><a href=\"https://pl.wikipedia.org/wiki/Mirogod\" target=\"_blank\" rel=\"noopener noreferrer\">Mirogod</a></i>). Pisownia z kończowym <i>-rz</i> prawdopodobnie jest zapisem imienia zdrobniałego, uformowanego przy użyciu przyrostka <i>-jь</i>, pod wpływem którego wygłosowe <i>-r</i> przeszło w <i>-rz</i>. W dawnych źródłach mazowieckich jako zamiennik tego imienia w formie <i><b>Niemierza</b></i> często pojawia się imię <a href=\"https://pl.wikipedia.org/wiki/Erazm\" target=\"_blank\" rel=\"noopener noreferrer\">Erazm</a>.", "Norma Constanza": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Norma</b>.</p><b>Norma</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie stworzone przez <a href=\"https://pl.wikipedia.org/wiki/Felice_Romani\" target=\"_blank\" rel=\"noopener noreferrer\">Felice Romaniego</a>, <a href=\"https://pl.wikipedia.org/wiki/Libretto\" target=\"_blank\" rel=\"noopener noreferrer\">librecistę</a> <i><a href=\"https://pl.wikipedia.org/wiki/Norma_(opera)\" target=\"_blank\" rel=\"noopener noreferrer\">Normy</a></i> <a href=\"https://pl.wikipedia.org/wiki/Vincenzo_Bellini\" target=\"_blank\" rel=\"noopener noreferrer\">Belliniego</a>, dla tytułowej bohaterki tej opery, prawdopodobnie w związku z <a href=\"https://pl.wikipedia.org/wiki/Norma\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskim znaczeniem tego słowa</a> – reguła, zasada. Stosowane także jako żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Norman_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Norman</a>.", "Nadiia-Diana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nadiia</b>.</p><p>Nadiya lub Nadiia (ukraina: Надія) to imię żeńskie, pochodzące z ukraińskiego słowa oznaczającego \"oczekiwanie\". Jest nosiona przez następujących osób: Nadia Al-Kokabany, jemenską pisarkę Nadiya Anderson (ur. 1986), połowę amerykańskiego duetu osobowości telewizyjnej Nadiya Babych (1943-2021), ukraińską lingwistę i filologię Nadiya Baranova (ur. 1983), ukraińską goalierkę futbolu Nadiia Bashynska (ur. 2003), ukraiński-kanadyjską tancerkę lodową Nadiia Bielkina (ur. 1990),...</p>", "Nondumiso": "<p>Nondumiso to kobiece imię, które oznacza \"chwała\" w języku zulu i \"psalm\" w język xhosa. Znanymi osobami z nazwiskiem są: Nondumiso Cele, południowoafrykański polityk Nondumiso Mzizana (ur. 1972), południo Afrykański dentysta Nondumiso Shangase (ur. 1996), gracz kryketa z Południowej Afryki Nondumiso Tembe (ur. 1987), aktorka z Połedniowej Afriki</p>", "N Ataliia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>N</b>.</p><b>N</b> (<i>en</i>, <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>n</b>) – czternasta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a> i osiemnasta <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskiego</a>. Oznacza zwykle w danym języku <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">spółgłoskę przedniojęzykową nosową</a>, np. [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a>].", "Neliya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nelia</b>.</p><p>Nelia (lat. Nelia) - rodzaj sukkulatów rodziny Aizoaceae, podrodzinnego rodu Ruschioideae, rosnący na terytorium prowincji Kapskiej Republiki Południowej Afryki.</p>", "Nicoleta-Diana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nicoleta</b>.</p><p>Nicoleta to rumuńskie imię żeńskie pochodzące od greckiego Nikolaos. Wśród znanych osób z tej nazwy są: Nicoleta Alexandru, piosenkarka reprezentująca Rumunię na konkursie piosenki Eurovision Song Contest 2003 Nicoleta Grasu, rumuńska dyskowerka Nicoleta Onel, rumuńskiej gimnastki Nicoleta Daniela Șofronie, artystyczna gimnastka</p>", "Naghma": "<p>Naghma lub Nagma to arabskie imię żeńskie, oznaczające piosenkę, i może odnosić się do: Nagma, indyjskiej aktorki Naghma (śpiewacz), piosenkarki Aghan Naghma (pakistańska aktorka) Nagma (Bangladeszka aktorka)</p>", "Ngọc Huyền": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Neko": "<p>Neko (ネコ lub ねこ lub 猫, kot) może odnosić się do:</p>", "Nikhita": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nichita</b>.</p><p>Nichita to rumuńska męska nazwa i nazwisko. Do wybitnych osób z tym nazwiskiem należą: Nichita Danilov (ur. 1952), rumuński poeta Nichita Iurașco (ur. 1999), moldawska piłkarka Nichita Moțpan (ur. 2001), moldawska piłkarz Nichita Smochină (1894-1980), rosyjsko-rumuńska aktywistka, uczona i polityczna figura Nichita Stănescu (1933-1983), rumuńska poetka i esejistka</p>", "Noemy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Noemi</b>.</p><b>Noemi</b> (hebr. Naomi, נָעֳמִי) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się od hebrajskiego słowa oznaczającego „moja słodycz”.", "Ngọc Quỳnh Anh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngọc Khánh Linh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngoc Vi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nolwazi": "<p>Nolwazi to kobiece imię. Znani ludzie z nazwiska obejmują: Nkosazana Daughter (Nkosazana Nolwazi Kimberly Nzama; urodzony 2000), południowoafrykański piosenkarz i autor piosenek Nolwazi Mabindla-Boqwana (urodzony 1973), połudnoafrykajski sędzia Nolwazi Hlabangane (urodzona 1995), południeafrykańska gracz rugby.</p>", "Naomi-Rebeca": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Naomi</b>.</p><p>Trynity Lachon Fatu (ang. Trinity LaShawn Fatu, urodziny.</p>", "Ni Made Ari": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Nasira": "<p>Nasira (arabsko: ناصرة, romanized: Nāṣira, lit. 'pomocnik, zwycięzca') lub Nasra to kobiece imię, powszechnie występujące w języku arabskim.</p>", "Naomi-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Naomi</b>.</p><p>Trynity Lachon Fatu (ang. Trinity LaShawn Fatu, urodziny.</p>", "Nurlane": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nurlan</b>.</p><p>Nurlan (kazachski: Нұрлан) to turkijska męska nazwa, która jest powszechna w Azerbejdżanie, Kazachstanie i Uzbekistanie. Nazwa jest w istocie połączeniem arabskiego słowa Noor (także śpiewany jako \"Nur\") oznaczającego światło, promienie lub blask oraz tureckiego słowa \"Lan/Ulan\", który oznacza lwa w większości języków tureckich.</p>", "Ngoc Chau": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Natanaela": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Natanael</b>.</p><b>Natanael</b> (hebr. Bóg dał) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> hebrajskie, znaczeniowo przypomina takie imiona, jak greckie z pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a> czy polskie <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCydar_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bożydar</a>.", "Ni Komang Dewi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Nisa Nur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nisa</b>.</p><p>Nisa jest dzielnicą portugalskiej prowincji Portalegre. Ogromnie liczy się 575 km2, a w 2001 roku liczba ludności wynosiła 8585 mieszkańców.</p>", "Ngọc An Nhiên": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nafissa": "<p>Nafissa to imię. Znani ludzie z nazwiska obejmują: Nafissa Sid Cara (1910-2002), francuska polityka Nafissa Souleymane (ur. 1992), nigeryjska sprinter Nafissa Thompson-Spires (ur. 1983), amerykański pisarz</p>", "Neta Lee": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Neta</b>.</p><p>Hozon Auto (cz. Wręcz przeciwnie.</p>", "Nnenne": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nene</b>.</p><p>Nene (寧寧 (Ninh Ninh) / ねね, Nene 1547 - 17 października 1624), lub zwykle nazywana Kōdai-in (高台院 (Kato Instytut) / こうだいいん, Kōdai-i), była szlachecką kobietą w okresie Sengoku i Edo w historii Japonii. Była znana z piękna, wysokiej mądrości i małżeństwa z Toyotomi Hideyoshi, najpotężniejszym mężczyzną w Japonii w tamtym czasie.</p>", "Ni Kade": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Ngọc Ly": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Neetha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Netha</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Neta</b>.</p><p>Hozon Auto (cz. Wręcz przeciwnie.</p>", "Nicoleta-Simina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nicoleta</b>.</p><p>Nicoleta to rumuńskie imię żeńskie pochodzące od greckiego Nikolaos. Wśród znanych osób z tej nazwy są: Nicoleta Alexandru, piosenkarka reprezentująca Rumunię na konkursie piosenki Eurovision Song Contest 2003 Nicoleta Grasu, rumuńska dyskowerka Nicoleta Onel, rumuńskiej gimnastki Nicoleta Daniela Șofronie, artystyczna gimnastka</p>", "Ni Luh Dewi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Nagat": "<p>Najat to arabskie imię dla kobiet, które oznacza \"zbawiciel\" lub \"zbawienie\". W niektórych krajach można ją pisać Nagat.</p>", "Nimo": "<b>Nimo</b>, właśc. <b>Nima Yaghobi</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/25_grudnia\" target=\"_blank\" rel=\"noopener noreferrer\">25 grudnia</a> <a href=\"https://pl.wikipedia.org/wiki/1995\" target=\"_blank\" rel=\"noopener noreferrer\">1995</a> w <a href=\"https://pl.wikipedia.org/wiki/Karlsruhe\" target=\"_blank\" rel=\"noopener noreferrer\">Karlsruhe</a>) – <a href=\"https://pl.wikipedia.org/wiki/Niemcy\" target=\"_blank\" rel=\"noopener noreferrer\">niemiecki</a> <a href=\"https://pl.wikipedia.org/wiki/Rap\" target=\"_blank\" rel=\"noopener noreferrer\">raper</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Iran\" target=\"_blank\" rel=\"noopener noreferrer\">irańskiego</a>.", "Natalia Margarita": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Natalia</b>.</p><b>Natalia</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em><a href=\"https://pl.wikipedia.org/wiki/Dies_natalis\" target=\"_blank\" rel=\"noopener noreferrer\">Dies natalis</a> Domini</em>, tj. <i>w dniu urodzin <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Pana</a></i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie wywodzące się od męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Natal_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Natalis</a>. W Polsce to imię jest poświadczane w formie Natalia w XIV wieku. Dawniej nadawane osobom urodzonym w dniach chrześcijańskich świąt <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCe_Narodzenie\" target=\"_blank\" rel=\"noopener noreferrer\">Bożego Narodzenia</a>. Patronką imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Adrian_i_Natalia_z_Nikomedii\" target=\"_blank\" rel=\"noopener noreferrer\">Natalia z Nikomedii</a>, męczennica.", "Ngoc Bao An": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ni Wayan Eka": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Nicoleta-Cristina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nicoleta</b>.</p><p>Nicoleta to rumuńskie imię żeńskie pochodzące od greckiego Nikolaos. Wśród znanych osób z tej nazwy są: Nicoleta Alexandru, piosenkarka reprezentująca Rumunię na konkursie piosenki Eurovision Song Contest 2003 Nicoleta Grasu, rumuńska dyskowerka Nicoleta Onel, rumuńskiej gimnastki Nicoleta Daniela Șofronie, artystyczna gimnastka</p>", "Naiomi": "<p>Naiomi to imię kobiece. Znani ludzie z nazwiska to: Naiomi Cameron, amerykański matematyka Naiomi Glasses, amerykańska (Diné) artystka tekstylna i skateboarder</p>", "Ni Made Rai": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Nazare": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nazar</b>.</p><b>Nazar</b>, zwany też <b>okiem <a href=\"https://pl.wikipedia.org/wiki/Fatima_(c%C3%B3rka_Mahometa)\" target=\"_blank\" rel=\"noopener noreferrer\">Fatimy</a></b> lub <b>okiem proroka</b> – <a href=\"https://pl.wikipedia.org/wiki/Amulet\" target=\"_blank\" rel=\"noopener noreferrer\">amulet</a> mający chronić przed „<a href=\"https://pl.wikipedia.org/wiki/Z%C5%82e_oko\" target=\"_blank\" rel=\"noopener noreferrer\">złym okiem</a>”. Nazwa nazar jest pochodzenia arabskiego i znaczy tyle co spojrzenie.", "Nuraini": "<p>Nuraini to indonezyjska kobieca nazwa i nazwisko, pochodzące z arabskiego nūr ʿaynī (نور عيني) oznaczające \"światło mojego oka\". Do osób o imieniu Nuraini należą:</p>", "Ni Luh Ayu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Ni Komang Ida": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ni</b>.</p><p>Nikel (symbol chemiczny - Ni, od łacińskiego Niccolum) - element chemiczny 10. grupy (w zastartym sklasyfikacji - podgrupa uboczna VIII grupy, VIIIB), czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Nicci": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nikki</b>.</p><p>Nikodimos (Nikki) Papavaciliu (grek. Νικόδημος Παπαβασιλείου; WD-Preamblula) - cypryjski piłkarz i trener piłki nożnej, obecny trener klubu ⁇ Dynamo ⁇ Česke-Budejewice.</p>", "Nelly Johana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nelly</b>.</p><p>Kornell Ayrel Haynes-młodszy (ang. Cornell Iral Haynes Jr. ; rodzaj.</p>", "Namiraa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Namira</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Namir</b>.</p><b>Namir</b> — staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Imię to składa się z dwóch członów: <i>na</i> (\"na\"; jedno ze znaczeń <i>na</i> nazywało kogoś, ze względu na kogo coś się działo\") oraz <i>-mir</i> (\"pokój, spokój, dobro\"). Mogło ono więc oznaczać \"ten, który pojawił się w czasie pokoju\" albo \"ten, dzięki któremu zapanuje pokój\".", "Nataliia-Diana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nataliia</b>.</p><p>Natalia jest nazwiskiem dla kobiet z oryginalnym późnolatynskim znaczeniem \"Dzień Bożego Narodzenia\" (por. lat. natale domini).</p>", "Nai̇me": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Naim</b>.</p><p>naim to kompaktowy program do natychmiastowej wymiany wiadomości, obsługujący protokół AIM, ICQ, IRC. W przeciwieństwie do większości takich programów, nie jest graficzny.</p>", "Nam Phuong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nam</b>.</p><p>W wietnamskim, Nam lub mascul jest słowem do wskazania: Mężczyzna: płci męskiej ludzi, w przeciwieństwie do \"żwomen\" jest płcią (żwomen) najniższej rangi szlachty feitów: Namcowiec kierunek: Słowo-Jużny zakres południowej dzielnicy kolonii miasteczkowej, prowincji Ho Nam, China: Słowe dzielnicy okręgów (khu) o nazwie Nam, patrz Naim (distrikty). W słowach \"wstrzymanie\" wskazują kierunek: męskie leki...</p>", "Ngoc Tuyet": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngọc Bảo Hân": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nichol": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nichola</b>.</p><p>Nicola lub Nichola jest łacińską wersją greckiego imienia osobistego Nikolaos (Νικόλαος), pochodzącego z nikē oznaczającego \"wygrę\", a laos oznacza \"ludzie\", co oznacza \"wygrnięcia ludzi\". Nicola to zarówno imię męskie, jak i żeńskie, w zależności od norm kulturalnych.</p>", "Ngọc Hoàng Anh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Ngọc Anh Thư": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nataliia-Viktoriia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nataliia</b>.</p><p>Natalia jest nazwiskiem dla kobiet z oryginalnym późnolatynskim znaczeniem \"Dzień Bożego Narodzenia\" (por. lat. natale domini).</p>", "Natalia Ximena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Natalia</b>.</p><b>Natalia</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em><a href=\"https://pl.wikipedia.org/wiki/Dies_natalis\" target=\"_blank\" rel=\"noopener noreferrer\">Dies natalis</a> Domini</em>, tj. <i>w dniu urodzin <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Pana</a></i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie wywodzące się od męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Natal_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Natalis</a>. W Polsce to imię jest poświadczane w formie Natalia w XIV wieku. Dawniej nadawane osobom urodzonym w dniach chrześcijańskich świąt <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCe_Narodzenie\" target=\"_blank\" rel=\"noopener noreferrer\">Bożego Narodzenia</a>. Patronką imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Adrian_i_Natalia_z_Nikomedii\" target=\"_blank\" rel=\"noopener noreferrer\">Natalia z Nikomedii</a>, męczennica.", "Ngoc Quynh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ngọc</b>.</p><p>To artykuł z \"Pearl\". W odniesieniu do znaczenia tego słowa, patrz Szczeniarz w Wiktionary.</p>", "Nadiia-Alina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Nadiia</b>.</p><p>Nadiya lub Nadiia (ukraina: Надія) to imię żeńskie, pochodzące z ukraińskiego słowa oznaczającego \"oczekiwanie\". Jest nosiona przez następujących osób: Nadia Al-Kokabany, jemenską pisarkę Nadiya Anderson (ur. 1986), połowę amerykańskiego duetu osobowości telewizyjnej Nadiya Babych (1943-2021), ukraińską lingwistę i filologię Nadiya Baranova (ur. 1983), ukraińską goalierkę futbolu Nadiia Bashynska (ur. 2003), ukraiński-kanadyjską tancerkę lodową Nadiia Bielkina (ur. 1990),...</p>", "Nadica": "<p>Nadica to kobiece imię pochodzenia sławskiego. To maleńka forma Nada.</p>", "Nelija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nelia</b>.</p><p>Nelia (lat. Nelia) - rodzaj sukkulatów rodziny Aizoaceae, podrodzinnego rodu Ruschioideae, rosnący na terytorium prowincji Kapskiej Republiki Południowej Afryki.</p>", "Nandy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Nandi</b>.</p><p>Nandi Awards to najwyższa nagroda za wyróżnienie się w dziedzinie kina, teatru, telewizji i żywotnego wkładu w indyjskie kino, przyznawana corocznie przez rząd stanu Andhra Pradesh. Nazwa Nandi, co oznacza ⁇ byk ⁇ , otrzymała nagrodę w cześć wielkiego byka granitowego w Lepaksi - kulturalnego i historycznego symbolu narodu telugu.</p>"};
